    class Player {
      constructor() {
        // Create water droplet shape (teardrop)
        const geometry = new THREE.SphereGeometry(0.5, 16, 16); // Reduced segments for performance
        
        // Modify geometry to make it more teardrop-shaped
        const positions = geometry.attributes.position;
        for (let i = 0; i < positions.count; i++) {
          const y = positions.getY(i);
          const x = positions.getX(i);
          const z = positions.getZ(i);
          
          // Stretch top to make teardrop
          if (y > 0) {
            positions.setY(i, y * 1.2);
            const squeeze = 1 - (y / 0.5) * 0.3;
            positions.setX(i, x * squeeze);
            positions.setZ(i, z * squeeze);
          }
        }
        geometry.computeVertexNormals();
        
        const material = new THREE.MeshPhysicalMaterial({ 
          color: COLORS.player,
          transparent: true,
          opacity: 0.75,
          metalness: 0.1,
          roughness: 0.2,
          transmission: 0.3,
          thickness: 0.5,
          envMapIntensity: 1,
          clearcoat: 1,
          clearcoatRoughness: 0.1
        });
        
        this.mesh = new THREE.Mesh(geometry, material);
        this.mesh.position.y = 0.5;
        this.mesh.castShadow = true;
        this.mesh.receiveShadow = true;
        scene.add(this.mesh);
        
        // Add water shine effect (multiple layers)
        const shineGeo = new THREE.SphereGeometry(0.52, 16, 16);
        const shineMat = new THREE.MeshBasicMaterial({ 
          color: 0xFFFFFF, 
          transparent: true, 
          opacity: 0.25,
          side: THREE.BackSide
        });
        this.shine = new THREE.Mesh(shineGeo, shineMat);
        this.mesh.add(this.shine);
        
        // Add reflection highlight
        const highlightGeo = new THREE.SphereGeometry(0.15, 16, 16);
        const highlightMat = new THREE.MeshBasicMaterial({ 
          color: 0xFFFFFF, 
          transparent: true, 
          opacity: 0.8
        });
        this.highlight = new THREE.Mesh(highlightGeo, highlightMat);
        this.highlight.position.set(-0.2, 0.3, 0.2);
        this.mesh.add(this.highlight);
        
        // Add player face: eyes with friendly appearance (matching main menu art style)
        // REMOVED RED EYES - using blue/cyan to match waterdrop theme
        const eyeGeo = new THREE.SphereGeometry(0.08, 8, 8);
        const eyeMat = new THREE.MeshBasicMaterial({ color: 0x5DADE2 }); // Cyan/blue eyes to match waterdrop
        
        this.leftEye = new THREE.Mesh(eyeGeo, eyeMat);
        this.leftEye.position.set(-0.12, 0.1, 0.4);
        this.mesh.add(this.leftEye);
        
        this.rightEye = new THREE.Mesh(eyeGeo, eyeMat);
        this.rightEye.position.set(0.12, 0.1, 0.4);
        this.mesh.add(this.rightEye);
        
        // Pupils (darker blue for depth - matches waterdrop theme)
        const pupilGeo = new THREE.SphereGeometry(0.04, 8, 8);
        const pupilMat = new THREE.MeshBasicMaterial({ color: 0x2874A6 }); // Dark blue to match waterdrop
        
        this.leftPupil = new THREE.Mesh(pupilGeo, pupilMat);
        this.leftPupil.position.set(-0.12, 0.1, 0.45);
        this.mesh.add(this.leftPupil);
        
        this.rightPupil = new THREE.Mesh(pupilGeo, pupilMat);
        this.rightPupil.position.set(0.12, 0.1, 0.45);
        this.mesh.add(this.rightPupil);
        
        // Smile (curved shape using torus segment)
        const smileGeo = new THREE.TorusGeometry(0.15, 0.02, 8, 16, Math.PI);
        const smileMat = new THREE.MeshBasicMaterial({ color: 0x000000 });
        this.smile = new THREE.Mesh(smileGeo, smileMat);
        this.smile.position.set(0, -0.05, 0.4);
        this.smile.rotation.x = Math.PI / 2;
        this.smile.rotation.z = Math.PI;
        this.mesh.add(this.smile);
        
        // Bandage accessory (white cross-shaped bandage on head)
        const bandageGeo = new THREE.BoxGeometry(0.3, 0.05, 0.05);
        const bandageMat = new THREE.MeshToonMaterial({ color: 0xFFFFFF }); // White
        this.bandage = new THREE.Mesh(bandageGeo, bandageMat);
        this.bandage.position.set(0, 0.35, 0);
        this.mesh.add(this.bandage);
        
        // Vertical bandage piece
        const bandageVertGeo = new THREE.BoxGeometry(0.05, 0.3, 0.05);
        this.bandageVert = new THREE.Mesh(bandageVertGeo, bandageMat);
        this.bandageVert.position.set(0, 0.35, 0);
        this.mesh.add(this.bandageVert);
        
        // Eye blink animation timer
        this.blinkTimer = 0;
        this.blinkDuration = 0.1; // 100ms blink
        this.nextBlinkTime = 2 + Math.random() * 3; // Random 2-5 seconds
        this.isBlinking = false;
        
        // Arms (simple cylinders attached to body)
        const armGeo = new THREE.CylinderGeometry(0.06, 0.06, 0.35, 8);
        const limbMaterial = new THREE.MeshToonMaterial({ color: COLORS.player, opacity: 0.85, transparent: true });
        
        // Left arm
        this.leftArm = new THREE.Mesh(armGeo, limbMaterial);
        this.leftArm.position.set(-0.35, 0, 0);
        this.leftArm.rotation.z = Math.PI / 6; // Angled outward
        this.mesh.add(this.leftArm);
        
        // Right arm (holding gun)
        this.rightArm = new THREE.Mesh(armGeo, limbMaterial);
        this.rightArm.position.set(0.35, 0, 0);
        this.rightArm.rotation.z = -Math.PI / 6; // Angled outward
        this.mesh.add(this.rightArm);
        
        // Gun visual (held by right arm) - enhanced for better visibility
        const gunBodyGeo = new THREE.BoxGeometry(0.12, 0.16, 0.35); // Larger gun body
        const gunMat = new THREE.MeshToonMaterial({ color: 0x333333 }); // Slightly lighter dark gray
        this.gunBody = new THREE.Mesh(gunBodyGeo, gunMat);
        this.gunBody.position.set(0.42, -0.05, 0.35);
        this.mesh.add(this.gunBody);
        
        // Gun barrel - longer and thicker
        const barrelGeo = new THREE.CylinderGeometry(0.035, 0.03, 0.3, 8);
        const barrelMat = new THREE.MeshToonMaterial({ color: 0x1a1a1a }); // Black barrel
        this.gunBarrel = new THREE.Mesh(barrelGeo, barrelMat);
        this.gunBarrel.rotation.x = Math.PI / 2;
        this.gunBarrel.position.set(0.42, -0.05, 0.56);
        this.mesh.add(this.gunBarrel);
        
        // Gun scope / sight for visibility
        const sightGeo = new THREE.BoxGeometry(0.04, 0.05, 0.06);
        const sightMat = new THREE.MeshToonMaterial({ color: 0x666666 });
        this.gunSight = new THREE.Mesh(sightGeo, sightMat);
        this.gunSight.position.set(0.42, 0.04, 0.35);
        this.mesh.add(this.gunSight);
        
        // Gun handle
        const handleGeo = new THREE.BoxGeometry(0.07, 0.18, 0.10);
        const handleMat = new THREE.MeshToonMaterial({ color: 0x8B4513 }); // Brown handle
        this.gunHandle = new THREE.Mesh(handleGeo, handleMat);
        this.gunHandle.position.set(0.42, -0.22, 0.25);
        this.gunHandle.rotation.z = -Math.PI / 6;
        this.mesh.add(this.gunHandle);
        
        // Legs (simple cylinders below body)
        const legGeo = new THREE.CylinderGeometry(0.08, 0.07, 0.4, 8);
        
        // Left leg
        this.leftLeg = new THREE.Mesh(legGeo, limbMaterial);
        this.leftLeg.position.set(-0.15, -0.45, 0);
        this.mesh.add(this.leftLeg);
        
        // Right leg
        this.rightLeg = new THREE.Mesh(legGeo, limbMaterial);
        this.rightLeg.position.set(0.15, -0.45, 0);
        this.mesh.add(this.rightLeg);
        
        // Smoke particles timer
        this.smokeTimer = 0;
        
        // Breathing animation states (breath-in with cigar glow, breath-out with smoke)
        this.breathTimer = 0;
        this.breathCycle = 4.0; // 4 seconds per breath cycle
        this.isBreathingIn = false;
        
        // Pulsing glow
        const glowGeo = new THREE.SphereGeometry(0.55, 16, 16);
        const glowMat = new THREE.MeshBasicMaterial({ 
          color: 0x4FC3F7, 
          transparent: true, 
          opacity: 0.2,
          side: THREE.BackSide
        });
        this.glow = new THREE.Mesh(glowGeo, glowMat);
        this.mesh.add(this.glow);
        
        // Aura Circle (visible when aura weapon is active) - smaller pulsating ring
        const auraGeo = new THREE.RingGeometry(1.5, 2.0, 24);
        const auraMat = new THREE.MeshBasicMaterial({ 
          color: 0x5DADE2, 
          transparent: true, 
          opacity: 0.3,
          side: THREE.DoubleSide
        });
        this.auraCircle = new THREE.Mesh(auraGeo, auraMat);
        this.auraCircle.rotation.x = -Math.PI / 2;
        this.auraCircle.position.y = 0.1;
        this.auraCircle.visible = false;
        this.currentAuraRange = 2.0;
        scene.add(this.auraCircle);
        
        // Fire Ring Orbs (visible when fireRing weapon is active)
        this.fireRingOrbs = [];
        this.fireRingAngle = 0;
        
        // Physics/Visuals
        this.velocity = new THREE.Vector3(0, 0, 0);
        this.targetScale = new THREE.Vector3(1, 1, 1);
        this.trailTimer = 0;
        this.wobblePhase = 0;
        // Spring-damper for waterdrop deformation
        this.scaleYVel = 0;       // spring velocity for Y scale
        this.scaleXZVel = 0;      // spring velocity for XZ scale
        this.currentScaleY = 1.0;
        this.currentScaleXZ = 1.0;
        this.wobbleIntensity = 0; // spikes on direction change / dash
        this.prevVelDir = new THREE.Vector3(); // previous velocity direction for direction-change detection
        this.postDashSquish = 0;  // timer for post-dash bounce
        this.wasMoving = false;   // used to detect stopping transition for squish
        
        // Phase 5: Low health water bleed timer
        this.waterBleedTimer = 0;
        
        // Dash
        this.isDashing = false;
        this.dashTime = 0;
        this.dashDuration = 0.2;
        this.dashVec = new THREE.Vector3();
        
        // Invulnerability frames to prevent instant death
        this.invulnerable = false;
        this.invulnerabilityTime = 0;
        this.invulnerabilityDuration = 0.5; // 500ms of invulnerability after taking damage
        
        // X eyes effect when hit
        this.xEyesActive = false;
        this.xEyes = [];
        
        // Store base scale for breathing animation efficiency
        this.baseScale = 1.0;
        this._breathScale = 1.0; // Multiplier from breathing animation, applied on top of spring-damper
      }

      update(dt) {
        // Update invulnerability timer
        const INVULNERABILITY_FLASH_FREQUENCY = 20; // Flash 20 times per second during invulnerability
        if (this.invulnerable) {
          this.invulnerabilityTime += dt;
          if (this.invulnerabilityTime >= this.invulnerabilityDuration) {
            this.invulnerable = false;
            this.invulnerabilityTime = 0;
          }
          // Flash effect during invulnerability
          if (Math.floor(this.invulnerabilityTime * INVULNERABILITY_FLASH_FREQUENCY) % 2 === 0) {
            this.mesh.material.opacity = 0.5;
          } else {
            this.mesh.material.opacity = 0.75;
          }
        } else {
          this.mesh.material.opacity = 0.75; // Normal opacity
        }
        
        // Phase 5: Water bleed effect when health < 30%
        const healthPercent = playerStats.hp / playerStats.maxHp;
        if (healthPercent < 0.3) {
          this.waterBleedTimer += dt;
          if (this.waterBleedTimer > 0.08) { // Fast drip
            this.waterBleedTimer = 0;
            spawnWaterDroplet(this.mesh.position);
            // Add blue water particles trailing behind
            if (Math.random() < 0.5) {
              spawnParticles(this.mesh.position, COLORS.player, 1);
            }
          }
        }
        
        // Dash Logic
        if (this.isDashing) {
          this.dashTime -= dt;
          const t = 1 - (this.dashTime / this.dashDuration);
          // Dash distance uses the upgradeable dashDistance variable
          const dashSpeed = (dashDistance / this.dashDuration); // units per second
          const speed = Math.sin(t * Math.PI) * dashSpeed; // Slow-Fast-Slow curve
          this.mesh.position.x += this.dashVec.x * speed * dt;
          this.mesh.position.z += this.dashVec.z * speed * dt;
          
          // Enhanced splash effect trail during dash - MORE PARTICLES
          if (Math.random() < 0.7) { // Increased from 0.5
            spawnParticles(this.mesh.position, COLORS.player, 3); // Increased from 2
            spawnWaterDroplet(this.mesh.position);
            // Add white sparkle particles during dash
            if (Math.random() < 0.4) {
              spawnParticles(this.mesh.position, 0xFFFFFF, 2);
            }
          }
          
          // DASH DESTRUCTION: Destroy any destructible prop dashed into
          if (window.destructibleProps) {
            for (let prop of window.destructibleProps) {
              if (prop.destroyed) continue;
              const ddx = this.mesh.position.x - prop.mesh.position.x;
              const ddz = this.mesh.position.z - prop.mesh.position.z;
              const ddist2 = ddx * ddx + ddz * ddz;
              if (ddist2 < 4) { // Within 2 units - destroy on dash
                prop.destroyed = true;
                // Big destruction effect
                const pPos = prop.mesh.position;
                if (prop.type === 'tree') {
                  spawnParticles(pPos, 0x8B4513, 25);
                  spawnParticles(pPos, 0x228B22, 20);
                  // Tree falls and remains as debris (does not disappear)
                  const fallDir = Math.random() < 0.5 ? 1 : -1;
                  const fallAxis = Math.random() < 0.5 ? 'x' : 'z';
                  const fallDuration = 500;
                  const fallStart = Date.now();
                  if (prop.mesh.userData.leaves) prop.mesh.userData.leaves.visible = false;
                  const treeMesh = prop.mesh;
                  if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
                    let dashFallTimer = 0;
                    const dashFallFrames = Math.ceil(fallDuration / 16);
                    managedAnimations.push({ update(_dt) {
                      dashFallTimer++;
                      const progress = Math.min(dashFallTimer / dashFallFrames, 1);
                      if (fallAxis === 'x') treeMesh.rotation.x = (Math.PI / 2) * progress * fallDir;
                      else treeMesh.rotation.z = (Math.PI / 2) * progress * fallDir;
                      treeMesh.position.y = -progress * 1.5;
                      return progress < 1;
                    }});
                  }
                } else if (prop.type === 'barrel') {
                  spawnParticles(pPos, 0xFF4500, 30);
                  spawnParticles(pPos, 0xFFFF00, 15);
                  // Leave broken debris on ground instead of removing
                  prop.mesh.scale.set(0.8, 0.3, 0.8);
                  prop.mesh.position.y = 0.15;
                  prop.mesh.rotation.x = (Math.random() - 0.5) * 0.8;
                  prop.mesh.rotation.z = (Math.random() - 0.5) * 0.8;
                  if (prop.mesh.material) prop.mesh.material.color.setHex(0x654321);
                  if (prop.mesh.material) prop.mesh.material.opacity = 0.7;
                } else {
                  spawnParticles(pPos, 0xD2691E, 20);
                  // Leave broken crate debris on ground
                  prop.mesh.scale.set(0.7, 0.25, 0.7);
                  prop.mesh.position.y = 0.12;
                  prop.mesh.rotation.x = (Math.random() - 0.5) * 1.0;
                  prop.mesh.rotation.z = (Math.random() - 0.5) * 1.0;
                  if (prop.mesh.material) prop.mesh.material.color.setHex(0x8B6914);
                  if (prop.mesh.material) prop.mesh.material.opacity = 0.6;
                }
                // Screen shake on big destruction
                if (window.triggerScreenShake) window.triggerScreenShake(0.3);
              }
            }
          }
          
          // DASH DESTRUCTION: Destroy fences dashed into
          if (window.breakableFences) {
            for (let fence of window.breakableFences) {
              if (!fence.userData.isFence || fence.userData.hp <= 0) continue;
              const fdx = this.mesh.position.x - fence.position.x;
              const fdz = this.mesh.position.z - fence.position.z;
              if (fdx * fdx + fdz * fdz < 4) {
                fence.userData.hp = 0;
                spawnParticles(fence.position, 0x8B4513, 15);
                // Leave fence debris on ground instead of removing
                fence.scale.set(1, 0.2, 1);
                fence.position.y = 0.05;
                fence.rotation.x = (Math.random() - 0.5) * 1.5;
                if (fence.material) fence.material.opacity = 0.5;
              }
            }
          }
          // DASH DESTRUCTION: Break through trees and props when dashing
          if (window.destructibleProps) {
            for (let prop of window.destructibleProps) {
              if (prop.destroyed) continue;
              const pdx = this.mesh.position.x - prop.mesh.position.x;
              const pdz = this.mesh.position.z - prop.mesh.position.z;
              if (pdx * pdx + pdz * pdz < 2.5) {
                prop.hp = 0;
                prop.destroyed = true;
                spawnParticles(prop.mesh.position, prop.type === 'tree' ? 0x228B22 : 0x8B4513, 20);
                prop.mesh.scale.set(1, 0.2, 1);
                prop.mesh.position.y = 0.05;
                prop.mesh.rotation.x = (Math.random() - 0.5) * 1.5;
                if (prop.mesh.material) {
                  prop.mesh.material.transparent = true;
                  prop.mesh.material.opacity = 0.5;
                }
              }
            }
          }
          
          if (this.dashTime <= 0) {
            this.isDashing = false;
          }
        }
        // Movement
        else {
          const targetVel = new THREE.Vector3(0, 0, 0);
        
          // Movement with LEFT stick
          if (joystickLeft.active) {
            const rageSpeedMult = this._rageSpeedMult || 1;
            const speed = GAME_CONFIG.playerSpeedBase * (playerStats.walkSpeed / 25) * 60 * rageSpeedMult; // Base speed for 60fps
            targetVel.x = joystickLeft.x * speed * dt; // Frame-rate independent
            targetVel.z = joystickLeft.y * speed * dt;
          }
          
          // Enhanced inertia: Smooth acceleration and deceleration with glide
          // Scale lerpFactor by dt*60 to normalize across frame rates and eliminate jitter
          // turnResponse (from flexibility training) scales acceleration, stopResponse scales deceleration
          const turnResp = (playerStats.turnResponse || 1.0);
          const stopResp = (playerStats.stopResponse || 1.0);
          const baseLerpFactor = joystickLeft.active ? GAME_CONFIG.accelLerpFactor * turnResp : GAME_CONFIG.decelLerpFactor * stopResp;
          const lerpFactor = Math.min(baseLerpFactor * (dt * 60), 1.0);
          this.velocity.lerp(targetVel, lerpFactor);
          
          // Apply velocity with inertia
          this.mesh.position.x += this.velocity.x;
          this.mesh.position.z += this.velocity.z;
          
          // Solid collision with map objects (trees, barrels, crates) — player bounces off
          if (window.destructibleProps) {
            for (let prop of window.destructibleProps) {
              if (prop.destroyed) continue;
              const collisionRadius = prop.type === 'tree' ? 1.0 : 0.7;
              const pdx = this.mesh.position.x - prop.mesh.position.x;
              const pdz = this.mesh.position.z - prop.mesh.position.z;
              const pdist = Math.sqrt(pdx * pdx + pdz * pdz);
              if (pdist < collisionRadius && pdist > 0.001) {
                // Push player out of object
                const pushX = (pdx / pdist) * collisionRadius;
                const pushZ = (pdz / pdist) * collisionRadius;
                this.mesh.position.x = prop.mesh.position.x + pushX;
                this.mesh.position.z = prop.mesh.position.z + pushZ;
                // Kill inward velocity
                const dot = this.velocity.x * pdx + this.velocity.z * pdz;
                if (dot < 0) {
                  this.velocity.x -= (dot / (pdist * pdist)) * pdx;
                  this.velocity.z -= (dot / (pdist * pdist)) * pdz;
                }
                // Wobble the object on collision
                if (!prop._wobbleTime) prop._wobbleTime = 0;
                prop._wobbleTime = 1.0; // Start wobble for 1 second
                if (!prop._wobbleDir) prop._wobbleDir = { x: -pdx / pdist, z: -pdz / pdist };
                else { prop._wobbleDir.x = -pdx / pdist; prop._wobbleDir.z = -pdz / pdist; }
              }
            }
          }
          // Solid collision with fences — also wobble on contact
          if (window.breakableFences) {
            for (let fence of window.breakableFences) {
              if (!fence.userData || !fence.userData.isFence || fence.userData.hp <= 0) continue;
              const fdx = this.mesh.position.x - fence.position.x;
              const fdz = this.mesh.position.z - fence.position.z;
              const fdist = Math.sqrt(fdx * fdx + fdz * fdz);
              if (fdist < 0.6 && fdist > 0.001) {
                this.mesh.position.x = fence.position.x + (fdx / fdist) * 0.6;
                this.mesh.position.z = fence.position.z + (fdz / fdist) * 0.6;
                // Wobble fence on collision
                if (!fence.userData._wobbleTime) fence.userData._wobbleTime = 0;
                fence.userData._wobbleTime = 0.8;
                if (!fence.userData._wobbleDir) fence.userData._wobbleDir = { x: -fdx / fdist, z: -fdz / fdist };
                else { fence.userData._wobbleDir.x = -fdx / fdist; fence.userData._wobbleDir.z = -fdz / fdist; }
              }
            }
          }

          // Solid collision with resource rocks/crystals — player cannot walk through them
          if (window.GameHarvesting && window.GameHarvesting.harvestNodes) {
            for (let node of window.GameHarvesting.harvestNodes) {
              if (node.depleted || !node.mesh) continue;
              const collRadius = 0.9; // Rocks are about 1.6 radius but use smaller collider
              const ndx = this.mesh.position.x - node.mesh.position.x;
              const ndz = this.mesh.position.z - node.mesh.position.z;
              const ndist = Math.sqrt(ndx * ndx + ndz * ndz);
              if (ndist < collRadius && ndist > 0.001) {
                // Push player out
                this.mesh.position.x = node.mesh.position.x + (ndx / ndist) * collRadius;
                this.mesh.position.z = node.mesh.position.z + (ndz / ndist) * collRadius;
                const dot = this.velocity.x * ndx + this.velocity.z * ndz;
                if (dot < 0) {
                  this.velocity.x -= (dot / (ndist * ndist)) * ndx;
                  this.velocity.z -= (dot / (ndist * ndist)) * ndz;
                }
                // Wobble the rock on collision
                node._wobbleTime = 0.7;
                if (!node._wobbleDir) node._wobbleDir = { x: -ndx / ndist, z: -ndz / ndist };
                else { node._wobbleDir.x = -ndx / ndist; node._wobbleDir.z = -ndz / ndist; }
              }
            }
          }

          // Enhanced water droplet trail when moving - MORE PARTICLES
          if (this.velocity.length() > 0.01) {
            this.trailTimer += dt;
            if (this.trailTimer > 0.12) { // Faster trail (was 0.15)
              this.trailTimer = 0;
              spawnWaterDroplet(this.mesh.position);
              // Add extra splash particles during movement
              if (Math.random() < 0.3) {
                spawnParticles(this.mesh.position, COLORS.player, 1);
              }
            }
          } else {
            // Idle
            this.trailTimer = 0;
          }
          
          // Add lean/tilt in direction of movement — more dynamic and responsive
          if (this.velocity.length() > 0.03) {
            const leanFactor = GAME_CONFIG.movementLeanFactor * (25 + this.wobbleIntensity * 25);
            const leanAngleX = -this.velocity.z * leanFactor;
            const leanAngleZ = this.velocity.x * leanFactor;
            // Faster response on direction changes, smooth in steady state
            const leanResponse = this.wobbleIntensity > 0.3 ? 0.7 : 0.5;
            const leanDt = Math.min(dt * 12, leanResponse);
            this.mesh.rotation.x += (leanAngleX - this.mesh.rotation.x) * leanDt;
            this.mesh.rotation.z += (leanAngleZ - this.mesh.rotation.z) * leanDt;
          } else {
            // Smooth return to upright when idle - more natural settle
            this.mesh.rotation.x *= 0.85;
            this.mesh.rotation.z *= 0.85;
          }
          
          // Rotation/Aiming with RIGHT stick (independent of movement)
          if (joystickRight.active) {
            // Manual aim: Turn to face the direction of right stick
            let angle = Math.atan2(joystickRight.x, joystickRight.y);
            
            // FRESH: Precision aiming - 15% nudge toward nearest enemy when right joystick active
            if (enemies && enemies.length > 0) {
              let nearestEnemy = null;
              let minDist = Infinity;
              enemies.forEach(e => {
                if (e && !e.isDead) {
                  const dist = this.mesh.position.distanceTo(e.mesh.position);
                  if (dist < minDist && dist < 15) { // Only nudge if enemy within reasonable range
                    minDist = dist;
                    nearestEnemy = e;
                  }
                }
              });
              
              if (nearestEnemy) {
                const dx = nearestEnemy.mesh.position.x - this.mesh.position.x;
                const dz = nearestEnemy.mesh.position.z - this.mesh.position.z;
                const enemyAngle = Math.atan2(dx, dz);
                
                // Blend 85% player input + 15% toward enemy (subtle magnetism)
                let angleDiff = enemyAngle - angle;
                // Normalize angle difference to -PI to PI
                while (angleDiff > Math.PI) angleDiff -= Math.PI * 2;
                while (angleDiff < -Math.PI) angleDiff += Math.PI * 2;
                
                angle = angle + angleDiff * 0.15; // 15% nudge
              }
            }
            
            this.mesh.rotation.y = angle;
          } else if (gameSettings.autoAim && enemies && enemies.length > 0) {
            // Auto-aim when enabled (works in any orientation)
            // Accuracy starts low and improves with dexterity/upgrades via autoAimAccuracy stat
            let nearestEnemy = null;
            let minDist = Infinity;
            enemies.forEach(e => {
              if (e && !e.isDead) {
                const dist = this.mesh.position.distanceTo(e.mesh.position);
                if (dist < minDist) {
                  minDist = dist;
                  nearestEnemy = e;
                }
              }
            });
            if (nearestEnemy) {
              const dx = nearestEnemy.mesh.position.x - this.mesh.position.x;
              const dz = nearestEnemy.mesh.position.z - this.mesh.position.z;
              const perfectAngle = Math.atan2(dx, dz);
              // Apply accuracy: low accuracy adds a stable offset (updated every 150ms, not every frame)
              // This prevents per-frame random jitter that causes the character to wobble rapidly
              const accuracy = playerStats.autoAimAccuracy || 0.3;
              const maxError = (1 - accuracy) * (Math.PI / 4); // up to 45° off at 0% accuracy
              // Recalculate aim error every 150ms (not every frame) to prevent per-frame jitter
              if (!this._nextAimErrorUpdate || gameTime >= this._nextAimErrorUpdate) {
                this._nextAimErrorUpdate = gameTime + 0.15; // 150ms between aim-error updates
                this._currentAimError = (Math.random() - 0.5) * 2 * maxError;
              }
              const targetAngle = perfectAngle + (this._currentAimError || 0);
              // Lerp toward target angle to avoid snapping
              let angleDiff = targetAngle - this.mesh.rotation.y;
              while (angleDiff > Math.PI) angleDiff -= 2 * Math.PI;
              while (angleDiff < -Math.PI) angleDiff += 2 * Math.PI;
              this.mesh.rotation.y += angleDiff * Math.min(10 * dt, 1);
            }
          } else if (joystickLeft.active) {
            // If no right stick input and no auto-aim, rotate to face movement direction
            // Only update rotation if joystick has meaningful input (prevents jitter near center)
            if (targetVel.lengthSq() > 0.000001) {
              const angle = Math.atan2(targetVel.x, targetVel.z);
              this.mesh.rotation.y = angle;
            }
          }
        }
        
        const speedMag = this.velocity.length();
        
        // Waterdrop physics: spring-damper squish/bounce/wobble
        const dt2 = Math.min(dt, 0.05);
        
        // Detect direction changes to spike wobble intensity
        if (speedMag > 0.04) {
          const velDir = this.velocity.clone().normalize();
          const dirDot = velDir.dot(this.prevVelDir);
          const dirChange = 1 - dirDot;
          if (dirChange > 0.2) {
            // Over-exaggerate wobble on direction changes for dynamic feel
            this.wobbleIntensity = Math.min(1, this.wobbleIntensity + dirChange * 4.0);
            // Full reversal (dot < -0.5): dramatic stretch + water trail
            if (dirDot < -0.5 && speedMag > 0.06) {
              this.postDashSquish = Math.max(this.postDashSquish, 0.9);
              this.wobbleIntensity = 1;
              // Spawn water trail particles to show sliding
              for (let i = 0; i < 4; i++) spawnWaterParticle(this.mesh.position);
            }
          }
          this.prevVelDir.copy(velDir);
        }
        // Decay wobble intensity
        this.wobbleIntensity = Math.max(0, this.wobbleIntensity - dt2 * 3);
        
        // Stopping squish: detect transition from moving to fully stopped
        if (this.wasMoving && speedMag < 0.02 && !this.isDashing) {
          this.postDashSquish = Math.max(this.postDashSquish, 0.7);
          this.wobbleIntensity = Math.min(1, this.wobbleIntensity + 0.5);
        }
        this.wasMoving = speedMag > 0.02;

        // Post-dash / post-stop squish bounce timer
        if (!this.isDashing && this.postDashSquish > 0) {
          this.postDashSquish = Math.max(0, this.postDashSquish - dt2 * 4);
        }
        if (this.isDashing) {
          this.postDashSquish = 1.0;
          this.wobbleIntensity = Math.min(1, this.wobbleIntensity + 0.8);
        }
        
        // Compute target scales
        let targetScaleY, targetScaleXZ;
        if (this.isDashing) {
          // Dash START: quick squish then elongate (gives a "push-off" feel)
          const dashProg = 1 - (this.dashTime / this.dashDuration);
          if (dashProg < 0.2) {
            const t = dashProg / 0.2;
            targetScaleY = 1.0 - t * 0.55;   // 1.0 → 0.45 squish
            targetScaleXZ = 1.0 + t * 0.5;   // 1.0 → 1.5 expand
          } else {
            // Dash BODY: fully elongated in travel direction
            targetScaleY = 0.45;
            targetScaleXZ = 1.5;
          }
        } else if (this.postDashSquish > 0.01) {
          // Post-dash/stop/turn oscillating bounce — over-exaggerated for comic waterdrop feel
          const bounce = Math.sin(this.postDashSquish * Math.PI * 3.0) * 0.45 * this.postDashSquish;
          targetScaleY = 1.0 + bounce;
          targetScaleXZ = 1.0 - bounce * 0.6;
        } else if (speedMag > 0.05) {
          // Moving: vertical bounce oscillates — bigger range, more dramatic wobble
          this.wobblePhase += dt2 * speedMag * 120;  // slower phase for heavier, lower-frequency bounce
          const bounce = Math.sin(this.wobblePhase) * (0.14 + this.wobbleIntensity * 0.18);
          targetScaleY = 1.0 + bounce;
          const squishAmt = Math.min(speedMag * 1.5, 0.25);
          targetScaleXZ = 1.0 + squishAmt + Math.cos(this.wobblePhase) * (0.06 + this.wobbleIntensity * 0.10);
        } else {
          // Idle breathing
          this.wobblePhase += dt2 * 2.5;
          targetScaleY = 1.0 + Math.sin(this.wobblePhase) * 0.03;
          targetScaleXZ = 1.0 - Math.sin(this.wobblePhase) * 0.015;
        }
        
        // Spring-damper integration (k=200 stiffness, c=18 damping)
        const springK = 200, springC = 18;
        const forceY = springK * (targetScaleY - this.currentScaleY) - springC * this.scaleYVel;
        const forceXZ = springK * (targetScaleXZ - this.currentScaleXZ) - springC * this.scaleXZVel;
        this.scaleYVel += forceY * dt2;
        this.scaleXZVel += forceXZ * dt2;
        this.currentScaleY += this.scaleYVel * dt2;
        this.currentScaleXZ += this.scaleXZVel * dt2;
        // Clamp to sane range
        this.currentScaleY = Math.max(0.3, Math.min(2.0, this.currentScaleY));
        this.currentScaleXZ = Math.max(0.5, Math.min(2.0, this.currentScaleXZ));
        // Note: mesh.scale is applied after breathing section, combined with _breathScale
        
        // Shed water particles when moving fast
        if (speedMag > 0.4 && Math.random() < dt2 * speedMag * 3 && !this.isDashing) {
          const n = Math.floor(Math.random() * 2) + 1;
          for (let i = 0; i < n; i++) spawnWaterParticle(this.mesh.position);
        }
        
        // Animate water shine
        this.shine.rotation.y += 0.05;
        this.shine.rotation.x += 0.03;
        
        // Pulse highlight
        this.highlight.material.opacity = 0.6 + Math.sin(gameTime * 3) * 0.2;
        
        // Pulse glow effect
        this.glow.material.opacity = 0.15 + Math.sin(gameTime * 2) * 0.1;
        this.glow.scale.set(
          1 + Math.sin(gameTime * 2) * 0.05,
          1 + Math.sin(gameTime * 2) * 0.05,
          1 + Math.sin(gameTime * 2) * 0.05
        );
        
        // Animate arms and legs (walking animation when moving)
        if (speedMag > 0.1) {
          // Walking animation - swing arms and legs
          const walkPhase = gameTime * 8; // Walking speed
          this.leftArm.rotation.x = Math.sin(walkPhase) * 0.3;
          this.rightArm.rotation.x = -Math.sin(walkPhase) * 0.3;
          this.leftLeg.rotation.x = -Math.sin(walkPhase) * 0.4;
          this.rightLeg.rotation.x = Math.sin(walkPhase) * 0.4;
        } else {
          // Idle - gentle sway
          const idlePhase = gameTime * 2;
          this.leftArm.rotation.x = Math.sin(idlePhase) * 0.1;
          this.rightArm.rotation.x = Math.sin(idlePhase + Math.PI) * 0.1;
          this.leftLeg.rotation.x = 0;
          this.rightLeg.rotation.x = 0;
        }
        
        // Breathing animation (subtle body scaling)
        this._breathScale = 1.0;
        this.breathTimer += dt;
        const breathPhase = (this.breathTimer % this.breathCycle) / this.breathCycle;
        if (breathPhase < 0.4) {
          const inhaleProgress = breathPhase / 0.4;
          this._breathScale = 1 + inhaleProgress * 0.05;
        } else if (breathPhase < 0.5) {
          this._breathScale = 1.05;
        } else {
          const exhaleProgress = (breathPhase - 0.5) / 0.5;
          this._breathScale = 1.05 - exhaleProgress * 0.05;
        }
        
        // Apply spring-damper scale combined with breathing multiplier
        // Directional stretch: mesh local Z = forward (movement direction), local X = sideways
        // Over-exaggerated for comic waterdrop style — elongate in travel direction
        const dirStretch = this.isDashing
          ? 0.5
          : Math.min(speedMag * 2.0, 0.28);
        this.mesh.scale.y = this.currentScaleY * this._breathScale;
        this.mesh.scale.x = this.currentScaleXZ * (1.0 - dirStretch * 0.65) * this._breathScale;
        this.mesh.scale.z = this.currentScaleXZ * (1.0 + dirStretch * 0.55) * this._breathScale;
        
        // Blinking eyes animation
        this.blinkTimer += dt;
        if (this.blinkTimer >= this.nextBlinkTime) {
          this.isBlinking = true;
          this.blinkTimer = 0;
          this.nextBlinkTime = 2 + Math.random() * 3; // Next blink in 2-5 seconds
        }
        
        if (this.isBlinking) {
          // Scale eyes down vertically for blink effect
          const blinkProgress = Math.min(1, this.blinkTimer / this.blinkDuration);
          if (blinkProgress < 0.5) {
            // Closing
            const scale = 1 - (blinkProgress * 2);
            this.leftEye.scale.y = scale;
            this.rightEye.scale.y = scale;
            this.leftPupil.scale.y = scale;
            this.rightPupil.scale.y = scale;
          } else {
            // Opening
            const scale = (blinkProgress - 0.5) * 2;
            this.leftEye.scale.y = scale;
            this.rightEye.scale.y = scale;
            this.leftPupil.scale.y = scale;
            this.rightPupil.scale.y = scale;
          }
          
          if (blinkProgress >= 1) {
            this.isBlinking = false;
            this.blinkTimer = 0;
            // Reset scale
            this.leftEye.scale.y = 1;
            this.rightEye.scale.y = 1;
            this.leftPupil.scale.y = 1;
            this.rightPupil.scale.y = 1;
          }
        }
        
        // Update aura circle - pulsating energy ring
        if (weapons.aura.active) {
          this.auraCircle.visible = true;
          this.auraCircle.position.x = this.mesh.position.x;
          this.auraCircle.position.z = this.mesh.position.z;
          
          // Scale based on aura range - smaller ring, only recreate if range changed
          const scale = weapons.aura.range * 1.5;
          if (this.currentAuraRange !== scale) {
            this.currentAuraRange = scale;
            this.auraCircle.geometry.dispose();
            this.auraCircle.geometry = new THREE.RingGeometry(scale - 0.4, scale, 24);
          }
          
          // Pulsating rotation and opacity for cool energy effect
          this.auraCircle.rotation.z += 0.03;
          const pulse1 = Math.sin(gameTime * 6) * 0.12;
          const pulse2 = Math.sin(gameTime * 2.5) * 0.08;
          this.auraCircle.material.opacity = 0.2 + pulse1 + pulse2;
          // Pulsate scale for breathing energy effect
          const scalePulse = 1.0 + Math.sin(gameTime * 4) * 0.06;
          this.auraCircle.scale.set(scalePulse, scalePulse, 1);
          // Color shift for cool pulsating look
          const colorShift = Math.sin(gameTime * 3) * 0.5 + 0.5;
          this.auraCircle.material.color.setRGB(0.36 + colorShift * 0.1, 0.75 - colorShift * 0.1, 0.88 + colorShift * 0.1);
        } else {
          this.auraCircle.visible = false;
        }
        
        // Update fire ring orbs
        if (weapons.fireRing.active) {
          const currentOrbCount = weapons.fireRing.orbs;
          
          // Add orbs if needed
          while (this.fireRingOrbs.length < currentOrbCount) {
            const geo = new THREE.SphereGeometry(0.3, 8, 8);
            const mat = new THREE.MeshBasicMaterial({ 
              color: 0xFF4500, 
              transparent: true, 
              opacity: 0.8 
            });
            const orb = new THREE.Mesh(geo, mat);
            scene.add(orb);
            this.fireRingOrbs.push(orb);
          }
          
          // Remove extra orbs if downgraded (shouldn't happen but safety)
          while (this.fireRingOrbs.length > currentOrbCount) {
            const orb = this.fireRingOrbs.pop();
            scene.remove(orb);
            orb.geometry.dispose();
            orb.material.dispose();
          }
          
          // Update orb positions (orbit around player)
          this.fireRingAngle += weapons.fireRing.rotationSpeed * dt;
          const radius = weapons.fireRing.range;
          
          for (let i = 0; i < this.fireRingOrbs.length; i++) {
            const angle = this.fireRingAngle + (i * Math.PI * 2 / currentOrbCount);
            const orb = this.fireRingOrbs[i];
            orb.position.x = this.mesh.position.x + Math.cos(angle) * radius;
            orb.position.z = this.mesh.position.z + Math.sin(angle) * radius;
            orb.position.y = this.mesh.position.y + Math.sin(gameTime * 5 + i) * 0.3; // Bob up and down
            
            // Glow effect
            orb.material.opacity = 0.7 + Math.sin(gameTime * 8 + i) * 0.2;
            
            // Fire particles around each orb (throttled: every 3 frames)
            if (Math.floor(gameTime * 60) % 3 === i % 3) {
              spawnParticles(orb.position, 0xFF4500, 1);
            }
            if (Math.floor(gameTime * 60) % 7 === i % 7) {
              spawnParticles(orb.position, 0xFF8C00, 1);
            }
          }
        } else {
          // Hide orbs when weapon not active
          for (let orb of this.fireRingOrbs) {
            orb.visible = false;
          }
        }

        // Camera Follow
        camera.position.x = this.mesh.position.x;
        camera.position.z = this.mesh.position.z + 20; // Isometric offset
        camera.lookAt(this.mesh.position);

        // Bounds (Map is 400x400, from -200 to 200)
        this.mesh.position.x = Math.max(-195, Math.min(195, this.mesh.position.x));
        this.mesh.position.z = Math.max(-195, Math.min(195, this.mesh.position.z));
      }

      dash(dx, dz) {
        if (this.isDashing) return;
        this.isDashing = true;
        this.dashTime = this.dashDuration;
        
        // Splash effect on dash start - more dramatic
        spawnParticles(this.mesh.position, COLORS.player, 10); // Reduced for performance
        for(let i=0; i<8; i++) {
          spawnWaterDroplet(this.mesh.position);
        }
        
        // Direct mapping: Screen coordinates to World coordinates
        // Screen X-axis maps to World X-axis
        // Screen Y-axis maps to World Z-axis
        this.dashVec.set(dx, 0, dz).normalize();
        
        // Add dramatic lean/tilt in dash direction
        const dashAngleX = -dz * GAME_CONFIG.dashLeanFactor;
        const dashAngleZ = dx * GAME_CONFIG.dashLeanFactor;
        
        // Animate tilt during dash
        const originalRotX = this.mesh.rotation.x;
        const originalRotZ = this.mesh.rotation.z;
        
        // Quick tilt into dash
        this.mesh.rotation.x = dashAngleX;
        this.mesh.rotation.z = dashAngleZ;
        
        // Return to normal after dash with smooth animation
        setTimeout(() => {
          let returnProgress = 0;
          const returnDuration = GAME_CONFIG.dashLeanReturnDuration;
          const returnAnim = () => {
            returnProgress += 16; // ~16ms per frame
            const t = Math.min(returnProgress / returnDuration, 1);
            this.mesh.rotation.x = dashAngleX * (1 - t);
            this.mesh.rotation.z = dashAngleZ * (1 - t);
            if (t < 1) {
              requestAnimationFrame(returnAnim);
            }
          };
          returnAnim();
        }, this.dashDuration * 1000);
        
        // Water splash sound
        playSound('splash');
      }

      takeDamage(amount) {
        // Safety: do not process damage when game is not active or already over
        if (!isGameActive || isGameOver) return;
        // Prevent stray hits during boss kill-cam cinematics
        if (killCamActive) return;
        // Check invulnerability frames (hit-stun + dash invulnerability)
        if (this.invulnerable || dashInvulnerable) return;
        // Safety: ignore zero or negative damage to prevent phantom kills
        if (!amount || amount <= 0) return;

        // Dodge chance — chance to fully negate the hit
        if (playerStats.dodgeChance > 0 && Math.random() < playerStats.dodgeChance) {
          createFloatingText('DODGE!', this.mesh.position, '#00FFFF');
          spawnParticles(this.mesh.position, 0x00FFFF, 6);
          return;
        }

        // Armor reduction — delegated to GameCombat
        let reduced = calculateArmorReduction(amount, playerStats.armor);

        // Extra damage reduction from skill tree (additive with armor, after it)
        if (playerStats.damageReduction > 0) {
          reduced = Math.max(1, reduced * (1 - playerStats.damageReduction));
        }

        // Last Stand — survive a fatal hit once per run
        if (playerStats.hasLastStand && !playerStats.lastStandUsed && playerStats.hp - reduced <= 0) {
          playerStats.lastStandUsed = true;
          playerStats.hp = 1;
          createFloatingText('LAST STAND!', this.mesh.position, '#FFD700');
          spawnParticles(this.mesh.position, 0xFFD700, 20);
          updateHUD();
          playSound('levelup');
          return;
        }

        playerStats.hp -= reduced;
        updateHUD();
        playSound('hit');
        
        // Trigger waterdrop UI attack animation
        const waterdropContainer = document.getElementById('waterdrop-container');
        if (waterdropContainer) {
          waterdropContainer.classList.add('attacked');
          setTimeout(() => {
            waterdropContainer.classList.remove('attacked');
          }, 400);
        }
        
        // Show "X" eyes when hit
        if (!this.xEyesActive) {
          this.xEyesActive = true;
          // Hide normal eyes
          this.leftEye.visible = false;
          this.rightEye.visible = false;
          this.leftPupil.visible = false;
          this.rightPupil.visible = false;
          
          // Create X shapes for eyes
          const xMaterial = new THREE.MeshBasicMaterial({ color: 0x000000 });
          this.xEyes = [];
          
          // Left X
          const leftX1 = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.02, 0.01), xMaterial);
          leftX1.position.set(-0.12, 0.1, 0.4);
          leftX1.rotation.z = Math.PI / 4;
          this.mesh.add(leftX1);
          this.xEyes.push(leftX1);
          
          const leftX2 = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.02, 0.01), xMaterial);
          leftX2.position.set(-0.12, 0.1, 0.4);
          leftX2.rotation.z = -Math.PI / 4;
          this.mesh.add(leftX2);
          this.xEyes.push(leftX2);
          
          // Right X
          const rightX1 = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.02, 0.01), xMaterial);
          rightX1.position.set(0.12, 0.1, 0.4);
          rightX1.rotation.z = Math.PI / 4;
          this.mesh.add(rightX1);
          this.xEyes.push(rightX1);
          
          const rightX2 = new THREE.Mesh(new THREE.BoxGeometry(0.15, 0.02, 0.01), xMaterial);
          rightX2.position.set(0.12, 0.1, 0.4);
          rightX2.rotation.z = -Math.PI / 4;
          this.mesh.add(rightX2);
          this.xEyes.push(rightX2);
          
          // Remove X eyes after 300ms and restore normal eyes
          setTimeout(() => {
            this.xEyesActive = false;
            this.xEyes.forEach(x => this.mesh.remove(x));
            this.xEyes = [];
            this.leftEye.visible = true;
            this.rightEye.visible = true;
            this.leftPupil.visible = true;
            this.rightPupil.visible = true;
          }, 300);
        }
        
        // Show damage number for player (red color)
        const div = document.createElement('div');
        div.className = 'damage-number player-damage';
        div.innerText = `-${Math.floor(reduced)}`;
        div.style.color = '#FF4444';
        div.style.fontSize = '24px';
        div.style.fontWeight = 'bold';
        div.style.textShadow = '0 0 8px rgba(255,68,68,0.8), 2px 2px 4px #000';
        
        // Project 3D pos to 2D screen
        const vec = this.mesh.position.clone();
        vec.y += 2;
        vec.project(camera);
        
        const x = (vec.x * .5 + .5) * window.innerWidth;
        const y = (-(vec.y * .5) + .5) * window.innerHeight;
        
        div.style.position = 'absolute';
        div.style.left = `${x}px`;
        div.style.top = `${y}px`;
        div.style.transform = 'translate(-50%, -50%)';
        div.style.pointerEvents = 'none';
        div.style.zIndex = '1000';
        
        document.body.appendChild(div);
        setTimeout(() => div.remove(), 1000);
        
        // Set invulnerability
        this.invulnerable = true;
        this.invulnerabilityTime = 0;
        
        // Visual flash
        this.mesh.material.color.setHex(0xFF0000);
        setTimeout(() => {
          this.mesh.material.color.setHex(COLORS.player);
        }, 100);
        
        // Water-themed blood effects for player (blue water droplets)
        // Spawn blue water particles (player's "blood")
        spawnParticles(this.mesh.position, COLORS.player, 8); // Blue water
        spawnParticles(this.mesh.position, 0x87CEEB, 5); // Light blue splash
        spawnParticles(this.mesh.position, 0xFFFFFF, 3); // White foam
        
        // Water droplets as player blood
        for(let i=0; i<5; i++) {
          spawnWaterDroplet(this.mesh.position);
        }
        
        // Squishy deformation on hit - drive spring-damper directly for smooth recovery
        this.currentScaleXZ = 1.4;
        this.currentScaleY = 0.6;
        this.scaleXZVel = 0;
        this.scaleYVel = 0;
        
        // FRESH IMPLEMENTATION: Screen shake scales with damage amount
        // Cancel any previous shake to prevent stacked RAF loops
        if (_cameraShakeRAF) {
          cancelAnimationFrame(_cameraShakeRAF);
          _cameraShakeRAF = null;
        }
        const originalCameraPos = { 
          x: camera.position.x, 
          y: camera.position.y, 
          z: camera.position.z 
        };
        let shakeTime = 0;
        const shakeDuration = 0.25 + (reduced / 100) * 0.15; // Duration scales with damage
        
        const shakeAnim = () => {
          shakeTime += 0.016;
          if (shakeTime < shakeDuration) {
            // Intensity scales with damage (0.5 base + up to 0.5 more based on damage)
            const baseIntensity = 0.5 + Math.min(reduced / 50, 1) * 0.5;
            const intensity = (1 - shakeTime / shakeDuration) * baseIntensity;
            camera.position.x = originalCameraPos.x + (Math.random() - 0.5) * intensity;
            camera.position.y = originalCameraPos.y + (Math.random() - 0.5) * intensity;
            camera.position.z = originalCameraPos.z + (Math.random() - 0.5) * intensity;
            _cameraShakeRAF = requestAnimationFrame(shakeAnim);
          } else {
            _cameraShakeRAF = null;
            camera.position.x = originalCameraPos.x;
            camera.position.y = originalCameraPos.y;
            camera.position.z = originalCameraPos.z;
          }
        };
        shakeAnim();

        if (playerStats.hp <= 0 && !isGameOver) {
          // ENHANCED Death splash: more particles + ground pool with fade
          spawnParticles(this.mesh.position, COLORS.player, 25); // Reduced for performance
          spawnParticles(this.mesh.position, 0xFFFFFF, 8); // Reduced for performance
          
          // Create ground pool (flat circle that fades out)
          const poolGeo = new THREE.CircleGeometry(1.5, 16);
          const poolMat = new THREE.MeshBasicMaterial({ 
            color: COLORS.player, 
            transparent: true, 
            opacity: 0.6,
            side: THREE.DoubleSide
          });
          const pool = new THREE.Mesh(poolGeo, poolMat);
          pool.rotation.x = -Math.PI / 2;
          pool.position.set(this.mesh.position.x, 0.05, this.mesh.position.z);
          scene.add(pool);
          
          // Fade out pool over time
          const fadePool = () => {
            poolMat.opacity -= 0.01;
            if (poolMat.opacity > 0) {
              setTimeout(fadePool, 50);
            } else {
              scene.remove(pool);
              poolGeo.dispose();
              poolMat.dispose();
            }
          };
          setTimeout(fadePool, 500);
          
          gameOver();
        }
      }
    }

    // Cached deformed geometry for Hard Tank (performance optimization)
    // Note: All Hard Tank enemies share the same deformed shape for performance.
    // This is intentional - visual variety comes from animations and positioning.
    let hardTankGeometryCache = null;

    // Water particle pool for player physics effects
    const waterParticlePool = [];
    const MAX_WATER_PARTICLES = 20;
    let waterParticleGeom = null;
    let waterParticleMat = null;

    function spawnWaterParticle(pos) {
      if (!scene) return;
      let p = waterParticlePool.find(x => !x.active);
      if (!p) {
        if (waterParticlePool.length >= MAX_WATER_PARTICLES) return;
        if (!waterParticleGeom) waterParticleGeom = new THREE.SphereGeometry(0.12, 4, 4);
        if (!waterParticleMat) waterParticleMat = new THREE.MeshBasicMaterial({ color: 0x44aabb, transparent: true, opacity: 0.7 });
        const mesh = new THREE.Mesh(waterParticleGeom, waterParticleMat.clone());
        p = { mesh, active: false, life: 0, vx: 0, vy: 0, vz: 0 };
        scene.add(p.mesh);
        waterParticlePool.push(p);
      }
      p.active = true;
      p.life = 0.5;
      p.mesh.position.set(pos.x + (Math.random()-0.5)*0.5, pos.y + Math.random()*0.5, pos.z + (Math.random()-0.5)*0.5);
      p.mesh.scale.setScalar(1);
      p.mesh.material.opacity = 0.7;
      p.vx = (Math.random()-0.5)*4;
      p.vy = Math.random()*3+1;
      p.vz = (Math.random()-0.5)*4;
      p.mesh.visible = true;
    }

    function updateWaterParticles(delta) {
      for (const p of waterParticlePool) {
        if (!p.active) continue;
        p.life -= delta;
        if (p.life <= 0) { p.active = false; p.mesh.visible = false; continue; }
        p.mesh.position.x += p.vx * delta;
        p.mesh.position.y += p.vy * delta;
        p.mesh.position.z += p.vz * delta;
        p.vy -= 9.8 * delta;
        const lifeFrac = p.life / 0.5;
        p.mesh.scale.setScalar(lifeFrac * 0.8);
        p.mesh.material.opacity = lifeFrac * 0.7;
      }
    }
    function getHardTankGeometry() {
      if (!hardTankGeometryCache) {
        const geometry = new THREE.SphereGeometry(0.6, 8, 8);
        const positions = geometry.attributes.position;
        for (let i = 0; i < positions.count; i++) {
          const x = positions.getX(i);
          const y = positions.getY(i);
          const z = positions.getZ(i);
          const noiseX = 1 + (Math.random() - 0.5) * 0.3;
          const noiseY = 1 + (Math.random() - 0.5) * 0.3;
          const noiseZ = 1 + (Math.random() - 0.5) * 0.3;
          positions.setX(i, x * noiseX);
          positions.setY(i, y * noiseY);
          positions.setZ(i, z * noiseZ);
        }
        geometry.computeVertexNormals();
        hardTankGeometryCache = geometry;
      }
      return hardTankGeometryCache;
    }

    // Drone Turret class - New weapon replacing Lightning
    class DroneTurret {
      constructor(player) {
        this.player = player;
        this.offset = new THREE.Vector3(2, 1.5, 0); // Initial hover position relative to player
        this.wobblePhase = Math.random() * Math.PI * 2; // Random starting phase
        
        // Create drone body - small mechanical unit
        const bodyGeo = new THREE.BoxGeometry(0.4, 0.3, 0.4);
        const bodyMat = new THREE.MeshToonMaterial({ 
          color: 0x808080, // Gray metallic
          emissive: 0x404040,
          emissiveIntensity: 0.3
        });
        this.mesh = new THREE.Mesh(bodyGeo, bodyMat);
        scene.add(this.mesh);
        
        // Add glowing core
        const coreGeo = new THREE.SphereGeometry(0.15, 8, 8);
        const coreMat = new THREE.MeshBasicMaterial({ 
          color: 0x00FFFF, // Cyan glow
          transparent: true,
          opacity: 0.8
        });
        this.core = new THREE.Mesh(coreGeo, coreMat);
        this.core.position.y = 0;
        this.mesh.add(this.core);
        
        // Add propellers/rotors on top
        const propGeo = new THREE.BoxGeometry(0.6, 0.05, 0.1);
        const propMat = new THREE.MeshBasicMaterial({ color: 0x333333 });
        this.propeller1 = new THREE.Mesh(propGeo, propMat);
        this.propeller1.position.y = 0.2;
        this.mesh.add(this.propeller1);
        
        this.propeller2 = new THREE.Mesh(propGeo, propMat);
        this.propeller2.position.y = 0.2;
        this.propeller2.rotation.y = Math.PI / 2;
        this.mesh.add(this.propeller2);
        
        // Add small barrel/gun
        const barrelGeo = new THREE.CylinderGeometry(0.05, 0.05, 0.3, 6);
        const barrelMat = new THREE.MeshToonMaterial({ color: 0x222222 });
        this.barrel = new THREE.Mesh(barrelGeo, barrelMat);
        this.barrel.rotation.x = Math.PI / 2;
        this.barrel.position.z = 0.3;
        this.barrel.position.y = -0.1;
        this.mesh.add(this.barrel);
        
        this.active = true;
        this.shootTimer = 0;
      }
      
      update(dt) {
        if (!this.active) {
          this.mesh.visible = false;
          return;
        }
        
        this.mesh.visible = true;
        
        // Hover near player with smooth bobbing motion
        this.wobblePhase += dt * 3;
        const bobHeight = Math.sin(this.wobblePhase) * 0.2;
        
        // Target position relative to player
        const targetX = this.player.mesh.position.x + this.offset.x;
        const targetY = this.player.mesh.position.y + this.offset.y + bobHeight;
        const targetZ = this.player.mesh.position.z + this.offset.z;
        
        // Smooth follow with lerp (frame-rate independent)
        const lerpSpeed = 0.1 / dt; // Normalize for frame rate
        const lerpFactor = Math.min(1, dt * 6); // Cap at 1.0, smooth at 60fps
        this.mesh.position.x += (targetX - this.mesh.position.x) * lerpFactor;
        this.mesh.position.y += (targetY - this.mesh.position.y) * lerpFactor;
        this.mesh.position.z += (targetZ - this.mesh.position.z) * lerpFactor;
        
        // Rotate propellers (frame-rate independent)
        this.propeller1.rotation.y += 0.3 * dt * 60; // Normalized for 60fps
        this.propeller2.rotation.y += 0.3 * dt * 60;
        
        // Pulse core
        this.core.material.opacity = 0.6 + Math.sin(gameTime * 5) * 0.2;
        
        // Find and track nearest enemy
        let nearestEnemy = null;
        let minDist = Infinity;
        
        for (let e of enemies) {
          if (e.isDead) continue;
          const dist = this.mesh.position.distanceTo(e.mesh.position);
          if (dist < weapons.droneTurret.range && dist < minDist) {
            minDist = dist;
            nearestEnemy = e;
          }
        }
        
        // Aim barrel at target
        if (nearestEnemy) {
          const dx = nearestEnemy.mesh.position.x - this.mesh.position.x;
          const dz = nearestEnemy.mesh.position.z - this.mesh.position.z;
          const angle = Math.atan2(dx, dz);
          this.mesh.rotation.y = angle;
        }
      }
      
      destroy() {
        if (this.mesh) {
          scene.remove(this.mesh);
          this.mesh.geometry.dispose();
          this.mesh.material.dispose();
          if (this.core) {
            this.core.geometry.dispose();
            this.core.material.dispose();
          }
          if (this.propeller1) {
            this.propeller1.geometry.dispose();
            this.propeller1.material.dispose();
          }
          if (this.propeller2) {
            this.propeller2.geometry.dispose();
            this.propeller2.material.dispose();
          }
          if (this.barrel) {
            this.barrel.geometry.dispose();
            this.barrel.material.dispose();
          }
        }
      }
    }

    class Enemy {
      constructor(type, x, z, playerLevel = 1) {
        this.type = type; // 0: Tank, 1: Fast, 2: Balanced, 3: Slowing, 4: Ranged, 5: Flying, 6: Hard Tank, 7: Hard Fast, 8: Hard Balanced, 9: Elite, 10: MiniBoss, 11: FlyingBoss, 12: BugRanged, 13: BugSlow, 14: BugFast
        let geometry;
        let color;
        
        // Enemy scaling based on player level - NOT SPEED, just HP and DAMAGE
        // Progressive difficulty: 20% per level to force use of all upgrades
        const levelScaling = 1 + (playerLevel - 1) * 0.20;
        
        if (type === 0) {
          // Bacteria/Amoeba - Squishy organic blob shape
          geometry = new THREE.SphereGeometry(0.6, 8, 8);
          // Modify geometry to make it irregular/organic
          const positions = geometry.attributes.position;
          for (let i = 0; i < positions.count; i++) {
            const x = positions.getX(i);
            const y = positions.getY(i);
            const z = positions.getZ(i);
            // Add different randomness for each axis for truly organic look
            const noiseX = 1 + (Math.random() - 0.5) * 0.3;
            const noiseY = 1 + (Math.random() - 0.5) * 0.3;
            const noiseZ = 1 + (Math.random() - 0.5) * 0.3;
            positions.setX(i, x * noiseX);
            positions.setY(i, y * noiseY);
            positions.setZ(i, z * noiseZ);
          }
          geometry.computeVertexNormals();
          color = COLORS.enemySquare; // Pink/Hot Pink - Tanky
        } else if (type === 1) {
          // Water Bug - Elongated with segments
          geometry = new THREE.CapsuleGeometry(0.3, 0.8, 6, 8);
          color = COLORS.enemyTriangle; // Gold - Fast
        } else if (type === 2) {
          // Microbe - Round squishy
          geometry = new THREE.DodecahedronGeometry(0.5, 0);
          color = COLORS.enemyRound; // Purple - Balanced
        } else if (type === 3) {
          // Slowing Enemy - Spiky/icy appearance
          geometry = new THREE.IcosahedronGeometry(0.55, 0);
          color = 0x00FFFF; // Cyan - Slowing
        } else if (type === 4) {
          // Ranged Enemy - Different shape, angular
          geometry = new THREE.TetrahedronGeometry(0.6, 0);
          color = 0xFF6347; // Tomato red - Ranged
        } else if (type === 5) {
          // Flying Enemy - Octahedron
          geometry = new THREE.OctahedronGeometry(0.5, 1);
          color = 0x87CEEB; // Sky blue - Flying
        } else if (type === 6) {
          // Hard Tank - use cached deformed geometry for performance
          geometry = getHardTankGeometry();
          color = 0xFF1493; // Deep pink - Hard Tank
        } else if (type === 7) {
          // Hard Fast
          geometry = new THREE.CapsuleGeometry(0.3, 0.8, 6, 8);
          color = 0xFFD700; // Gold - Hard Fast
        } else if (type === 8) {
          // Hard Balanced
          geometry = new THREE.DodecahedronGeometry(0.5, 0);
          color = 0x9932CC; // Dark orchid - Hard Balanced
        } else if (type === 9) {
          // Elite
          geometry = new THREE.IcosahedronGeometry(0.6, 0);
          color = 0xFF0000; // Red - Elite
        } else if (type === 10) {
          // MiniBoss
          geometry = new THREE.DodecahedronGeometry(1.0, 1);
          color = 0xFFD700; // Gold - MiniBoss
        } else if (type === 11) {
          // Flying Boss — large, imposing, multi-winged form
          geometry = new THREE.IcosahedronGeometry(2.5, 1);
          color = 0x8B008B; // Dark magenta — menacing flying boss
        } else if (type === 12) {
          // Bug Ranged — insect-like body with compound eyes
          geometry = new THREE.CapsuleGeometry(0.35, 0.6, 6, 8);
          color = 0x556B2F; // Dark olive green — bug colour
        } else if (type === 13) {
          // Bug Slow — bulky armoured beetle-like body
          geometry = new THREE.SphereGeometry(0.7, 10, 10);
          color = 0x2F4F2F; // Very dark green — armoured beetle
        } else if (type === 14) {
          // Bug Fast — small dart-like flying bug
          geometry = new THREE.OctahedronGeometry(0.35, 1);
          color = 0x9ACD32; // Yellow-green — quick bug
        } else if (type === 15) {
          // Daddy Longlegs — small round spider body
          geometry = new THREE.SphereGeometry(0.28, 10, 10);
          color = 0x8B4513; // Brown spider body
        } else if (type === 16) {
          // Sweeping Swarm — small fast diamond shape
          geometry = new THREE.OctahedronGeometry(0.22, 0);
          color = 0xFFAA00; // Amber swarm colour
        }

        const material = new THREE.MeshPhysicalMaterial({ 
          color: color,
          transparent: true,
          opacity: 0.85,
          metalness: (type === 10 || type === 11) ? 0.4 : (type === 13 ? 0.3 : 0.1),
          roughness: type === 13 ? 0.8 : 0.6,
          transmission: 0.2,
          thickness: 0.5,
          emissive: (type === 10 || type === 11) ? color : 0x000000,
          emissiveIntensity: type === 10 ? 0.3 : (type === 11 ? 0.5 : 0)
        });
        this.mesh = new THREE.Mesh(geometry, material);
        // Flying enemies hover higher; Flying Boss is enormous and hovers high
        const yPos = (type === 5 || type === 14 || type === 16) ? 2 : (type === 11 ? 5 : 0.5);
        this.mesh.position.set(x, yPos, z);
        // Flying Boss is scaled large enough to be dramatic but still mostly visible on screen
        if (type === 11) this.mesh.scale.set(1.8, 1.8, 1.8);
        this.mesh.castShadow = true;
        this.mesh.receiveShadow = true;
        scene.add(this.mesh);

        // Add legs to Daddy Longlegs spider
        if (type === 15) {
          const legMat = new THREE.MeshLambertMaterial({ color: 0x5C3317 });
          for (let leg = 0; leg < 8; leg++) {
            const legAngle = (leg / 8) * Math.PI * 2;
            const legGeo = new THREE.CylinderGeometry(0.02, 0.02, 0.9, 4);
            const legMesh = new THREE.Mesh(legGeo, legMat);
            legMesh.rotation.z = Math.PI / 2 - 0.4;
            legMesh.rotation.y = legAngle;
            legMesh.position.set(Math.cos(legAngle) * 0.35, -0.1, Math.sin(legAngle) * 0.35);
            this.mesh.add(legMesh);
          }
          this._rearingPhase = 0; // 0=walking 1=rearing up 2=attacking
          this._rearingTimer = 0;
        }

        // Ground shadow for flying enemies
        this.groundShadow = null;
        if (type === 5 || type === 11 || type === 14 || type === 16) {
          const shadowRadius = type === 11 ? 2.0 : (type === 5 ? 0.6 : 0.35);
          const shadowGeo = new THREE.CircleGeometry(shadowRadius, 12);
          const shadowMat = new THREE.MeshBasicMaterial({ color: 0x000000, transparent: true, opacity: 0.25, depthWrite: false });
          this.groundShadow = new THREE.Mesh(shadowGeo, shadowMat);
          this.groundShadow.rotation.x = -Math.PI / 2;
          this.groundShadow.position.set(x, 0.05, z);
          scene.add(this.groundShadow);
        }

        // Stats based on type — delegated to GameEnemies.getEnemyBaseStats
        Object.assign(this, getEnemyBaseStats(type, levelScaling, GAME_CONFIG.enemySpeedBase, playerLevel));
        this.isDead = false;
        this.isDamaged = false; // Track if enemy has been visually damaged
        this.pulsePhase = Math.random() * Math.PI;
        this.wobbleOffset = Math.random() * 100;
        this.lastAttackTime = 0;
        this.attackCooldown = 1000; // 1 second cooldown
        // AI state for smarter behaviors
        this._aiState = 'approach'; // approach, flank, retreat, dive, wait
        this._aiTimer = 0;
        this._aiCooldown = 1.0 + Math.random() * 2.0; // Randomize decision intervals
        this._lastPlayerPos = null; // For movement prediction
        this._playerVelocity = { x: 0, z: 0 }; // Estimated player velocity
        this._flankAngle = (Math.random() > 0.5 ? 1 : -1) * (Math.PI * 0.3 + Math.random() * Math.PI * 0.4);
        this._packRush = false; // Pack behavior: periodic group rush flag
        // Armor defaults to 0 if not set (only MiniBoss has armor = 0.25)
        
        // Add glowing eyes to enemy (VFX) with realistic pupils
        const eyeRadius = type === 10 ? 0.12 : (type === 11 ? 0.28 : (type === 13 ? 0.10 : 0.07));
        const eyeColor = type === 4 ? 0xFF3300 : (type === 10 ? 0xFF0000 : (type === 11 ? 0xFF0000 : (type >= 12 ? 0xFF6600 : 0xFF2222)));
        const eGeo = new THREE.SphereGeometry(eyeRadius, 6, 6);
        const eMat = new THREE.MeshBasicMaterial({ color: 0xFFFFFF }); // White sclera
        const eyeSpread = type === 10 ? 0.3 : (type === 11 ? 0.7 : (type === 13 ? 0.25 : 0.18));
        const eyeForward = type === 5 ? 0.45 : (type === 11 ? 2.0 : (type === 14 ? 0.3 : 0.42));
        this.leftEye = new THREE.Mesh(eGeo, eMat);
        this.leftEye.position.set(-eyeSpread, 0.1, eyeForward);
        this.mesh.add(this.leftEye);
        this.rightEye = new THREE.Mesh(eGeo, eMat.clone());
        this.rightEye.position.set(eyeSpread, 0.1, eyeForward);
        this.mesh.add(this.rightEye);
        // Add colored iris + dark pupil for realistic eyes
        const pupilRadius = eyeRadius * 0.55;
        const pupilGeo = new THREE.SphereGeometry(pupilRadius, 5, 5);
        const irisMat = new THREE.MeshBasicMaterial({ color: eyeColor });
        const leftIris = new THREE.Mesh(pupilGeo, irisMat);
        leftIris.position.set(0, 0, eyeRadius * 0.55);
        this.leftEye.add(leftIris);
        const rightIris = new THREE.Mesh(pupilGeo, irisMat.clone());
        rightIris.position.set(0, 0, eyeRadius * 0.55);
        this.rightEye.add(rightIris);
        // Inner dark pupil
        const innerPupilGeo = new THREE.SphereGeometry(pupilRadius * 0.5, 4, 4);
        const innerPupilMat = new THREE.MeshBasicMaterial({ color: 0x000000 });
        const leftPupil = new THREE.Mesh(innerPupilGeo, innerPupilMat);
        leftPupil.position.set(0, 0, pupilRadius * 0.4);
        leftIris.add(leftPupil);
        const rightPupil = new THREE.Mesh(innerPupilGeo, innerPupilMat.clone());
        rightPupil.position.set(0, 0, pupilRadius * 0.4);
        rightIris.add(rightPupil);
        // Blink timer
        this.blinkTimer = 0;
        this.blinkDuration = 0.08;
        this.nextBlinkTime = 1.5 + Math.random() * 3.5;
        this.isBlinking = false;
      }

      update(dt, playerPos) {
        if (this.isDead) return;

        // Windmill Quest: Attack windmill instead of player
        let targetPos = playerPos;
        if (windmillQuest.active && windmillQuest.windmill) {
          targetPos = windmillQuest.windmill.position;
        }

        // Move towards target
        const dx = targetPos.x - this.mesh.position.x;
        const dz = targetPos.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);

        // Estimate player velocity for prediction AI
        if (this._lastPlayerPos) {
          this._playerVelocity.x = (playerPos.x - this._lastPlayerPos.x) / Math.max(dt, 0.016);
          this._playerVelocity.z = (playerPos.z - this._lastPlayerPos.z) / Math.max(dt, 0.016);
        }
        this._lastPlayerPos = { x: playerPos.x, z: playerPos.z };
        
        // AI decision timer
        this._aiTimer += dt;

        // Ranged Enemy behavior - stop at range, strafe, and shoot
        if (this.type === 4 && dist < this.attackRange) {
          const now = Date.now();
          if (now - this.lastAttackTime > this.attackCooldown) {
            this.fireProjectile(targetPos);
            this.lastAttackTime = now;
          }
          // Smart retreat - predict player direction and dodge accordingly
          if (dist < 3.0) {
            const retreatX = -(dx / dist) + this._playerVelocity.x * 0.3;
            const retreatZ = -(dz / dist) + this._playerVelocity.z * 0.3;
            const rMag = Math.sqrt(retreatX*retreatX + retreatZ*retreatZ) || 1;
            this.mesh.position.x += (retreatX / rMag) * this.speed * 1.8;
            this.mesh.position.z += (retreatZ / rMag) * this.speed * 1.8;
          } else {
            // Strafe while shooting - vary pattern
            const strafeDir = Math.sin(gameTime * 3 + this.wobbleOffset) > 0 ? 1 : -1;
            const perpX = -dz / dist;
            const perpZ =  dx / dist;
            this.mesh.position.x += perpX * this.speed * 0.5 * strafeDir;
            this.mesh.position.z += perpZ * this.speed * 0.5 * strafeDir;
          }
          this.mesh.lookAt(targetPos);
        } else if (this.type === 12 && dist < this.attackRange) {
          // Bug Ranged — strafe sideways while firing, retreat if too close
          const now = Date.now();
          if (now - this.lastAttackTime > 1800) {
            this.fireProjectile(targetPos);
            this.lastAttackTime = now;
          }
          if (dist < 4.0) {
            this.mesh.position.x -= (dx / dist) * this.speed * 1.2;
            this.mesh.position.z -= (dz / dist) * this.speed * 1.2;
          } else {
            const perpX = -dz / dist;
            const perpZ =  dx / dist;
            this.mesh.position.x += perpX * this.speed * 0.7;
            this.mesh.position.z += perpZ * this.speed * 0.7;
          }
          this.mesh.lookAt(new THREE.Vector3(targetPos.x, this.mesh.position.y, targetPos.z));
        } else if (this.isFlyingBoss && dist < this.attackRange) {
          // Flying Boss — orbit player and fire powerful projectiles
          const now = Date.now();
          if (now - this.lastAttackTime > 2000) {
            this.fireProjectile(targetPos);
            this.lastAttackTime = now;
          }
          // Orbit with varying radius
          const orbitSpeed = 0.012;
          const angle = Math.atan2(this.mesh.position.z - targetPos.z, this.mesh.position.x - targetPos.x);
          const newAngle = angle + orbitSpeed;
          const orbitR = this.attackRange * (0.6 + Math.sin(gameTime * 0.5) * 0.2);
          this.mesh.position.x = targetPos.x + Math.cos(newAngle) * orbitR;
          this.mesh.position.z = targetPos.z + Math.sin(newAngle) * orbitR;
          this.mesh.lookAt(new THREE.Vector3(targetPos.x, this.mesh.position.y, targetPos.z));
        } else if (dist > 0.5) {
          // Check if slow/freeze effect expired
          const nowMs = Date.now();
          if (this.slowedUntil && this.slowedUntil < nowMs) {
            this.speed = this.originalSpeed || this.speed;
            this.slowedUntil = null;
          }
          // Handle freeze expiry: thaw enemy, restore color and speed
          if (this.isFrozen && this.frozenUntil < nowMs) {
            this.isFrozen = false;
            this._freezeProgress = 0;
            this.speed = this.originalSpeed || this.speed;
            if (this.mesh && this.mesh.material && this._originalColor) {
              this.mesh.material.color.copy(this._originalColor);
              if (this.mesh.material.emissive) {
                this.mesh.material.emissive.setHex(0x000000);
                this.mesh.material.emissiveIntensity = 0;
              }
              this.mesh.material.needsUpdate = true;
            }
            // Remove ice crack overlays on thaw
            if (this._iceCracks && this._iceCracks.length > 0) {
              for (const crack of this._iceCracks) {
                this.mesh.remove(crack);
                crack.geometry.dispose();
                crack.material.dispose();
              }
              this._iceCracks = [];
            }
            // Shatter ice: spawn ice chips flying outward
            spawnParticles(this.mesh.position, 0xAEEEFF, 6);
            spawnParticles(this.mesh.position, 0xFFFFFF, 4);
            // Ice crack particles + water pool on ground
            if (window.BloodSystem) {
              window.BloodSystem.emitBurst(this.mesh.position, 30, { spreadXZ: 0.6, spreadY: 0.4, color1: 0xAEEEFF, color2: 0xFFFFFF, minSize: 0.05, maxSize: 0.14 });
            }
            // Brief shaking struggle: enemy wiggles before breaking free
            let shakeCount = 0;
            const origX = this.mesh.position.x;
            const origZ = this.mesh.position.z;
            const shakeInterval = setInterval(() => {
              shakeCount++;
              if (this.mesh) {
                this.mesh.position.x = origX + (Math.random() - 0.5) * 0.12;
                this.mesh.position.z = origZ + (Math.random() - 0.5) * 0.12;
              }
              if (shakeCount >= 8) {
                clearInterval(shakeInterval);
                if (this.mesh) { this.mesh.position.x = origX; this.mesh.position.z = origZ; }
              }
            }, 40);
          }
          
          // Frozen enemies stop moving
          if (this.isFrozen) {
            // Gradual freeze visual: lerp from original → ice blue based on freeze progress
            if (this.mesh && this.mesh.material && this._originalColor && this.frozenUntil) {
              const totalFreezeDur = this._freezeDuration || 2500;
              const elapsed = Math.max(0, nowMs - (this.frozenUntil - totalFreezeDur));
              const freezeT = Math.min(1, elapsed / 600); // 600ms to reach full ice
              const iceColor = new THREE.Color(0xB0E8FF);
              this.mesh.material.color.copy(this._originalColor).lerp(iceColor, freezeT);
              this.mesh.material.emissiveIntensity = 0.3 + Math.sin(gameTime * 8) * 0.15 * freezeT;
            }
            // Skip all movement below
          } else {
          
          // Base movement towards target
          let vx = (dx / dist) * this.speed;
          let vz = (dz / dist) * this.speed;
          
          // Add enemy avoidance to prevent stacking/trains (optimized — squared distance to skip sqrt)
          let avoidX = 0, avoidZ = 0;
          let avoidanceCount = 0;
          const maxAvoidanceChecks = 5;
          const avoidRadiusSq = 1.5 * 1.5;
          for (let other of enemies) {
            if (other === this || other.isDead) continue;
            if (avoidanceCount >= maxAvoidanceChecks) break;
            const odx = this.mesh.position.x - other.mesh.position.x;
            const odz = this.mesh.position.z - other.mesh.position.z;
            const odistSq = odx*odx + odz*odz;
            
            if (odistSq < avoidRadiusSq && odistSq > 0.0001) {
              const odist = Math.sqrt(odistSq);
              const repulsion = 0.02;
              avoidX += (odx / odist) * repulsion;
              avoidZ += (odz / odist) * repulsion;
              avoidanceCount++;
            }
          }
          const avoidMag = Math.sqrt(avoidX*avoidX + avoidZ*avoidZ);
          if (avoidMag > this.speed * 0.6) {
            const scale = (this.speed * 0.6) / avoidMag;
            avoidX *= scale;
            avoidZ *= scale;
          }
          vx += avoidX;
          vz += avoidZ;
          
          // AI Behavior System - each enemy type acts differently
          const behavior = this.aiBehavior || 'approach';
          
          if (behavior === 'interceptor') {
            // Predict where the player will be and move to intercept
            const predictTime = Math.min(dist / (this.speed * 60), 1.5);
            const predictX = targetPos.x + this._playerVelocity.x * predictTime * 0.5;
            const predictZ = targetPos.z + this._playerVelocity.z * predictTime * 0.5;
            const pdx = predictX - this.mesh.position.x;
            const pdz = predictZ - this.mesh.position.z;
            const pdist = Math.sqrt(pdx*pdx + pdz*pdz) || 1;
            vx = (pdx / pdist) * this.speed;
            vz = (pdz / pdist) * this.speed;
            // Charge when close
            if (dist < 5 && dist > 1.5 && !this._charging) {
              if (Math.random() < 0.008) {
                this._charging = true;
                this._chargeTime = 0.5;
              }
            }
            if (this._charging) {
              this._chargeTime -= dt;
              vx = (dx / dist) * this.speed * 3;
              vz = (dz / dist) * this.speed * 3;
              if (this._chargeTime <= 0) this._charging = false;
            }
          } else if (behavior === 'flanker') {
            // Approach from the side/behind the player, blend with forward movement to ensure closure
            if (this._aiTimer > this._aiCooldown) {
              this._aiTimer = 0;
              this._flankAngle = (Math.random() > 0.5 ? 1 : -1) * (Math.PI * 0.25 + Math.random() * Math.PI * 0.35);
              this._aiCooldown = 0.8 + Math.random() * 1.5;
            }
            const flankX = dx * Math.cos(this._flankAngle) - dz * Math.sin(this._flankAngle);
            const flankZ = dx * Math.sin(this._flankAngle) + dz * Math.cos(this._flankAngle);
            const fMag = Math.sqrt(flankX*flankX + flankZ*flankZ) || 1;
            if (dist > 3) {
              // Blend flank direction with direct approach so enemies always close distance
              const blend = Math.min(1, (dist - 3) / 5);
              vx = (flankX / fMag) * this.speed * (1 - blend * 0.4) + (dx / dist) * this.speed * blend * 0.4;
              vz = (flankZ / fMag) * this.speed * (1 - blend * 0.4) + (dz / dist) * this.speed * blend * 0.4;
            } else {
              // Close range: dash straight at player
              vx = (dx / dist) * this.speed * 1.6;
              vz = (dz / dist) * this.speed * 1.6;
            }
          } else if (behavior === 'pack') {
            // Spread out and surround the player, then rush together
            const surroundDist = 3 + Math.sin(this.wobbleOffset) * 1.5;
            // Periodically force a group rush to prevent endless circling
            if (this._aiTimer > this._aiCooldown) {
              this._aiTimer = 0;
              this._aiCooldown = 1.5 + Math.random() * 2.0;
              this._packRush = true;
            }
            if (this._packRush) {
              // Rush straight at player
              vx = (dx / dist) * this.speed * 1.4;
              vz = (dz / dist) * this.speed * 1.4;
              if (dist < 1.5) this._packRush = false;
            } else if (dist > surroundDist + 1) {
              // Move towards player with slight weave
              vx = (dx / dist) * this.speed;
              vz = (dz / dist) * this.speed;
              const weave = Math.sin(gameTime * 4 + this.wobbleOffset) * 0.06;
              vx += weave * (-dz/dist);
              vz += weave * (dx/dist);
            } else if (dist > 1.5) {
              // Circle around player — always maintain inward pull to prevent endless orbit
              const perpX = -dz / dist;
              const perpZ =  dx / dist;
              const circleDir = this.wobbleOffset > 50 ? 1 : -1;
              vx = perpX * this.speed * 0.5 * circleDir + (dx / dist) * this.speed * 0.5;
              vz = perpZ * this.speed * 0.5 * circleDir + (dz / dist) * this.speed * 0.5;
            }
          } else if (behavior === 'ambusher') {
            // Wait at medium range then dash in
            if (this._aiState === 'approach' && dist < 6) {
              this._aiState = 'wait';
              this._aiTimer = 0;
            }
            if (this._aiState === 'wait') {
              // Hold position, slight drift
              vx *= 0.1;
              vz *= 0.1;
              if (this._aiTimer > 1.5 + Math.random()) {
                this._aiState = 'dash';
                this._aiTimer = 0;
              }
            } else if (this._aiState === 'dash') {
              vx = (dx / dist) * this.speed * 2.5;
              vz = (dz / dist) * this.speed * 2.5;
              if (dist < 1.2 || this._aiTimer > 0.6) {
                this._aiState = 'retreat';
                this._aiTimer = 0;
              }
            } else if (this._aiState === 'retreat') {
              vx = -(dx / dist) * this.speed * 1.2;
              vz = -(dz / dist) * this.speed * 1.2;
              if (this._aiTimer > 0.8 || dist > 7) {
                this._aiState = 'approach';
                this._aiTimer = 0;
              }
            }
          } else if (behavior === 'kiter') {
            // Maintain optimal range, retreat when player approaches
            const optimalRange = this.attackRange ? this.attackRange * 0.7 : 6;
            if (dist < optimalRange - 1) {
              // Too close - back away
              vx = -(dx / dist) * this.speed * 1.5;
              vz = -(dz / dist) * this.speed * 1.5;
            } else if (dist < optimalRange + 2) {
              // At range - strafe
              const perpX = -dz / dist;
              const perpZ =  dx / dist;
              const sDir = Math.sin(gameTime * 2 + this.wobbleOffset) > 0 ? 1 : -1;
              vx = perpX * this.speed * 0.6 * sDir;
              vz = perpZ * this.speed * 0.6 * sDir;
            }
            // else: approach normally (default vx/vz)
          } else if (behavior === 'divebomber') {
            // Swoop in fast then pull away
            if (this._aiState === 'approach' && dist < 5) {
              this._aiState = 'dive';
              this._aiTimer = 0;
            }
            if (this._aiState === 'dive') {
              vx = (dx / dist) * this.speed * 2.0;
              vz = (dz / dist) * this.speed * 2.0;
              if (dist < 1.5 || this._aiTimer > 0.5) {
                this._aiState = 'pullup';
                this._aiTimer = 0;
              }
            } else if (this._aiState === 'pullup') {
              // Fly away at angle
              const escAngle = Math.atan2(dz, dx) + Math.PI + this._flankAngle * 0.5;
              vx = Math.cos(escAngle) * this.speed * 1.5;
              vz = Math.sin(escAngle) * this.speed * 1.5;
              if (this._aiTimer > 1.0 || dist > 8) {
                this._aiState = 'approach';
                this._aiTimer = 0;
              }
            }
          } else if (behavior === 'stalker') {
            // Circle at medium range, strike when player is fighting others
            // Only count nearby attackers (limit check count for performance)
            let nearbyAttacking = 0;
            for (let i = 0, count = 0; i < enemies.length && count < 8; i++) {
              const e = enemies[i];
              if (e === this || e.isDead) continue;
              count++;
              const edx = e.mesh.position.x - playerPos.x;
              const edz = e.mesh.position.z - playerPos.z;
              if (edx*edx + edz*edz < 9) nearbyAttacking++;
            }
            
            if (nearbyAttacking >= 2 || dist < 2) {
              // Player is distracted - rush in
              vx = (dx / dist) * this.speed * 1.8;
              vz = (dz / dist) * this.speed * 1.8;
            } else if (dist < 8) {
              // Circle at medium range
              const perpX = -dz / dist;
              const perpZ =  dx / dist;
              vx = perpX * this.speed * 0.5 + (dx / dist) * this.speed * 0.15;
              vz = perpZ * this.speed * 0.5 + (dz / dist) * this.speed * 0.15;
            }
          } else if (behavior === 'rearing') {
            // Daddy Longlegs: creep toward player, then rear up and attack
            if (!this._rearingPhase) this._rearingPhase = 0;
            if (!this._rearingTimer) this._rearingTimer = 0;
            this._rearingTimer += dt;
            if (this._rearingPhase === 0) {
              // Walking phase: approach slowly
              if (dist > this.attackRange) {
                vx = (dx / dist) * this.speed * 0.8;
                vz = (dz / dist) * this.speed * 0.8;
              } else if (this._rearingTimer > 1.0) {
                // Close enough — start rearing
                this._rearingPhase = 1;
                this._rearingTimer = 0;
              }
            } else if (this._rearingPhase === 1) {
              // Rearing up: lift body, legs spread wide (animated via Y position)
              this.mesh.position.y = 0.5 + Math.sin(this._rearingTimer * 4) * 0.4;
              if (this._rearingTimer > 0.8) {
                this._rearingPhase = 2;
                this._rearingTimer = 0;
              }
            } else if (this._rearingPhase === 2) {
              // Attack lunge
              vx = (dx / dist) * this.speed * 3.0;
              vz = (dz / dist) * this.speed * 3.0;
              if (this._rearingTimer > 0.4) {
                this._rearingPhase = 0;
                this._rearingTimer = 0;
                this.mesh.position.y = 0.5;
              }
            }
          } else if (behavior === 'sweep') {
            // Sweeping Swarm: flies rapidly in wide arcs across the map
            if (!this._sweepDir) this._sweepDir = (Math.random() > 0.5) ? 1 : -1;
            if (!this._sweepTimer) this._sweepTimer = 0;
            this._sweepTimer += dt;
            // Sweep side to side with a sinusoidal path
            const sweepSpeed = this.speed * 2.5;
            const perpX = -dz / (dist || 1);
            const perpZ =  dx / (dist || 1);
            vx = (dx / dist) * sweepSpeed * 0.3 + perpX * Math.sin(this._sweepTimer * 2) * sweepSpeed;
            vz = (dz / dist) * sweepSpeed * 0.3 + perpZ * Math.sin(this._sweepTimer * 2) * sweepSpeed;
            // Reverse direction occasionally
            if (this._sweepTimer > 2.5 + Math.random() * 1.5) {
              this._sweepDir *= -1;
              this._sweepTimer = 0;
            }
          }
          
          // Flying height behavior
          if (this.type === 5 || this.type === 14 || this.type === 16) {
            const wavePhase = gameTime * 5 + this.wobbleOffset;
            const wave = Math.sin(wavePhase) * 0.08;
            vx += wave * (dz/(dist||1));
            vz -= wave * (dx/(dist||1));
            const baseHeight = this._aiState === 'dive' ? 0.8 : (this.type === 16 ? 1.5 : 2);
            this.mesh.position.y = baseHeight + Math.sin(gameTime * 3 + this.wobbleOffset) * 0.5;
          }
          
          this.mesh.position.x += vx;
          this.mesh.position.z += vz;
          this.mesh.lookAt(targetPos);
          } // end else (!isFrozen) movement block
        }

        // Collision with target
        if (windmillQuest.active && windmillQuest.windmill && dist < 3.0) {
          // Attack windmill with cooldown
          const now = Date.now();
          if (now - this.lastAttackTime > this.attackCooldown) {
            windmillQuest.windmill.userData.hp -= this.damage;
            updateWindmillQuestUI();
            this.lastAttackTime = now;
            playSound('hit');
          }
          // Knockback
          this.mesh.position.x -= (dx / dist) * 2;
          this.mesh.position.z -= (dz / dist) * 2;
          
          if (windmillQuest.windmill.userData.hp <= 0) {
            failWindmillQuest();
          }
        } else if (dist < 1.0 && this.type !== 4) { // Ranged enemies don't melee attack
          // Attack player with cooldown to prevent instant death
          const now = Date.now();
          if (now - this.lastAttackTime > this.attackCooldown) {
            player.takeDamage(this.damage);
            this.lastAttackTime = now;
            
            // Thorns damage - reflect damage back to enemy if still alive
            if (playerStats.thornsPercent > 0 && !this.isDead) {
              const thornsDamage = this.damage * playerStats.thornsPercent;
              this.takeDamage(thornsDamage, false);
              createDamageNumber(thornsDamage, this.mesh.position, false);
              spawnParticles(this.mesh.position, 0xFF6347, 8); // Tomato red thorns
            }
            
            // Slowing enemy slows player on hit
            if (this.type === 3) {
              playerStats.walkSpeed *= this.slowAmount;
              // Remove slow after duration
              setTimeout(() => {
                playerStats.walkSpeed /= this.slowAmount;
              }, this.slowDuration);
              // Visual effect for slow
              spawnParticles(player.mesh.position, 0x00FFFF, 10);
            }
          }
          
          // Knockback (always apply to prevent enemies from stacking)
          this.mesh.position.x -= (dx / dist) * 2;
          this.mesh.position.z -= (dz / dist) * 2;
        }

        // Squishy idle with more gravity-based wobble
        this.pulsePhase += dt * 6; // Slightly faster
        const squish = Math.sin(this.pulsePhase) * 0.08; // More pronounced from 0.05
        
        // MiniBoss glowing effect
        if (this.isMiniBoss) {
          const glowIntensity = 0.3 + Math.sin(this.pulsePhase * 2) * 0.2;
          this.mesh.material.emissiveIntensity = glowIntensity;
          // Larger breathing effect for mini-boss
          this.mesh.scale.set(1+squish*2, 1-squish*2, 1+squish*2);
        } else if (this.isFlyingBoss) {
          // Flying Boss — dramatic pulsing glow and slow rotation
          const fbGlow = 0.5 + Math.sin(this.pulsePhase * 1.5) * 0.3;
          this.mesh.material.emissiveIntensity = fbGlow;
          this.mesh.rotation.y += dt * 0.8; // Slow menacing spin
          this.mesh.scale.set(1.8 + squish, 1.8 + squish, 1.8 + squish);
        } else if (this.type === 0 || this.type === 3 || this.type === 6) {
           // Tank, Slowing, and Hard Tank breathe more dramatically
           this.mesh.scale.set(1+squish*1.5, 1-squish*1.5, 1+squish*1.5);
        } else {
           this.mesh.scale.set(1-squish, 1+squish*1.5, 1-squish);
        }
        
        // Blinking eyes animation
        if (this.leftEye && this.rightEye) {
          this.blinkTimer += dt;
          if (this.blinkTimer >= this.nextBlinkTime) {
            this.isBlinking = true;
            this.blinkTimer = 0;
            this.nextBlinkTime = 1.5 + Math.random() * 3.5;
          }
          if (this.isBlinking) {
            const bp = Math.min(1, this.blinkTimer / this.blinkDuration);
            const eyeScale = bp < 0.5 ? 1 - bp * 2 : (bp - 0.5) * 2;
            this.leftEye.scale.y = Math.max(0.05, eyeScale);
            this.rightEye.scale.y = Math.max(0.05, eyeScale);
            if (bp >= 1) {
              this.isBlinking = false;
              this.blinkTimer = 0;
              this.leftEye.scale.y = 1;
              this.rightEye.scale.y = 1;
            }
          }
        }
        
        // Update ground shadow position for flying enemies
        if (this.groundShadow) {
          this.groundShadow.position.x = this.mesh.position.x;
          this.groundShadow.position.z = this.mesh.position.z;
          // Shadow opacity scales with height
          this.groundShadow.material.opacity = Math.max(0.08, 0.25 - (this.mesh.position.y - 0.5) * 0.03);
        }
      }

      fireProjectile(targetPos) {
        // Create enemy projectile
        const projectile = {
          startPos: this.mesh.position.clone(),
          targetPos: targetPos.clone(),
          mesh: null,
          speed: this.projectileSpeed,
          damage: this.damage,
          lifetime: 100, // frames
          isEnemyProjectile: true
        };
        
        // Create visual
        const geo = new THREE.SphereGeometry(0.2, 8, 8);
        const mat = new THREE.MeshBasicMaterial({ color: 0xFF6347 });
        projectile.mesh = new THREE.Mesh(geo, mat);
        projectile.mesh.position.copy(this.mesh.position);
        projectile.mesh.position.y = 0.5;
        scene.add(projectile.mesh);
        
        // Direction
        const dx = targetPos.x - this.mesh.position.x;
        const dz = targetPos.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        projectile.direction = new THREE.Vector3(dx/dist, 0, dz/dist);
        
        // Add to projectiles array (will be updated in main loop)
        projectiles.push(projectile);
        
        playSound('shoot');
      }

      /**
       * Apply damage to the enemy
       * @param {number} amount - Damage amount
       * @param {boolean} isCrit - Whether this is a critical hit
       * @param {string} damageType - Type of damage: 'physical', 'fire', 'ice', 'lightning', 'shotgun', 'headshot', 'gun', 'doubleBarrel', 'drone'
       */
      takeDamage(amount, isCrit = false, damageType = 'physical') {
        // Track last damage type for death effects
        this.lastDamageType = damageType;
        
        // Phase 5: Hit impact particles (flesh/blood) on every hit - ENHANCED: Scale with HP remaining
        const hpRatio = this.hp / this.maxHp;
        const bloodParticleCount = Math.max(10, Math.floor((1 - hpRatio) * 28) + 8); // More blood as HP drops - increased intensity
        spawnParticles(this.mesh.position, 0x8B0000, Math.min(bloodParticleCount, 30)); // Blood particles scale with HP loss
        spawnParticles(this.mesh.position, 0x660000, Math.min(Math.floor(bloodParticleCount * 0.6), 14)); // Darker blood
        spawnParticles(this.mesh.position, 0xCC0000, Math.min(Math.floor(bloodParticleCount * 0.4), 10)); // Bright splatter
        // Spawn multiple ground blood decals for more brutal effect
        spawnBloodDecal(this.mesh.position);
        spawnBloodDecal(this.mesh.position); // Always at least 2 decals per hit
        spawnBloodDecal(this.mesh.position); // Extra decal for more violence
        if (hpRatio < 0.7) {
          spawnBloodDecal(this.mesh.position); // Start extra blood earlier
        }
        if (hpRatio < 0.5) {
          spawnBloodDecal(this.mesh.position); // Extra decal at half HP
          spawnBloodDecal(this.mesh.position); // Additional splatter
        }
        if (hpRatio < 0.25) {
          spawnBloodDecal(this.mesh.position); // Extra decal at low HP
          spawnBloodDecal(this.mesh.position); // Even more at critical HP
          spawnBloodDecal(this.mesh.position); // Enemy barely alive - covered in blood
        }
        
        // Progressive blood stain: blend enemy mesh color toward dark red as HP drops
        // This works on ALL enemy colors (including yellow/gold) by directly lerping the color
        if (this.mesh && this.mesh.material) {
          if (!this._originalColor) {
            this._originalColor = this.mesh.material.color.clone();
          }
          // Lerp factor: 0 at full HP → 0.85 near death (almost fully blood-covered)
          const bloodLerp = (1 - hpRatio) * 0.85;
          const bloodColor = new THREE.Color(0x8B0000);
          // Only update color if not frozen (freeze manages its own colour)
          if (!this.isFrozen) {
            this.mesh.material.color.copy(this._originalColor).lerp(bloodColor, bloodLerp);
          }
          // Also apply emissive for wet blood sheen
          if (!this.isFrozen && this.mesh.material.emissive !== undefined) {
            const bloodStainIntensity = (1 - hpRatio) * 0.4;
            this.mesh.material.emissive = new THREE.Color(0x6B0000);
            this.mesh.material.emissiveIntensity = bloodStainIntensity;
          }
        }
        
        // Throttle expensive new-mesh creation (blood stains, drips, holes) to at most
        // once every 120 ms to avoid creating dozens of objects during rapid drone fire.
        const nowHit = Date.now();
        const canSpawnMeshes = !this._lastHitMeshTime || (nowHit - this._lastHitMeshTime) > 120;
        if (canSpawnMeshes) {
          this._lastHitMeshTime = nowHit;

        // Add blood stain meshes directly on enemy body (visible on all colors)
        if (!this._bloodStains) this._bloodStains = [];
        const MAX_BODY_BLOOD_STAINS = 12;
        if (this._bloodStains.length < MAX_BODY_BLOOD_STAINS) {
          const stainCount = hpRatio < 0.25 ? 3 : (hpRatio < 0.5 ? 2 : 1);
          for (let s = 0; s < stainCount && this._bloodStains.length < MAX_BODY_BLOOD_STAINS; s++) {
            const stainSize = 0.08 + Math.random() * 0.15;
            const stain = new THREE.Mesh(
              new THREE.CircleGeometry(stainSize, 6),
              new THREE.MeshStandardMaterial({
                color: 0x5a0000,
                emissive: 0x1a0000,
                emissiveIntensity: 0.25,
                roughness: 0.22,
                metalness: 0.5,
                transparent: true,
                opacity: 0.82,
                side: THREE.DoubleSide,
                depthWrite: false
              })
            );
            // Place on enemy surface
            const theta = Math.random() * Math.PI * 2;
            const phi = Math.random() * Math.PI;
            const r = 0.49;
            stain.position.set(r * Math.sin(phi) * Math.cos(theta), r * Math.sin(phi) * Math.sin(theta), r * Math.cos(phi));
            stain.lookAt(stain.position.clone().multiplyScalar(2));
            this.mesh.add(stain);
            this._bloodStains.push(stain);
          }
        }
        
        // Blood drip: small drops fall from wounded enemy to ground (managed in main loop)
        // More blood drips from first shot onward, increasing with damage
        if (scene && bloodDrips.length < MAX_BLOOD_DRIPS) {
          const dripCount = hpRatio < 0.25 ? 6 : (hpRatio < 0.5 ? 4 : 3); // Blood from every hit
          for (let d = 0; d < dripCount && bloodDrips.length < MAX_BLOOD_DRIPS; d++) {
            const dripSize = 0.03 + Math.random() * 0.05;
            const drip = new THREE.Mesh(
              new THREE.SphereGeometry(dripSize, 4, 4),
              new THREE.MeshBasicMaterial({ color: 0x8B0000 })
            );
            drip.position.set(
              this.mesh.position.x + (Math.random() - 0.5) * 0.5,
              this.mesh.position.y + (Math.random() - 0.5) * 0.3,
              this.mesh.position.z + (Math.random() - 0.5) * 0.5
            );
            scene.add(drip);
            bloodDrips.push({ mesh: drip, velY: 0, life: 30 + Math.floor(Math.random() * 20) });
          }
        }
        
        // Bullet-hole decal that sticks to enemy surface (visible bloody wound)
        if (!this.bulletHoles) this.bulletHoles = [];
        const MAX_ENEMY_BULLET_HOLES = 12;
        if (this.bulletHoles.length < MAX_ENEMY_BULLET_HOLES) {
          // Reuse shared geometry; clone shared material for per-hole opacity control
          const holeDecal = new THREE.Mesh(bulletHoleGeo, bulletHoleMat.clone());
          // Place on enemy surface (random position on sphere surface)
          const theta = Math.random() * Math.PI * 2;
          const phi = Math.random() * Math.PI;
          const nx = Math.sin(phi) * Math.cos(theta);
          const ny = Math.sin(phi) * Math.sin(theta);
          const nz = Math.cos(phi);
          holeDecal.position.set(nx * 0.54, ny * 0.54, nz * 0.54);
          // Face outward from center
          holeDecal.lookAt(new THREE.Vector3(nx * 2, ny * 2, nz * 2));
          this.mesh.add(holeDecal);
          this.bulletHoles.push(holeDecal);
        }
        } // end canSpawnMeshes throttle
        
        // Airborne blood splatter - throttled alongside other mesh creation
        if (canSpawnMeshes) {
        const burstCount = isCrit ? 5 : 3; // More airborne blood per shot
        for (let b = 0; b < burstCount && bloodDrips.length < MAX_BLOOD_DRIPS; b++) {
          const bSize = 0.03 + Math.random() * 0.05;
          const p = new THREE.Mesh(
            new THREE.SphereGeometry(bSize, 4, 4),
            new THREE.MeshBasicMaterial({ color: 0xAA0000 })
          );
          p.position.set(
            this.mesh.position.x + (Math.random() - 0.5) * 0.4,
            this.mesh.position.y + 0.1,
            this.mesh.position.z + (Math.random() - 0.5) * 0.4
          );
          scene.add(p);
          bloodDrips.push({
            mesh: p,
            velX: (Math.random() - 0.5) * 0.08,
            velZ: (Math.random() - 0.5) * 0.08,
            velY: 0.12 + Math.random() * 0.22, // initial upward burst
            life: 35 + Math.floor(Math.random() * 15)
          });
        }
        } // end airborne blood throttle
        
        // Phase 3: Apply armor reduction for MiniBoss/FlyingBoss — delegated to GameCombat
        let finalAmount = amount;
        if (this.armor > 0) {
          // Apply player's armor penetration: reduces effective enemy armor
          const effectiveArmor = this.armor * (1 - (playerStats.armorPenetration || 0));
          finalAmount = calculateEnemyArmorReduction(amount, effectiveArmor);
          // Show armor reduction effect
          if (this.isMiniBoss || this.isFlyingBoss) {
            createFloatingText(`-${Math.floor(amount * effectiveArmor)}`, this.mesh.position, '#FFD700');
          }
        }

        // Apply elemental resistance/vulnerability based on damage type
        if (damageType && this.elementalResistance) {
          const resistKey = damageType === 'gun' || damageType === 'sword' || damageType === 'drone' || damageType === 'shotgun' || damageType === 'doubleBarrel'
            ? 'physical' : damageType;
          const resist = this.elementalResistance[resistKey] || 0;
          if (resist !== 0) finalAmount *= (1 - resist);
        }

        // Frozen enemies take double damage after armor — freeze bonus applies on top of armor
        if (this.isFrozen) finalAmount *= 2;

        // Execute bonus: extra damage vs enemies below 30% HP
        if (playerStats.executeDamage > 0 && this.hp / this.maxHp < 0.30) {
          finalAmount *= (1 + playerStats.executeDamage);
        }
        
        const oldHp = this.hp;
        this.hp -= finalAmount;
        createDamageNumber(Math.floor(finalAmount), this.mesh.position, isCrit);
        
        const hpPercent = this.hp / this.maxHp;
        const oldHpPercent = oldHp / this.maxHp;
        
        // 75% HP: Blood spots, darken color by 20%
        if (oldHpPercent >= 0.75 && hpPercent < 0.75 && !this.stage1Damage) {
          this.stage1Damage = true;
          
          // Darken color
          const currentColor = this.mesh.material.color;
          currentColor.r *= 0.8;
          currentColor.g *= 0.8;
          currentColor.b *= 0.8;
          
          // Blood spots (small red particles)
          spawnParticles(this.mesh.position, 0x8B0000, 10);
          playSound('hit');
        }
        
        // 50% HP: Add flesh/hole meshes
        if (oldHpPercent >= 0.5 && hpPercent < 0.5 && !this.stage2Damage) {
          this.stage2Damage = true;
          
          // Add visible wounds/holes
          for(let i=0; i<3; i++) {
            const holeGeo = new THREE.SphereGeometry(0.1, 6, 6);
            const holeMat = new THREE.MeshBasicMaterial({ color: 0x220000 }); // Dark red
            const hole = new THREE.Mesh(holeGeo, holeMat);
            hole.position.set(
              (Math.random() - 0.5) * 0.5,
              (Math.random() - 0.5) * 0.5,
              (Math.random() - 0.5) * 0.5
            );
            this.mesh.add(hole);
          }
          
          spawnParticles(this.mesh.position, 0x8B0000, 8); // Reduced for performance
          playSound('hit');
        }
        
        // 25% HP: Heavy blood spray, walkSpeed *= 0.6
        if (oldHpPercent >= 0.25 && hpPercent < 0.25 && !this.stage3Damage) {
          this.stage3Damage = true;
          
          // Reduce speed
          this.speed *= 0.6;
          
          // Massive blood spray instead of big limb pieces
          const enemyColor = this.mesh.material.color.getHex();
          spawnParticles(this.mesh.position, 0x8B0000, 20);
          spawnParticles(this.mesh.position, 0xCC0000, 15);
          spawnParticles(this.mesh.position, 0x660000, 10);
          spawnParticles(this.mesh.position, enemyColor, 6);
          
          // Blood spray decals around
          for (let i = 0; i < 6; i++) {
            spawnBloodDecal(this.mesh.position);
          }
          
          // Airborne blood bursts
          for (let b = 0; b < 5 && bloodDrips.length < MAX_BLOOD_DRIPS; b++) {
            const p = new THREE.Mesh(
              new THREE.SphereGeometry(0.03 + Math.random() * 0.04, 4, 4),
              new THREE.MeshBasicMaterial({ color: 0xAA0000 })
            );
            p.position.set(
              this.mesh.position.x + (Math.random() - 0.5) * 0.5,
              this.mesh.position.y + 0.2,
              this.mesh.position.z + (Math.random() - 0.5) * 0.5
            );
            scene.add(p);
            bloodDrips.push({
              mesh: p,
              velY: 0.18 + Math.random() * 0.25,
              life: 35 + Math.floor(Math.random() * 15)
            });
          }
          
          playSound('hit');
        }
        
        // Destruction effect at 20% HP threshold — covered in blood, near death
        if (oldHpPercent >= 0.2 && hpPercent < 0.2 && !this.isDamaged) {
          this.isDamaged = true;
          
          // Visually damage the enemy - make smaller
          const damagePercent = 0.35 + Math.random() * 0.15; // 35-50%
          const newScale = 1 - damagePercent;
          this.mesh.scale.multiplyScalar(newScale);
          
          // Heavy blood spray instead of big broken pieces
          spawnParticles(this.mesh.position, 0x8B0000, 18);
          spawnParticles(this.mesh.position, 0xCC0000, 12);
          spawnParticles(this.mesh.position, 0x440000, 8);
          
          // Blood pools around enemy
          for (let i = 0; i < 8; i++) {
            spawnBloodDecal(this.mesh.position);
          }
          
          playSound('hit');
        }
        
        // Enhanced splash particles using enemy's own color
        const enemyColor = this.mesh.material.color.getHex();
        const particleCount = isCrit ? 8 : 3;
        spawnParticles(this.mesh.position, enemyColor, particleCount);
        
        // Blood spray on every hit — more blood as enemy takes more damage
        const bloodIntensity = Math.ceil((1 - hpPercent) * 6) + 1;
        spawnParticles(this.mesh.position, 0x8B0000, Math.min(bloodIntensity, 6));
        if (hpPercent < 0.6) {
          spawnBloodDecal(this.mesh.position);
        }
        if (hpPercent < 0.3) {
          spawnBloodDecal(this.mesh.position);
          spawnParticles(this.mesh.position, 0xCC0000, 3);
        }
        
        // Additional impact particles
        if (isCrit) {
          spawnParticles(this.mesh.position, enemyColor, 5);
          spawnParticles(this.mesh.position, 0xFFFFFF, 3);
          spawnBloodDecal(this.mesh.position);
        }
        
        // Enhanced squishy deformation on hit — only apply/schedule if not already squishing
        if (!this._squishTimer) {
          const squishScale = isCrit ? 0.7 : 0.85;
          this.mesh.scale.set(squishScale, 1.3, squishScale);
          this._squishTimer = setTimeout(() => {
            if (this.mesh) this.mesh.scale.set(1, 1, 1);
            this._squishTimer = null;
          }, 100);
        }

        if (this.hp <= 0) {
          this.die();
        }
      }

      die() {
        this.isDead = true;
        // Clear freeze state so no further update logic applies to dead enemy
        this.isFrozen = false;
        // Cancel pending squish timeout to prevent callback on dead enemy
        if (this._squishTimer) {
          clearTimeout(this._squishTimer);
          this._squishTimer = null;
        }
        
        // Clean up ground shadow
        if (this.groundShadow) {
          scene.remove(this.groundShadow);
          this.groundShadow.geometry.dispose();
          this.groundShadow.material.dispose();
          this.groundShadow = null;
        }
        
        // Clone position NOW before any mesh removal or disposal to prevent
        // race condition where position becomes undefined after scene.remove/dispose
        if (!this.mesh) return;
        const deathPos = this.mesh.position.clone();
        
        // Track kills for active quests
        if (montanaQuest.active) {
          montanaQuest.kills++;
          updateMontanaQuestUI();
        }
        if (eiffelQuest.active) {
          eiffelQuest.kills++;
          updateEiffelQuestUI();
        }
        
        // Determine death effect based on damage type and health when dying
        const damageType = this.lastDamageType || 'physical';
        const enemyColor = this.mesh.material.color.getHex();
        // Detect yellow/gold enemy for special spin death (type 7=HardFast gold, type 10=MiniBoss gold)
        const isYellowEnemy = (this.type === 7 || this.type === 10);
        
        // Trigger kill cam effect for varied visual feedback
        triggerKillCam(this.mesh.position, this.isMiniBoss, damageType);
        
        // Special death effects based on damage type
        if (isYellowEnemy && damageType !== 'ice' && damageType !== 'fire' && damageType !== 'headshot') {
          // Yellow enemies: 180-degree spin death with continuous neck blood arc
          this.dieBySpinDeath(enemyColor);
        } else if (damageType === 'fire') {
          // Fire death: Char and ash
          this.dieByFire(enemyColor);
        } else if (damageType === 'ice') {
          // Ice death: Shatter into ice shards
          this.dieByIce(enemyColor);
        } else if (damageType === 'lightning') {
          // Lightning death: Blackened and smoke
          this.dieByLightning(enemyColor);
        } else if (damageType === 'shotgun' || damageType === 'doubleBarrel') {
          // Shotgun / double barrel / homing missile death: Massive gibs explosion
          this.dieByShotgun(enemyColor);
        } else if (damageType === 'headshot') {
          // Headshot: Specific head explosion
          this.dieByHeadshot(enemyColor);
        } else if (damageType === 'drone') {
          // Drone death: riddled with holes, blood-soaked standard death
          this.dieStandard(enemyColor);
        } else {
          // Standard death (bullet/physical/gun)
          this.dieStandard(enemyColor);
        }
        
        // Screen flash on kill (dopamine boost) - stronger flash for mini-boss
        const flash = document.createElement('div');
        flash.style.position = 'fixed';
        flash.style.top = '0';
        flash.style.left = '0';
        flash.style.width = '100%';
        flash.style.height = '100%';
        flash.style.background = this.isFlyingBoss ? 'rgba(139, 0, 139, 0.4)' : (this.isMiniBoss ? 'rgba(255, 215, 0, 0.3)' : 'rgba(255, 255, 255, 0.2)');
        flash.style.pointerEvents = 'none';
        flash.style.zIndex = '500';
        document.body.appendChild(flash);
        setTimeout(() => flash.remove(), (this.isMiniBoss || this.isFlyingBoss) ? 100 : 50);
        
        // Blood spray on death - massive brutal blood explosion
        spawnParticles(this.mesh.position, 0x8B0000, 14); // Blood spray
        spawnParticles(this.mesh.position, 0xCC0000, 10); // Bright red splatter
        spawnParticles(this.mesh.position, 0x660000, 8); // Dark blood mist
        spawnParticles(this.mesh.position, 0x440000, 6); // Extra dark blood chunks
        // Advanced blood particle burst on death — heavy spray up in air
        if (window.BloodSystem) {
          window.BloodSystem.emitBurst(deathPos, this.isMiniBoss ? 900 : 500, { spreadXZ: 2.2, spreadY: 1.8, minSize: 0.03, maxSize: 0.16, minLife: 55, maxLife: 120 });
          // Extra micro-fountain mist that rains down as tiny droplets
          window.BloodSystem.emitBurst(deathPos, this.isMiniBoss ? 420 : 240, { spreadXZ: 1.8, spreadY: 1.2, minSize: 0.015, maxSize: 0.06, minLife: 60, maxLife: 110 });
          // Pulsating blood fountain after death — simulates heart still pumping
          window.BloodSystem.emitPulse(deathPos, { pulses: this.isMiniBoss ? 10 : 6, perPulse: this.isMiniBoss ? 750 : 420, interval: 160, spreadXZ: 2.2, minSize: 0.02, maxSize: 0.1, minLife: 55, maxLife: 110 });
        }
        // Airborne blood spray burst — sprays high in air, rains down tiny droplets
        for (let sb = 0; sb < 14 && bloodDrips.length < MAX_BLOOD_DRIPS; sb++) {
          const spraySize = 0.02 + Math.random() * 0.06;
          const spray = new THREE.Mesh(
            new THREE.SphereGeometry(spraySize, 4, 4),
            new THREE.MeshBasicMaterial({ color: [0xAA0000, 0x8B0000, 0x660000, 0xCC0000][sb % 4] })
          );
          spray.position.copy(deathPos);
          spray.position.y += 0.3;
          scene.add(spray);
          bloodDrips.push({
            mesh: spray,
            velX: (Math.random() - 0.5) * 0.45,
            velZ: (Math.random() - 0.5) * 0.45,
            velY: 0.35 + Math.random() * 0.55,
            life: 55 + Math.floor(Math.random() * 30)
          });
        }
        // Dynamic blood pools: more pools with bigger sizes
        const airBloodCount = this.isMiniBoss ? 24 : 16;
        for (let ab = 0; ab < airBloodCount; ab++) {
          if (managedAnimations.length >= MAX_MANAGED_ANIMATIONS) break;
          const landX = deathPos.x + (Math.random() - 0.5) * 5;
          const landZ = deathPos.z + (Math.random() - 0.5) * 5;
          // Dynamic sizing: small drips (0.05), drops (0.15), pools (0.4+)
          const sizeRoll = Math.random();
          const r = sizeRoll < 0.3 ? (0.04 + Math.random() * 0.1) :  // 30% tiny drips
                    sizeRoll < 0.55 ? (0.12 + Math.random() * 0.2) :  // 25% drops
                    sizeRoll < 0.8 ? (0.25 + Math.random() * 0.3) :   // 25% medium pools
                                     (0.4 + Math.random() * 0.4);     // 20% big pools
          const poolGeo = new THREE.CircleGeometry(r, r > 0.2 ? 12 : 6);
          const poolMat = new THREE.MeshStandardMaterial({ 
            color: sizeRoll < 0.5 ? 0x8B0000 : 0x6B0000, 
            transparent: true, opacity: 0,
            roughness: 0.15, metalness: 0.5
          });
          const pool = new THREE.Mesh(poolGeo, poolMat);
          pool.rotation.x = -Math.PI / 2;
          pool.position.set(landX, 0.015, landZ);
          scene.add(pool);
          const delayFrames = 3 + Math.floor(Math.random() * 15);
          const maxOpacity = 0.5 + Math.random() * 0.35;
          const WAIT_FRAMES = 480;
          const FADE_FRAMES = 60;
          let abTimer = 0;
          managedAnimations.push({
            update(_dt) {
              abTimer++;
              if (abTimer === delayFrames) poolMat.opacity = maxOpacity;
              if (abTimer > WAIT_FRAMES) {
                poolMat.opacity = Math.max(0, maxOpacity * (1 - (abTimer - WAIT_FRAMES) / FADE_FRAMES));
              }
              if (abTimer >= WAIT_FRAMES + FADE_FRAMES) {
                if (pool.parent) scene.remove(pool);
                poolGeo.dispose();
                poolMat.dispose();
                return false;
              }
              return true;
            },
            cleanup() {
              if (pool.parent) scene.remove(pool);
              poolGeo.dispose();
              poolMat.dispose();
            }
          });
        }
        for (let db = 0; db < (this.isMiniBoss ? 18 : 12); db++) {
          spawnBloodDecal(this.mesh.position);
        }
        
        // Enemy death animation: fall lifeless to ground, then spawn XP star separately
        const dyingMesh = this.mesh;
        const _bulletHoles = this.bulletHoles;
        const _bloodStains = this._bloodStains;
        const _leftEye = this.leftEye;
        const _rightEye = this.rightEye;
        this.bulletHoles = [];
        this._bloodStains = [];
        this.leftEye = null;
        this.rightEye = null;
        
        // XP scaling by enemy type - stronger enemies give more XP
        let expMultiplier = 1;
        if (this.isFlyingBoss) {
          expMultiplier = 5;
        } else if (this.isMiniBoss) {
          expMultiplier = 3;
        } else if (this.type === 9) { // Elite
          expMultiplier = 2;
        } else if (this.type >= 6 && this.type <= 8) { // Hard variants
          expMultiplier = 2;
        } else if (this.type === 0 || this.type === 3 || this.type === 5) { // Tank, Slowing, Flying
          expMultiplier = 1;
        } else if (this.type === 13) { // Bug Slow (tanky)
          expMultiplier = 2;
        } else {
          expMultiplier = 1; // Fast, Balanced, Ranged, Bug Fast, Bug Ranged
        }
        const wasFlying = this.isFlying;
        
        // XP star pops out immediately on death, flying slightly away from the body
        // so it is visible during the death animation and can be collected right away.
        const xpPopAngle = Math.random() * Math.PI * 2;
        const xpPopDist = 0.8 + Math.random() * 0.6; // 0.8–1.4 units away
        for (let i = 0; i < expMultiplier; i++) {
          const spread = i * (Math.PI * 2 / Math.max(expMultiplier, 1));
          const angle = xpPopAngle + spread;
          spawnExp(deathPos.x + Math.cos(angle) * xpPopDist, deathPos.z + Math.sin(angle) * xpPopDist);
        }
        
        // Dynamic death animation styles - brutal varied ragdoll falls
        const deathStyle = Math.floor(Math.random() * 6); // 0-5 different death types
        const fallSignX = (Math.random() < 0.5) ? 1 : -1;
        const fallSignZ = (Math.random() < 0.5) ? 1 : -1;
        const spinDir = (Math.random() < 0.5) ? 1 : -1;
        
        // Fall down animation: enemy falls dynamically, lies on ground, explodes into blood
        const FALL_FRAMES = wasFlying ? 50 : 35;
        const LINGER_FRAMES = 50; // Lie on ground lifeless before blood explosion
        const EXPLODE_FRAMES = 15; // Blood explosion phase
        const FADE_FRAMES = 15; // Fade out remains
        let fallFrame = 0;
        const startY = dyingMesh.position.y;
        const startScaleY = dyingMesh.scale.y;
        
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            fallFrame++;
            
            if (fallFrame <= FALL_FRAMES) {
              const progress = Math.min(fallFrame / FALL_FRAMES, 1);
              const eased = 1 - Math.pow(1 - progress, 3); // Ease-out cubic for natural fall
              
              if (deathStyle === 0) {
                // Face-plant: fall forward onto stomach
                dyingMesh.rotation.x = fallSignX * eased * (Math.PI / 2);
                dyingMesh.rotation.z = fallSignZ * eased * 0.15; // slight twist
                dyingMesh.position.y = startY * (1 - eased);
                dyingMesh.scale.y = startScaleY * (1 - eased * 0.6);
              } else if (deathStyle === 1) {
                // Side fall: topple sideways
                dyingMesh.rotation.z = fallSignZ * eased * (Math.PI / 2);
                dyingMesh.rotation.x = fallSignX * eased * 0.2;
                dyingMesh.position.y = startY * (1 - eased);
                dyingMesh.scale.y = startScaleY * (1 - eased * 0.4);
              } else if (deathStyle === 2) {
                // Back fall: fall backward
                dyingMesh.rotation.x = fallSignX * -1 * eased * (Math.PI / 2.2);
                dyingMesh.rotation.z = fallSignZ * eased * 0.1;
                dyingMesh.position.y = startY * (1 - eased);
                dyingMesh.scale.y = startScaleY * (1 - eased * 0.5);
              } else if (deathStyle === 3) {
                // Knees first: two-stage collapse - knees buckle then body falls
                if (progress < 0.4) {
                  const kneePhase = progress / 0.4;
                  dyingMesh.scale.y = startScaleY * (1 - kneePhase * 0.5); // compress down
                  dyingMesh.position.y = startY * (1 - kneePhase * 0.6);
                } else {
                  const bodyPhase = (progress - 0.4) / 0.6;
                  const bodyEased = 1 - Math.pow(1 - bodyPhase, 2);
                  dyingMesh.scale.y = startScaleY * 0.5 * (1 - bodyEased * 0.6);
                  dyingMesh.rotation.x = fallSignX * bodyEased * (Math.PI / 2);
                  dyingMesh.rotation.z = fallSignZ * bodyEased * 0.3;
                  dyingMesh.position.y = startY * 0.4 * (1 - bodyEased);
                }
              } else if (deathStyle === 4) {
                // Spin and collapse: enemy spins as they fall
                dyingMesh.rotation.y = spinDir * eased * Math.PI * 1.5;
                dyingMesh.rotation.x = fallSignX * eased * (Math.PI / 2.5);
                dyingMesh.position.y = startY * (1 - eased);
                dyingMesh.scale.y = startScaleY * (1 - eased * 0.55);
              } else {
                // Dramatic crumple: compress then topple
                if (progress < 0.3) {
                  const crumple = progress / 0.3;
                  dyingMesh.scale.y = startScaleY * (1 - crumple * 0.4);
                  dyingMesh.scale.x = startScaleY * (1 + crumple * 0.2);
                  dyingMesh.position.y = startY * (1 - crumple * 0.3);
                } else {
                  const topple = (progress - 0.3) / 0.7;
                  const toppleEased = 1 - Math.pow(1 - topple, 2);
                  dyingMesh.rotation.x = fallSignX * toppleEased * (Math.PI / 2);
                  dyingMesh.rotation.z = fallSignZ * toppleEased * (Math.PI / 4);
                  dyingMesh.scale.y = startScaleY * 0.6 * (1 - toppleEased * 0.4);
                  dyingMesh.position.y = startY * 0.7 * (1 - toppleEased);
                }
              }
              // Flying enemies: also tumble during fall
              if (wasFlying) {
                dyingMesh.rotation.y += 0.1;
                dyingMesh.position.y = Math.max(0, startY * (1 - eased));
              }
              // Bounce impact when hitting ground near end of fall
              if (progress > 0.85 && progress < 0.95) {
                spawnParticles(deathPos, 0x8B0000, 3);
                spawnBloodDecal(deathPos);
              }
            } else if (fallFrame <= FALL_FRAMES + LINGER_FRAMES) {
              // Phase 2: Lie on ground lifeless - slight settling
              const lingerProgress = (fallFrame - FALL_FRAMES) / LINGER_FRAMES;
              if (lingerProgress < 0.1) {
                // Small bounce/settle on impact
                const bounce = Math.sin(lingerProgress * Math.PI * 10) * 0.02 * (1 - lingerProgress * 10);
                dyingMesh.position.y = bounce;
              }
            } else if (fallFrame <= FALL_FRAMES + LINGER_FRAMES + EXPLODE_FRAMES) {
              // Phase 3: Blood explosion - body bursts into blood piles
              const explodeProgress = (fallFrame - FALL_FRAMES - LINGER_FRAMES) / EXPLODE_FRAMES;
              if (explodeProgress < 0.3) {
                // Burst blood spray
                spawnParticles(deathPos, 0x8B0000, 4);
                spawnParticles(deathPos, 0x660000, 3);
                spawnBloodDecal(deathPos);
                spawnBloodDecal(deathPos);
              }
              // Flatten and expand as body breaks apart
              if (dyingMesh.material) {
                dyingMesh.material.transparent = true;
                dyingMesh.material.opacity = 1 - explodeProgress * 0.7;
              }
              dyingMesh.scale.y *= 0.92;
              dyingMesh.scale.x *= 1.03;
              dyingMesh.scale.z *= 1.03;
            } else if (fallFrame <= FALL_FRAMES + LINGER_FRAMES + EXPLODE_FRAMES + FADE_FRAMES) {
              // Phase 4: Fade out remains
              const fadeProgress = (fallFrame - FALL_FRAMES - LINGER_FRAMES - EXPLODE_FRAMES) / FADE_FRAMES;
              if (dyingMesh.material) {
                dyingMesh.material.transparent = true;
                dyingMesh.material.opacity = Math.max(0, 0.3 * (1 - fadeProgress));
              }
            } else {
              // Phase 5: Remove corpse (XP star already spawned at death start)
              scene.remove(dyingMesh);
              if (dyingMesh.geometry) dyingMesh.geometry.dispose();
              if (dyingMesh.material) dyingMesh.material.dispose();
              if (_bulletHoles) _bulletHoles.forEach(h => { if (h.material) h.material.dispose(); });
              if (_bloodStains) _bloodStains.forEach(s => { if (s.geometry) s.geometry.dispose(); if (s.material) s.material.dispose(); });
              if (_leftEye) _leftEye.material.dispose();
              if (_rightEye) _rightEye.material.dispose();
              return false;
            }
            return true;
          }});
        } else {
          // Fallback: no animation slot available, remove immediately
          scene.remove(dyingMesh);
          setTimeout(() => {
            if (dyingMesh.geometry) dyingMesh.geometry.dispose();
            if (dyingMesh.material) dyingMesh.material.dispose();
            if (_bulletHoles) _bulletHoles.forEach(h => { if (h.material) h.material.dispose(); });
            if (_bloodStains) _bloodStains.forEach(s => { if (s.geometry) s.geometry.dispose(); if (s.material) s.material.dispose(); });
            if (_leftEye) _leftEye.material.dispose();
            if (_rightEye) _rightEye.material.dispose();
          }, 100);
          // XP already spawned above; nothing extra needed in this fallback
        }
        
        // PR #117: Drop GOLD - Reduced drop rate (chest-like rarity), bigger amounts
        let goldAmount = 0;
        let dropChance = 0;
        
        if (this.isFlyingBoss) {
          // Flying Boss: guaranteed large gold reward
          goldAmount = 100 + Math.floor(Math.random() * 101); // 100-200 gold
          dropChance = 1.0;
        } else if (this.isMiniBoss) {
          // MiniBoss: guaranteed 50-100 gold (increased from 30-60)
          goldAmount = 50 + Math.floor(Math.random() * 51);
          dropChance = 1.0; // 100% for mini-boss
        } else {
          // Regular enemies: MUCH lower drop rate (5-10% instead of 100%)
          dropChance = 0.05 + Math.random() * 0.05; // 5-10% chance
          
          if (Math.random() < dropChance) {
            // When they DO drop, drop MUCH more gold
            if (this.type === 0) { // Tank
              goldAmount = 8 + Math.floor(Math.random() * 5); // 8-12 gold (was 2-3)
            } else if (this.type === 1) { // Fast
              goldAmount = 5 + Math.floor(Math.random() * 3); // 5-7 gold (was 1)
            } else if (this.type === 2) { // Balanced
              goldAmount = 6 + Math.floor(Math.random() * 4); // 6-9 gold (was 1-2)
            } else if (this.type === 3) { // Slowing
              goldAmount = 8 + Math.floor(Math.random() * 5); // 8-12 gold (was 2-3)
            } else if (this.type === 4) { // Ranged
              goldAmount = 6 + Math.floor(Math.random() * 4); // 6-9 gold (was 1-2)
            } else if (this.type === 5) { // Flying
              goldAmount = 8 + Math.floor(Math.random() * 5); // 8-12 gold (was 2-3)
            } else if (this.type === 6) { // Hard Tank
              goldAmount = 15 + Math.floor(Math.random() * 11); // 15-25 gold (was 3-5)
            } else if (this.type === 7) { // Hard Fast
              goldAmount = 10 + Math.floor(Math.random() * 11); // 10-20 gold (was 2-4)
            } else if (this.type === 8) { // Hard Balanced
              goldAmount = 15 + Math.floor(Math.random() * 11); // 15-25 gold (was 3-5)
            } else if (this.type === 9) { // Elite
              goldAmount = 25 + Math.floor(Math.random() * 26); // 25-50 gold (was 5-8)
            } else if (this.type === 12) { // Bug Ranged
              goldAmount = 8 + Math.floor(Math.random() * 7);  // 8-14 gold
            } else if (this.type === 13) { // Bug Slow
              goldAmount = 12 + Math.floor(Math.random() * 9); // 12-20 gold
            } else if (this.type === 14) { // Bug Fast
              goldAmount = 5 + Math.floor(Math.random() * 5);  // 5-9 gold
            } else if (this.type === 15) { // Daddy Longlegs — easy early enemy, small reward
              goldAmount = 3 + Math.floor(Math.random() * 4);  // 3-6 gold
            } else if (this.type === 16) { // Sweeping Swarm — minimal reward
              goldAmount = 2 + Math.floor(Math.random() * 3);  // 2-4 gold
            } else {
              goldAmount = 5 + Math.floor(Math.random() * 6); // 5-10 gold (was 1-2)
            }
          }
        }
        
        // Only spawn gold if amount > 0
        if (goldAmount > 0) {
          spawnGold(deathPos.x, deathPos.z, goldAmount);
        }
        
        // Phase 1: Gear drop system - enemies have a chance to drop gear
        let gearDropChance = 0;
        if (this.isFlyingBoss) {
          gearDropChance = 0.75; // 75% for flying boss
        } else if (this.isMiniBoss) {
          gearDropChance = 0.5; // 50% for mini-boss
        } else {
          // Regular enemies: 3-8% chance (scales with enemy type 0-9)
          // Enemy types 0-9 add 0-0.05% additional chance
          gearDropChance = 0.03 + Math.min(this.type * 0.005, 0.05); // 3-8% cap
        }
        
        if (Math.random() < gearDropChance) {
          const newGear = generateRandomGear();
          saveData.inventory.push(newGear);
          saveSaveData();
          
          // Show notification
          const rarityColors = {
            common: '#AAAAAA',
            uncommon: '#00FF00',
            rare: '#5DADE2',
            epic: '#9B59B6',
            legendary: '#F39C12'
          };
          createFloatingText(`+${newGear.name}`, deathPos, rarityColors[newGear.rarity] || '#FFFFFF');
          playSound('coin');

          // Notify SSB with gear drop rarity
          if (window.pushSuperStatEvent) {
            const gr = newGear.rarity || 'common';
            window.pushSuperStatEvent(`📦 ${newGear.name}`, gr, '📦', 'success');
          }
          
          console.log('[Phase 1 Gear Drop]', newGear.name, '-', newGear.rarity);
          
          // Quest progression: lake chest quest (triggered by first item collection)
          if (saveData.storyQuests.currentQuest === 'discoverLakeChest' && saveData.inventory.length === 1) {
            // This is the first item - treat it as finding the lake chest
            setTimeout(() => {
              progressQuest('discoverLakeChest', true);
            }, 2000); // Small delay to let player see the item notification
          }
        }
        
        playerStats.kills++;

        // Heal on kill (Bloodlust skill and similar)
        if (playerStats.healOnKill > 0) {
          playerStats.hp = Math.min(playerStats.maxHp, playerStats.hp + playerStats.healOnKill);
          updateHUD();
        }

        // Tutorial Quest: Track kills this run
        if (saveData.tutorialQuests) {
          saveData.tutorialQuests.killsThisRun = playerStats.kills;
          updateQuestTracker();
          
          // Quest 1: Kill 3 enemies
          const currentQuest = getCurrentQuest();
          if (currentQuest && currentQuest.id === 'quest1_kill3' && playerStats.kills >= 3) {
            progressTutorialQuest('quest1_kill3', true);
            // Guard: only set pending notification if quest1 is now in readyToClaim
            if (saveData.tutorialQuests.readyToClaim.includes('quest1_kill3')) {
              saveData.tutorialQuests.pendingMissionNotification = 'quest1_kill3';
            }
          }
          // Quest kill tracking — notify mid-run when objective reached
          if (currentQuest && currentQuest.id === 'quest8_kill10' && playerStats.kills >= 10 &&
              !saveData.tutorialQuests.readyToClaim.includes('quest8_kill10')) {
            showStatChange('⚔️ 10 Kills! Return to camp after this run!');
          }
          // Kill 15 enemies
          if (currentQuest && currentQuest.id === 'quest10_kill15' && playerStats.kills >= 15 &&
              !saveData.tutorialQuests.readyToClaim.includes('quest10_kill15')) {
            showStatChange('⚔️ 15 Kills! Return to camp to claim your reward!');
          }
          // Kill 25 enemies
          if (currentQuest && currentQuest.id === 'quest14_kill25' && playerStats.kills >= 25 &&
              !saveData.tutorialQuests.readyToClaim.includes('quest14_kill25')) {
            progressTutorialQuest('quest14_kill25', true);
            showStatChange('⚔️ 25 Kills! Return to camp to claim your reward!');
          }
        }
        
        // Track side challenge progress
        if (saveData.sideChallenges.kill10Enemies && !saveData.sideChallenges.kill10Enemies.completed) {
          saveData.sideChallenges.kill10Enemies.progress++;
          if (saveData.sideChallenges.kill10Enemies.progress >= saveData.sideChallenges.kill10Enemies.target) {
            saveData.sideChallenges.kill10Enemies.completed = true;
            // Award gold before saving to prevent loss on crash
            saveData.gold += 50;
            saveSaveData();
            createFloatingText("Side Quest Complete: Kill 10 Enemies! +50 Gold", deathPos, '#FFD700');
          }
        }
        
        // Track mini-boss defeats for achievements
        if (this.isMiniBoss) {
          playerStats.miniBossesDefeated++;
          createFloatingText("MINI-BOSS DEFEATED! 🏆", deathPos);
          // Clean up any surviving minions spawned with this mini-boss
          // Stagger deaths to prevent simultaneous death effect overload (freeze fix)
          let minionDelay = 0;
          for (const e of enemies) {
            if (!e.isDead && e.isMiniBossMinion) {
              const minionRef = e;
              setTimeout(() => { if (!minionRef.isDead) minionRef.die(); }, minionDelay);
              minionDelay += 150; // 150ms between each minion death
            }
          }
        }
        if (this.isFlyingBoss) {
          playerStats.miniBossesDefeated++;
          createFloatingText("⚡ FLYING BOSS DEFEATED! ⚡", deathPos, '#FF00FF');
          showEnhancedNotification('achievement', '⚡ FLYING BOSS SLAIN!', 'You defeated the Level 15 Flying Boss!');
        }
        
        updateHUD();
        updateComboCounter(true); // Phase 2: Track combo on kill
        checkAchievements(); // Check for achievements after kill
        // Rage Mode: add rage on kill
        if (window.GameRageCombat) window.GameRageCombat.addRage(8);
        // Special Atk Points: earn 1 point per 10 kills
        if (playerStats.kills % 10 === 0) {
          saveData.specialAtkPoints = (saveData.specialAtkPoints || 0) + 1;
        }
        // Harvesting: chance to drop Flesh
        if (window.GameHarvesting && this.mesh) window.GameHarvesting.onEnemyKilled(this.mesh.position);
        // Kill 7 achievement check
        if (playerStats.kills === 7 && (!saveData.achievementQuests || !saveData.achievementQuests.kill7Unlocked)) {
          if (!saveData.achievementQuests) saveData.achievementQuests = { kill7Unlocked: false, kill7Quest: 'none' };
          saveData.achievementQuests.kill7Unlocked = true;
          saveData.achievementQuests.kill7Quest = 'active';
          saveSaveData();
          showEnhancedNotification('achievement', '🏆 ACHIEVEMENT UNLOCKED: Kill 7 Enemies!', 'Visit the Achievement Building in Camp to claim your reward!');
          updateStatBar();
        }
      }
      
      // Specialized death effects by damage type
      dieStandard(enemyColor) {
        // Phase 5: Death Variety - Multiple death animation variations
        const deathVariation = Math.random();
        
        if (deathVariation < 0.25) {
          // BLOOD BURST DEATH: Intense blood explosion (no large flying pieces for performance)
          spawnParticles(this.mesh.position, 0x8B0000, 25); // Dark blood
          spawnParticles(this.mesh.position, 0xCC0000, 15); // Bright red splatter
          spawnParticles(this.mesh.position, 0xFF2200, 10); // Vivid gore
          // Small blood splatter marks on the ground
          for (let i = 0; i < 6; i++) {
            const angle = (i / 6) * Math.PI * 2;
            const dist = 0.4 + Math.random() * 0.8;
            spawnBloodDecal({ x: this.mesh.position.x + Math.cos(angle) * dist, y: 0, z: this.mesh.position.z + Math.sin(angle) * dist });
          }
        } else if (deathVariation < 0.5) {
          // CORPSE DEATH: Leave a corpse sprite with blood pool
          spawnParticles(this.mesh.position, 0x8B0000, 8);
          spawnParticles(this.mesh.position, 0xCC0000, 4);
          
          // 3D body: a flattened sphere matching the enemy color, lying on the ground
          const corpseGeo = new THREE.SphereGeometry(0.45, 8, 6);
          const corpseMat = new THREE.MeshBasicMaterial({ 
            color: enemyColor, 
            transparent: true,
            opacity: 0.85
          });
          const corpse = new THREE.Mesh(corpseGeo, corpseMat);
          corpse.position.copy(this.mesh.position);
          corpse.position.y = 0.12;
          corpse.scale.y = 0.22; // Flatten into a pancake/body shape
          scene.add(corpse);
          
          // Blood pool
          const bloodGeo = new THREE.CircleGeometry(0.8, 16);
          const bloodMat = new THREE.MeshStandardMaterial({ 
            color: 0x8B0000, 
            transparent: true,
            opacity: 0.5,
            roughness: 0.3,
            metalness: 0.5, // Shine/reflection on blood pool
            side: THREE.DoubleSide
          });
          const bloodPool = new THREE.Mesh(bloodGeo, bloodMat);
          bloodPool.position.copy(this.mesh.position);
          bloodPool.position.y = 0.01;
          bloodPool.rotation.x = -Math.PI / 2;
          scene.add(bloodPool);
          
          // Fade out
          let corpseLife = 180;
          if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            corpseLife--;
            corpse.material.opacity = (corpseLife / 180) * 0.7;
            bloodPool.material.opacity = (corpseLife / 180) * 0.5;
            if (corpseLife <= 0) {
              scene.remove(corpse);
              scene.remove(bloodPool);
              corpse.geometry.dispose();
              corpse.material.dispose();
              bloodPool.geometry.dispose();
              bloodPool.material.dispose();
              return false;
            }
            return true;
          }});
          } else {
            scene.remove(corpse); scene.remove(bloodPool);
            corpse.geometry.dispose(); corpse.material.dispose();
            bloodPool.geometry.dispose(); bloodPool.material.dispose();
          }
        } else if (deathVariation < 0.75) {
          // BLOOD MIST DEATH: Enemy dissolves in a burst of blood mist (no large pieces for performance)
          spawnParticles(this.mesh.position, 0x8B0000, 20); // Dark blood cloud
          spawnParticles(this.mesh.position, 0xCC2200, 12); // Red mist
          spawnParticles(this.mesh.position, 0x660000, 8);  // Deep crimson
          // Scattered blood stains around death position
          for (let i = 0; i < 5; i++) {
            spawnBloodDecal({ x: this.mesh.position.x + (Math.random() - 0.5) * 3, y: 0, z: this.mesh.position.z + (Math.random() - 0.5) * 3 });
          }
        } else {
          // SPLATTER DEATH: Dramatic blood splatter effect
          spawnParticles(this.mesh.position, 0x8B0000, 25); // Lots of blood
          spawnParticles(this.mesh.position, 0xCC0000, 10); // Blood spray
          
          // Create blood splatter marks in random directions
          for(let i = 0; i < 8; i++) {
            const splatter = new THREE.Mesh(
              new THREE.CircleGeometry(0.3, 8),
              new THREE.MeshBasicMaterial({ 
                color: 0x8B0000, 
                transparent: true,
                opacity: 0.6,
                side: THREE.DoubleSide
              })
            );
            const angle = (i / 8) * Math.PI * 2;
            const dist = 0.5 + Math.random() * 0.5;
            splatter.position.set(
              this.mesh.position.x + Math.cos(angle) * dist,
              0.01,
              this.mesh.position.z + Math.sin(angle) * dist
            );
            splatter.rotation.x = -Math.PI / 2;
            scene.add(splatter);
            
            // Fade out
            let life = 100;
            if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
            managedAnimations.push({ update(_dt) {
              life--;
              splatter.material.opacity = (life / 100) * 0.6;
              if (life <= 0) {
                scene.remove(splatter);
                splatter.geometry.dispose();
                splatter.material.dispose();
                return false;
              }
              return true;
            }});
            } else {
              scene.remove(splatter);
              splatter.geometry.dispose(); splatter.material.dispose();
            }
          }
          
          // Central corpse piece - 3D flattened body matching enemy color
          const corpse = new THREE.Mesh(
            new THREE.SphereGeometry(0.4, 8, 6),
            new THREE.MeshBasicMaterial({ 
              color: enemyColor, 
              transparent: true,
              opacity: 0.85
            })
          );
          corpse.position.copy(this.mesh.position);
          corpse.position.y = 0.1;
          corpse.scale.y = 0.2; // Flattened body silhouette
          scene.add(corpse);
          
          let corpseLife = 120;
          if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            corpseLife--;
            corpse.material.opacity = (corpseLife / 120) * 0.8;
            if (corpseLife <= 0) {
              scene.remove(corpse);
              corpse.geometry.dispose();
              corpse.material.dispose();
              return false;
            }
            return true;
          }});
          } else {
            scene.remove(corpse);
            corpse.geometry.dispose(); corpse.material.dispose();
          }
        }
      }
      
      dieByFire(enemyColor) {
        // Fire death: Char and burn to ash
        spawnParticles(this.mesh.position, 0xFF4500, 20); // Orange fire
        spawnParticles(this.mesh.position, 0xFFFF00, 10); // Yellow flames
        spawnParticles(this.mesh.position, 0x222222, 8); // Black smoke
        
        // Charred corpse - 3D flattened body shape
        const corpseGeo = new THREE.SphereGeometry(0.5, 8, 6);
        const corpseMat = new THREE.MeshBasicMaterial({ 
          color: 0x222222, // Charred black
          transparent: true,
          opacity: 0.8
        });
        const corpse = new THREE.Mesh(corpseGeo, corpseMat);
        corpse.position.copy(this.mesh.position);
        corpse.position.y = 0.11;
        corpse.scale.y = 0.2; // Flat charred body
        scene.add(corpse);
        
        // Burn mark on ground
        const burnGeo = new THREE.CircleGeometry(0.9, 16);
        const burnMat = new THREE.MeshBasicMaterial({ 
          color: 0x111111, 
          transparent: true,
          opacity: 0.6,
          side: THREE.DoubleSide
        });
        const burnMark = new THREE.Mesh(burnGeo, burnMat);
        burnMark.position.copy(this.mesh.position);
        burnMark.position.y = 0.01;
        burnMark.rotation.x = -Math.PI / 2;
        scene.add(burnMark);
        
        // Fade to ash
        let life = 120;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
        managedAnimations.push({ update(_dt) {
          life--;
          corpse.material.opacity = (life / 120) * 0.8;
          corpse.scale.multiplyScalar(0.995);
          if (life <= 0) {
            scene.remove(corpse);
            scene.remove(burnMark);
            corpse.geometry.dispose();
            corpse.material.dispose();
            burnMark.geometry.dispose();
            burnMark.material.dispose();
            return false;
          }
          return true;
        }});
        } else {
          scene.remove(corpse); scene.remove(burnMark);
          corpse.geometry.dispose(); corpse.material.dispose();
          burnMark.geometry.dispose(); burnMark.material.dispose();
        }
      }
      
      dieByIce(enemyColor) {
        // Enhanced ice death: crack → struggle → shatter, leaves ice chunks + water pools
        const deathPos = this.mesh.position.clone();
        spawnParticles(deathPos, 0x87CEEB, 15); // Light blue ice
        spawnParticles(deathPos, 0xFFFFFF, 12); // White frost
        // Ice crack particles
        if (window.BloodSystem) {
          window.BloodSystem.emitBurst(deathPos, 40, { spreadXZ: 0.5, spreadY: 0.4, color1: 0xAEEEFF, color2: 0xFFFFFF, minSize: 0.05, maxSize: 0.14, minLife: 30, maxLife: 60 });
        }

        // Brief struggle: body shakes before shattering
        let struggleCount = 0;
        const sx = deathPos.x, sz = deathPos.z;
        const struggleInterval = setInterval(() => {
          struggleCount++;
          if (this.mesh) {
            this.mesh.position.x = sx + (Math.random()-0.5) * (struggleCount < 4 ? 0.06 : 0.12);
            this.mesh.position.z = sz + (Math.random()-0.5) * (struggleCount < 4 ? 0.06 : 0.12);
            this.mesh.rotation.y += (Math.random()-0.5) * 0.3;
          }
          if (struggleCount >= 10) clearInterval(struggleInterval);
        }, 40);

        // Shatter into ice shards (with slight delay for drama)
        const shardCount = 10;
        for(let i = 0; i < shardCount; i++) {
          const shardGeo = new THREE.ConeGeometry(0.1, 0.3, 4);
          const shardMat = new THREE.MeshBasicMaterial({ 
            color: 0xADD8E6, // Light ice blue
            transparent: true,
            opacity: 0.7
          });
          const shard = new THREE.Mesh(shardGeo, shardMat);
          shard.position.copy(deathPos);
          scene.add(shard);
          
          const angle = (i / shardCount) * Math.PI * 2;
          const vel = new THREE.Vector3(
            Math.cos(angle) * 0.3,
            0.4 + Math.random() * 0.2,
            Math.sin(angle) * 0.3
          );
          
          let life = 60;
          if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
            managedAnimations.push({ update(_dt) {
              life--;
              shard.position.add(vel);
              vel.y -= 0.03;
              shard.rotation.x += 0.2;
              shard.rotation.z += 0.15;
              shard.material.opacity = (life / 60) * 0.7;
              if (life <= 0 || shard.position.y < 0) {
                scene.remove(shard);
                shard.geometry.dispose();
                shard.material.dispose();
                return false;
              }
              return true;
            }});
          } else {
            scene.remove(shard);
            shard.geometry.dispose();
            shard.material.dispose();
          }
        }

        // Water pool left on ground after ice melts
        setTimeout(() => {
          if (!scene) return;
          const waterGeo = new THREE.CircleGeometry(0.6 + Math.random() * 0.3, 12);
          const waterMat = new THREE.MeshStandardMaterial({ color: 0x88CCFF, transparent: true, opacity: 0.55, roughness: 0.05, metalness: 0.3, depthWrite: false });
          const water = new THREE.Mesh(waterGeo, waterMat);
          water.rotation.x = -Math.PI / 2;
          water.position.set(deathPos.x, 0.015, deathPos.z);
          scene.add(water);
          let wLife = 180;
          if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
            managedAnimations.push({ update(_dt) {
              wLife--;
              water.material.opacity = (wLife / 180) * 0.55;
              if (wLife <= 0) { scene.remove(water); water.geometry.dispose(); water.material.dispose(); return false; }
              return true;
            }, cleanup() { scene.remove(water); water.geometry.dispose(); water.material.dispose(); }});
          } else {
            scene.remove(water); water.geometry.dispose(); water.material.dispose();
          }
        }, 300);
      }
      
      dieByLightning(enemyColor) {
        // Lightning death: Blackened and smoking
        spawnParticles(this.mesh.position, 0xFFFF00, 15); // Yellow lightning
        spawnParticles(this.mesh.position, 0xFFFFFF, 10); // White flash
        spawnParticles(this.mesh.position, 0x444444, 8); // Gray smoke
        
        // Blackened corpse - 3D flattened body shape
        const corpseGeo = new THREE.SphereGeometry(0.5, 8, 6);
        const corpseMat = new THREE.MeshBasicMaterial({ 
          color: 0x1a1a1a, // Very dark gray
          transparent: true,
          opacity: 0.9
        });
        const corpse = new THREE.Mesh(corpseGeo, corpseMat);
        corpse.position.copy(this.mesh.position);
        corpse.position.y = 0.11;
        corpse.scale.y = 0.2; // Flat blackened body
        scene.add(corpse);
        
        // Smoke particles rising - use managedAnimations instead of setInterval to prevent timer accumulation
        const deathPos = this.mesh.position.clone();
        let smokeSpawnCount = 8;
        let smokeSpawnTimer = 0;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            smokeSpawnTimer++;
            if (smokeSpawnTimer % 6 === 0) { // ~100ms at 60fps
              smokeSpawnCount--;
              if (smokeSpawnCount <= 0 || !scene) return false;
              if (smokeParticles.length < MAX_SMOKE_PARTICLES) {
                const smokeGeo = new THREE.SphereGeometry(0.1, 6, 6);
                const smokeMat = new THREE.MeshBasicMaterial({ color: 0x666666, transparent: true, opacity: 0.4 });
                const smoke = new THREE.Mesh(smokeGeo, smokeMat);
                smoke.position.copy(deathPos);
                smoke.position.y = 0.1;
                scene.add(smoke);
                smokeParticles.push({ mesh: smoke, material: smokeMat, geometry: smokeGeo,
                  velocity: { x: (Math.random()-0.5)*0.02, y: 0.03, z: (Math.random()-0.5)*0.02 },
                  life: 40, maxLife: 40 });
              }
            }
            return smokeSpawnCount > 0;
          }});
        }
        
        // Fade corpse
        let corpseLife = 120;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
        managedAnimations.push({ update(_dt) {
          corpseLife--;
          corpse.material.opacity = (corpseLife / 120) * 0.9;
          if (corpseLife <= 0) {
            scene.remove(corpse);
            corpse.geometry.dispose();
            corpse.material.dispose();
            return false;
          }
          return true;
        }});
        } else {
          scene.remove(corpse);
          corpse.geometry.dispose(); corpse.material.dispose();
        }
      }
      
      dieByShotgun(enemyColor) {
        // DISMEMBERMENT: Body splits into upper/lower halves with gore physics
        const deathPos = this.mesh.position.clone();
        spawnParticles(deathPos, 0x8B0000, 30); // Lots of blood
        spawnParticles(deathPos, 0xCC0000, 20); // Bright splatter
        spawnParticles(deathPos, 0xFF2200, 10); // Vivid gore
        // Advanced blood burst
        if (window.BloodSystem) window.BloodSystem.emitBurst(deathPos, 800, { spreadXZ: 2.2, spreadY: 1.8 });

        // Scatter blood decals in a wide radius
        for (let i = 0; i < 10; i++) {
          const angle = (i / 10) * Math.PI * 2;
          const dist = 0.3 + Math.random() * 1.5;
          spawnBloodDecal({ x: deathPos.x + Math.cos(angle) * dist, y: 0, z: deathPos.z + Math.sin(angle) * dist });
        }

        // ── Upper body ─────────────────────────────────────────────────────────
        const upperGeo = new THREE.SphereGeometry(0.35, 8, 8);
        const upperMat = new THREE.MeshBasicMaterial({ color: enemyColor, transparent: true, opacity: 1 });
        const upper = new THREE.Mesh(upperGeo, upperMat);
        upper.position.copy(deathPos);
        upper.position.y += 0.4;
        scene.add(upper);
        // Intestine strands hanging from upper half (dark pink cylinder)
        for (let g = 0; g < 3; g++) {
          const gutGeo = new THREE.CylinderGeometry(0.025, 0.015, 0.3 + Math.random() * 0.2, 4);
          const gutMat = new THREE.MeshBasicMaterial({ color: [0xFF69B4, 0xCC2244, 0x8B1A1A][g % 3] });
          const gut = new THREE.Mesh(gutGeo, gutMat);
          gut.position.set((Math.random() - 0.5) * 0.2, -0.25, (Math.random() - 0.5) * 0.2);
          gut.rotation.z = (Math.random() - 0.5) * 0.5;
          upper.add(gut);
        }

        // ── Lower body ─────────────────────────────────────────────────────────
        const lowerGeo = new THREE.CylinderGeometry(0.3, 0.25, 0.35, 7);
        const lowerMat = new THREE.MeshBasicMaterial({ color: enemyColor, transparent: true, opacity: 1 });
        const lower = new THREE.Mesh(lowerGeo, lowerMat);
        lower.position.copy(deathPos);
        lower.position.y += 0.15;
        scene.add(lower);
        // Intestines from lower half too
        for (let g = 0; g < 2; g++) {
          const gutGeo = new THREE.CylinderGeometry(0.025, 0.015, 0.25 + Math.random() * 0.15, 4);
          const gutMat = new THREE.MeshBasicMaterial({ color: [0xFF69B4, 0x8B1A1A][g % 2] });
          const gut = new THREE.Mesh(gutGeo, gutMat);
          gut.position.set((Math.random() - 0.5) * 0.15, 0.22, (Math.random() - 0.5) * 0.15);
          lower.add(gut);
        }

        // ── Physics ────────────────────────────────────────────────────────────
        // Random slide direction (lower half glides backward, upper stands briefly)
        const slideAngle = Math.random() * Math.PI * 2;
        const slideSpd = 0.06 + Math.random() * 0.05;
        let upperVelY = 0.04;
        let lowerSlideX = Math.cos(slideAngle) * slideSpd;
        let lowerSlideZ = Math.sin(slideAngle) * slideSpd;
        let splitLife = 140;
        let dragTimer = 0;

        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            splitLife--;
            dragTimer++;

            // Lower half slides/glides backward, leaving blood trail
            lower.position.x += lowerSlideX;
            lower.position.z += lowerSlideZ;
            lowerSlideX *= 0.95; // Friction
            lowerSlideZ *= 0.95;

            // Blood drag trail every 2 frames
            if (dragTimer % 2 === 0 && window.BloodSystem) {
              window.BloodSystem.emitDragTrail(lower.position, { x: lowerSlideX, y: 0, z: lowerSlideZ }, 8);
            }

            // Upper half: drop organs after brief pause, then collapse
            if (splitLife < 100) {
              upperVelY -= 0.012;
              upper.position.y += upperVelY;
              upper.rotation.x += 0.04;
              upper.rotation.z += 0.03;
              if (upper.position.y < 0.1) upper.position.y = 0.1;
            }

            if (splitLife < 30) {
              upper.material.opacity = splitLife / 30;
              lower.material.opacity = splitLife / 30;
            }

            if (splitLife <= 0) {
              scene.remove(upper); scene.remove(lower);
              upper.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
              lower.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
              return false;
            }
            return true;
          }, cleanup() {
            scene.remove(upper); scene.remove(lower);
            upper.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
            lower.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
          }});
        } else {
          scene.remove(upper); scene.remove(lower);
          upper.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
          lower.traverse(c => { if (c.geometry) c.geometry.dispose(); if (c.material) c.material.dispose(); });
        }

        // Large blood pool at split point
        const bloodGeo = new THREE.CircleGeometry(1.2, 16);
        const bloodMat = new THREE.MeshBasicMaterial({ 
          color: 0x8B0000, 
          transparent: true,
          opacity: 0.7,
          side: THREE.DoubleSide
        });
        const bloodPool = new THREE.Mesh(bloodGeo, bloodMat);
        bloodPool.position.copy(deathPos);
        bloodPool.position.y = 0.01;
        bloodPool.rotation.x = -Math.PI / 2;
        scene.add(bloodPool);
        
        // Fade blood pool
        let life = 150;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
        managedAnimations.push({ update(_dt) {
          life--;
          bloodPool.material.opacity = (life / 150) * 0.7;
          if (life <= 0) {
            scene.remove(bloodPool);
            bloodPool.geometry.dispose();
            bloodPool.material.dispose();
            return false;
          }
          return true;
        }, cleanup() { scene.remove(bloodPool); bloodPool.geometry.dispose(); bloodPool.material.dispose(); }});
        } else {
          scene.remove(bloodPool);
          bloodPool.geometry.dispose(); bloodPool.material.dispose();
        }
      }
      
      dieBySpinDeath(enemyColor) {
        // Yellow enemy: 180-degree spin with continuous neck blood arc trail
        const deathPos = this.mesh.position.clone();
        spawnParticles(deathPos, 0x8B0000, 20);
        spawnParticles(deathPos, 0xCC0000, 10);

        // Create spinning body proxy
        const bodyGeo = new THREE.SphereGeometry(0.4, 8, 8);
        const bodyMat = new THREE.MeshBasicMaterial({ color: enemyColor, transparent: true, opacity: 1 });
        const body = new THREE.Mesh(bodyGeo, bodyMat);
        body.position.copy(deathPos);
        scene.add(body);

        let spinAngle = 0;
        let spinLife = 90; // ~1.5 seconds at 60fps
        const spinSpeed = (Math.PI) / 30; // 180° in ~30 frames, then continues

        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            spinLife--;
            spinAngle += spinSpeed;
            body.rotation.y = spinAngle;

            // Blood spray from neck following the spin
            if (window.BloodSystem && spinLife > 15) {
              window.BloodSystem.emitSpinTrail(body.position, spinAngle, 4);
            }

            // Scatter blood decal spots on ground as it spins
            if (spinLife % 5 === 0) {
              const splatAngle = spinAngle;
              const dist = 0.5 + Math.random() * 1.5;
              spawnBloodDecal({ x: deathPos.x + Math.cos(splatAngle) * dist, y: 0, z: deathPos.z + Math.sin(splatAngle) * dist });
            }

            if (spinLife < 25) {
              body.material.opacity = spinLife / 25;
            }
            if (spinLife <= 0) {
              scene.remove(body);
              body.geometry.dispose(); body.material.dispose();
              return false;
            }
            return true;
          }, cleanup() {
            scene.remove(body);
            body.geometry.dispose(); body.material.dispose();
          }});
        } else {
          scene.remove(body);
          body.geometry.dispose(); body.material.dispose();
        }
      }
      
      dieByHeadshot(enemyColor) {
        // FRESH IMPLEMENTATION: Enhanced headshot with actual head detachment
        // Headshot: Blood spray (reduced enemy color particles, more blood)
        spawnParticles(this.mesh.position, 0xDC143C, 20); // Crimson blood
        spawnParticles(this.mesh.position, 0x8B0000, 15); // Dark red blood
        spawnParticles(this.mesh.position, 0xCC0000, 10); // Bright blood spray
        // Advanced headshot: pulsating blood from neck/head in 180-degree spread
        if (window.BloodSystem) {
          const neckPos = this.mesh.position.clone();
          neckPos.y += 0.6;
          window.BloodSystem.emitPulse(neckPos, { pulses: 4, perPulse: 400, interval: 200, spreadXZ: 1.8, color1: 0x8B0000, color2: 0xDC143C });
        }
        
        // Create detached head that flies off with enhanced rotation
        const headGeo = new THREE.SphereGeometry(0.3, 12, 12);
        const headMat = new THREE.MeshBasicMaterial({ 
          color: enemyColor, 
          transparent: true,
          opacity: 1
        });
        const head = new THREE.Mesh(headGeo, headMat);
        head.position.copy(this.mesh.position);
        head.position.y += 0.5; // Start from head height
        scene.add(head);
        
        // Head velocity (flies backward and up with spin)
        const headVel = new THREE.Vector3(
          (Math.random() - 0.5) * 0.6,
          0.8 + Math.random() * 0.4, // Upward
          (Math.random() - 0.5) * 0.6
        );
        
        // Enhanced rotation speeds for dramatic spinning
        const rotSpeed = {
          x: 0.15 + Math.random() * 0.1,
          y: 0.2 + Math.random() * 0.15,
          z: 0.1 + Math.random() * 0.1
        };
        
        // Blood spray trail from neck
        let headLife = 80;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
        managedAnimations.push({ update(_dt) {
          headLife--;
          head.position.add(headVel);
          headVel.y -= 0.025;
          head.rotation.x += rotSpeed.x;
          head.rotation.y += rotSpeed.y;
          head.rotation.z += rotSpeed.z;
          if (headLife % 2 === 0 && headLife > 20) {
            spawnParticles(head.position, 0xDC143C, 3);
          }
          if (headLife < 20) {
            head.material.opacity = headLife / 20;
          }
          if (headLife <= 0 || head.position.y < 0) {
            scene.remove(head);
            head.geometry.dispose();
            head.material.dispose();
            return false;
          }
          return true;
        }});
        } else {
          scene.remove(head);
          head.geometry.dispose(); head.material.dispose();
        }
        
        // Body falls (corpse without head) - 3D flattened body matching enemy color
        const corpseGeo = new THREE.SphereGeometry(0.5, 8, 6);
        const corpseMat = new THREE.MeshBasicMaterial({ 
          color: enemyColor, 
          transparent: true,
          opacity: 0.85
        });
        const corpse = new THREE.Mesh(corpseGeo, corpseMat);
        corpse.position.copy(this.mesh.position);
        corpse.position.y = 0.11;
        corpse.scale.y = 0.22; // Flat headless body
        scene.add(corpse);
        
        // Large blood splatter pool (crimson, not white!)
        const bloodGeo = new THREE.CircleGeometry(1.2, 16); // Larger pool
        const bloodMat = new THREE.MeshBasicMaterial({ 
          color: 0xDC143C, // Crimson blood
          transparent: true,
          opacity: 0.7, // More visible
          side: THREE.DoubleSide
        });
        const bloodPool = new THREE.Mesh(bloodGeo, bloodMat);
        bloodPool.position.copy(this.mesh.position);
        bloodPool.position.y = 0.01;
        bloodPool.rotation.x = -Math.PI / 2;
        scene.add(bloodPool);
        
        // Extra blood particles instead of large gore pieces (better performance)
        spawnParticles(this.mesh.position, 0xDC143C, 12); // Crimson blood burst
        spawnParticles(this.mesh.position, 0x8B0000, 8);  // Dark blood
        for (let i = 0; i < 5; i++) {
          const angle = (i / 5) * Math.PI * 2;
          spawnBloodDecal({ x: this.mesh.position.x + Math.cos(angle) * (0.5 + Math.random() * 0.8), y: 0, z: this.mesh.position.z + Math.sin(angle) * (0.5 + Math.random() * 0.8) });
        }
        
        // Fade corpse
        let life = 120;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
        managedAnimations.push({ update(_dt) {
          life--;
          corpse.material.opacity = (life / 120) * 0.8;
          bloodPool.material.opacity = (life / 120) * 0.6;
          if (life <= 0) {
            scene.remove(corpse);
            scene.remove(bloodPool);
            corpse.geometry.dispose();
            corpse.material.dispose();
            bloodPool.geometry.dispose();
            bloodPool.material.dispose();
            return false;
          }
          return true;
        }});
        } else {
          scene.remove(corpse); scene.remove(bloodPool);
          corpse.geometry.dispose(); corpse.material.dispose();
          bloodPool.geometry.dispose(); bloodPool.material.dispose();
        }
      }
    }

    // Performance: Cached geometries and materials for projectiles (reused across instances)
    const projectileGeometryCache = {
      bullet: new THREE.SphereGeometry(0.0625, 8, 8),  // 75% smaller radius (0.25 → 0.0625 is 25% of original)
      bulletGlow: new THREE.SphereGeometry(0.0875, 6, 6)  // 75% smaller radius (0.35 → 0.0875 is 25% of original)
    };
    const projectileMaterialCache = {
      bullet: new THREE.MeshBasicMaterial({ 
        color: 0xFF4500,  // Red-orange starting color
        transparent: true,
        opacity: 0.95
      }),
      bulletGlow: new THREE.MeshBasicMaterial({
        color: 0xFF6347,  // Tomato red-orange for glow
        transparent: true,
        opacity: 0.4
      })
    };

    // Phase 5: Companion System - Simplified implementation for stable gameplay
    class Companion {
      constructor(companionId) {
        this.companionId = companionId;
        this.data = COMPANIONS[companionId];
        this.companionData = saveData.companions[companionId];
        
        // Stats based on level
        const isEvolved = this.companionData.level >= 10;
        const stats = isEvolved ? this.data.evolvedStats : this.data.baseStats;
        
        this.damage = stats.damage;
        this.attackSpeed = stats.attackSpeed;
        this.maxHp = stats.health;
        this.hp = this.maxHp;
        this.isDead = false;
        this.respawnTimer = 0;
        this.lastAttackTime = 0;
        
        // Create visual representation
        const icon = isEvolved ? this.data.evolvedIcon : this.data.icon;
        const size = 0.8;
        const geo = new THREE.BoxGeometry(size, size, size);
        const mat = new THREE.MeshStandardMaterial({ 
          color: this.data.type === 'melee' ? 0x8B4513 : 
                 this.data.type === 'ranged' ? 0x4169E1 : 0x00CED1
        });
        this.mesh = new THREE.Mesh(geo, mat);
        this.mesh.castShadow = true;
        this.mesh.receiveShadow = true;
        scene.add(this.mesh);
        
        // Position near player
        this.mesh.position.copy(player.mesh.position);
        this.mesh.position.x += 2;
      }
      
      update(dt) {
        if (this.isDead) {
          this.respawnTimer -= dt;
          if (this.respawnTimer <= 0) {
            this.respawn();
          }
          return;
        }
        
        if (!player || !player.mesh) return;
        
        // Follow player with simple AI
        const dx = player.mesh.position.x - this.mesh.position.x;
        const dz = player.mesh.position.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        
        // Keep distance from player (melee closer, others farther)
        const targetDist = this.data.type === 'melee' ? 2 : 3;
        
        if (dist > targetDist + 0.5) {
          // Move toward player
          const moveSpeed = 0.15;
          this.mesh.position.x += (dx / dist) * moveSpeed;
          this.mesh.position.z += (dz / dist) * moveSpeed;
        } else if (dist < targetDist - 0.5) {
          // Move away from player
          const moveSpeed = 0.1;
          this.mesh.position.x -= (dx / dist) * moveSpeed;
          this.mesh.position.z -= (dz / dist) * moveSpeed;
        }
        
        // Attack nearest enemy
        const now = Date.now();
        if (enemies.length > 0 && now - this.lastAttackTime > this.attackSpeed * 1000) {
          let nearest = null;
          let nearestDist = Infinity;
          
          for (const enemy of enemies) {
            if (enemy.isDead) continue; // Skip dead enemies
            const ex = enemy.mesh.position.x - this.mesh.position.x;
            const ez = enemy.mesh.position.z - this.mesh.position.z;
            const d = ex*ex + ez*ez;
            if (d < nearestDist && d < 100) { // Range check
              nearestDist = d;
              nearest = enemy;
            }
          }
          
          if (nearest) {
            // Attack
            const damageMultiplier = 1 + (this.companionData.level - 1) * 0.1; // +10% per level
            const finalDamage = Math.floor(this.damage * damageMultiplier * playerStats.strength);
            nearest.takeDamage(finalDamage, false);
            spawnParticles(nearest.mesh.position, 0xFF6347, 3);
            this.lastAttackTime = now;
          }
        }
        
        // Bob animation
        this.mesh.position.y = 0.5 + Math.sin(Date.now() * 0.003) * 0.1;
      }
      
      takeDamage(amount) {
        this.hp -= amount;
        if (this.hp <= 0) {
          this.die();
        }
      }
      
      die() {
        this.isDead = true;
        this.mesh.visible = false;
        this.respawnTimer = 10; // 10 second respawn
        createFloatingText('Companion down!', this.mesh.position, '#FF6347');
      }
      
      respawn() {
        this.isDead = false;
        this.hp = this.maxHp;
        this.mesh.visible = true;
        this.mesh.position.copy(player.mesh.position);
        this.mesh.position.x += 2;
        createFloatingText('Companion respawned!', this.mesh.position, '#00FF00');
      }
      
      addXP(amount) {
        // Companions gain 10% of all XP awarded to the player
        const companionXP = Math.floor(amount * 0.1);
        this.companionData.xp += companionXP;
        
        // Level up check (simplified progression)
        const xpRequired = [0, 100, 250, 500, 800, 1200, 1700, 2300, 3000, 4000];
        if (this.companionData.level < 10 && this.companionData.xp >= xpRequired[this.companionData.level]) {
          this.companionData.level++;
          saveData.companions[this.companionId] = this.companionData;
          // Award companion skill point on level up
          saveData.companionSkillPoints = (saveData.companionSkillPoints || 0) + 1;
          saveSaveData();
          
          if (this.companionData.level === 10) {
            createFloatingText('⭐ COMPANION EVOLVED! ⭐', this.mesh.position, '#FFD700');
            // Update stats to evolved form
            const stats = this.data.evolvedStats;
            this.damage = stats.damage;
            this.attackSpeed = stats.attackSpeed;
            this.maxHp = stats.health;
            this.hp = this.maxHp;
          } else {
            createFloatingText(`Level ${this.companionData.level}! +1 SP`, this.mesh.position, '#00FF00');
          }
        }
      }
      
      destroy() {
        scene.remove(this.mesh);
        this.mesh.geometry.dispose();
        this.mesh.material.dispose();
      }
    }

    class Projectile {
      constructor(x, z, target) {
        // Performance: Reuse cached geometry but clone materials for independent color transitions
        this.mesh = new THREE.Mesh(
          projectileGeometryCache.bullet, 
          projectileMaterialCache.bullet.clone()  // Clone material for independent color
        );
        this.mesh.position.set(x, 0.5, z);
        scene.add(this.mesh);
        
        // Add glowing trail effect with cloned material
        this.glow = new THREE.Mesh(
          projectileGeometryCache.bulletGlow, 
          projectileMaterialCache.bulletGlow.clone()  // Clone material for independent color
        );
        this.glow.position.copy(this.mesh.position);
        scene.add(this.glow);

        this.speed = 0.5; // Increased from 0.4 (25% faster)
        this.active = true;
        this.life = 60; // Frames
        this.maxLife = 60; // Track max life for color transition
        
        // Piercing support: track enemies already hit
        this.hitEnemies = new Set();
        this.maxHits = (playerStats.pierceCount || 0) + 1; // Total enemies this bullet can hit (1 + pierce count)

        // Calculate direction
        const dx = target.x - x;
        const dz = target.z - z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        this.vx = (dx / dist) * this.speed;
        this.vz = (dz / dist) * this.speed;
      }

      update() {
        if (!this.active) return false;
        
        // Handle enemy projectiles separately
        if (this.isEnemyProjectile) {
          this.mesh.position.add(this.direction.clone().multiplyScalar(this.speed));
          this.lifetime--;
          
          if (this.lifetime <= 0) {
            this.destroy();
            return false;
          }
          
          // Check collision with player
          const dx = this.mesh.position.x - player.mesh.position.x;
          const dz = this.mesh.position.z - player.mesh.position.z;
          if (dx*dx + dz*dz < 0.8) { // Hit radius
            player.takeDamage(this.damage);
            spawnParticles(player.mesh.position, 0xFF6347, 5);
            this.destroy();
            playSound('hit');
            return false;
          }
          return true;
        }
        
        // Player projectiles
        this.mesh.position.x += this.vx;
        this.mesh.position.z += this.vz;
        
        // Color transition: red-orange (start) → copper (end)
        // Progress: 1.0 (just fired) → 0.0 (about to expire)
        const progress = this.life / this.maxLife;
        
        // Red-orange: 0xFF4500 (RGB: 255, 69, 0)
        // Copper: 0xB87333 (RGB: 184, 115, 51)
        const startColor = { r: 255, g: 69, b: 0 };
        const endColor = { r: 184, g: 115, b: 51 };
        
        const r = Math.floor(startColor.r * progress + endColor.r * (1 - progress));
        const g = Math.floor(startColor.g * progress + endColor.g * (1 - progress));
        const b = Math.floor(startColor.b * progress + endColor.b * (1 - progress));
        
        const currentColor = (r << 16) | (g << 8) | b;
        this.mesh.material.color.setHex(currentColor);
        
        // Update glow position and fade it
        if (this.glow) {
          this.glow.position.copy(this.mesh.position);
          this.glow.material.opacity = 0.4 * (this.life / 60);
          // Also update glow color to match bullet
          this.glow.material.color.setHex(currentColor);
        }
        
        this.life--;

        if (this.life <= 0) {
          this.destroy();
          return false;
        }

        // Collision Check - with piercing support
        for (let enemy of enemies) {
          if (enemy.isDead) continue;
          if (this.hitEnemies.has(enemy)) continue; // Skip already-hit enemies
          
          const dx = this.mesh.position.x - enemy.mesh.position.x;
          const dz = this.mesh.position.z - enemy.mesh.position.z;
          if (dx*dx + dz*dz < 0.6) { // Hit radius
            // Calculate Damage
            let dmg = weapons.gun.damage * playerStats.damage * playerStats.strength;
            
            // Double barrel uses its own damage
            if (weapons.doubleBarrel.active && this.isDoubleBarrel) {
              dmg = weapons.doubleBarrel.damage * playerStats.damage * playerStats.strength;
            }
            
            // Drone turret uses its own damage
            if (weapons.droneTurret.active && this.isDroneTurret) {
              dmg = weapons.droneTurret.damage * playerStats.damage * playerStats.strength;
            }

            // Rage Mode damage boost
            if (player && player._rageDamageMult && player._rageDamageMult > 1) {
              dmg *= player._rageDamageMult;
            }
            
            // HEADSHOT SYSTEM: Double-crit check for headshot (instant kill)
            const isCrit = Math.random() < playerStats.critChance;
            const isDoubleCrit = isCrit && Math.random() < playerStats.critChance; // Second crit check
            
            if (isDoubleCrit && playerStats.headshotUnlocked) {
              // HEADSHOT! Instant kill
              enemy.hp = 0;
              
              // Create floating HEADSHOT text - THINNER FONT
              const div = document.createElement('div');
              div.style.position = 'absolute';
              div.style.color = '#FF0000';
              div.style.fontSize = '32px';
              div.style.fontWeight = '500'; // Reduced from 600 to 500 for thinner font
              div.style.fontFamily = 'Bangers, cursive';
              div.style.textShadow = '0 0 20px #FF0000, 2px 2px 4px #000';
              div.style.pointerEvents = 'none';
              div.style.zIndex = '1000';
              div.innerText = 'HEADSHOT!';
              if (window.pushSuperStatEvent) window.pushSuperStatEvent('HEADSHOT!', 'legendary', '\uD83C\uDFAF', 'success');
              
              const vec = enemy.mesh.position.clone();
              vec.y += 2;
              vec.project(camera);
              
              // Convert NDC (-1 to 1) to screen coordinates (0 to width/height)
              const NDC_CENTER_OFFSET = 0.5; // Offset to center NDC coordinates
              const x = (vec.x * NDC_CENTER_OFFSET + NDC_CENTER_OFFSET) * window.innerWidth;
              const y = (-(vec.y * NDC_CENTER_OFFSET) + NDC_CENTER_OFFSET) * window.innerHeight;
              
              div.style.left = `${x}px`;
              div.style.top = `${y}px`;
              div.style.transform = 'translate(-50%, -50%)';
              
              document.body.appendChild(div);
              setTimeout(() => div.remove(), 1500);
              
              // Blood particle effect
              spawnParticles(enemy.mesh.position, 0x8B0000, 30); // Dark red blood
              spawnParticles(enemy.mesh.position, 0xFF0000, 20); // Bright red blood
              // Advanced headshot: pulsating blood spray (zero knockback, 180° spread)
              if (window.BloodSystem) {
                const headPos = enemy.mesh.position.clone();
                headPos.y += 0.7;
                window.BloodSystem.emitPulse(headPos, { pulses: 4, perPulse: 400, interval: 200, spreadXZ: 1.6 });
              }
              
              // Flash effect
              const headshotLight = new THREE.PointLight(0xFF0000, 12, 20);
              headshotLight.position.copy(enemy.mesh.position);
              headshotLight.position.y += 2;
              scene.add(headshotLight);
              setTimeout(() => {
                scene.remove(headshotLight);
              }, 200);
            } else if (isCrit) {
              // Normal crit
              dmg *= playerStats.critDmg;
              const critDmgType = this.isDroneTurret ? 'drone' : (this.isDoubleBarrel ? 'doubleBarrel' : 'gun');
              enemy.takeDamage(Math.floor(dmg), isCrit, critDmgType);
              
              // FRESH: Critical hit effects - gold particles, brief light flash
              spawnParticles(enemy.mesh.position, 0xFFD700, 15); // Gold particles
              spawnParticles(enemy.mesh.position, 0xFFA500, 10); // Orange particles
              
              // Brief golden light flash
              const critLight = new THREE.PointLight(0xFFD700, 8, 15);
              critLight.position.copy(enemy.mesh.position);
              critLight.position.y += 1;
              scene.add(critLight);
              setTimeout(() => {
                scene.remove(critLight);
              }, 150);
            } else {
              // Normal hit — pass weapon-specific damageType for downstream effects
              const hitDmgType = this.isDroneTurret ? 'drone' : (this.isDoubleBarrel ? 'doubleBarrel' : 'gun');
              enemy.takeDamage(Math.floor(dmg), false, hitDmgType);
            }
            
            // Knockback effect — drone: near zero; gun: reduced with level scaling; double barrel: heavy
            let knockbackForce;
            if (this.isDroneTurret) {
              const droneLevel = weapons.droneTurret ? (weapons.droneTurret.level || 1) : 1;
              // Drone L1/L2: near-zero knockback. L3: slight knockback (bullet penetration)
              knockbackForce = droneLevel >= 3 ? 0.12 : 0.02;
              // Level-based drone hit effects
              if (droneLevel === 1) {
                // L1: Slow enemy movement, fast wobble animation
                if (!enemy.isDead && !enemy.isFrozen) {
                  if (!enemy.originalSpeed) enemy.originalSpeed = enemy.speed;
                  // Always calculate from originalSpeed to prevent compounding slowdown
                  enemy.speed = (enemy.originalSpeed) * 0.5;
                  if (!enemy.slowedUntil || enemy.slowedUntil < Date.now() + 500) {
                    enemy.slowedUntil = Date.now() + 800; // Brief slow
                  }
                }
                // Small blood pools in front
                spawnBloodDecal({ x: enemy.mesh.position.x + this.vx * 0.5, y: 0, z: enemy.mesh.position.z + this.vz * 0.5 });
              } else if (droneLevel === 2) {
                // L2: Stop the enemy completely, fast shaking
                if (!enemy.isDead && !enemy.isFrozen) {
                  if (!enemy.originalSpeed) enemy.originalSpeed = enemy.speed;
                  enemy.slowedUntil = Date.now() + 400; // Brief full stop
                  enemy.speed = 0;
                  setTimeout(() => { if (enemy && !enemy.isDead) enemy.speed = enemy.originalSpeed || enemy.speed; }, 400);
                }
                // Rapid shaking animation
                if (enemy.mesh) {
                  // Clear any existing shake interval to prevent concurrent animations
                  if (enemy._droneShakeTimer) { clearInterval(enemy._droneShakeTimer); enemy._droneShakeTimer = null; }
                  let shakes = 0;
                  const sx = enemy.mesh.position.x, sz = enemy.mesh.position.z;
                  enemy._droneShakeTimer = setInterval(() => {
                    shakes++;
                    if (enemy.mesh) {
                      enemy.mesh.position.x = sx + (Math.random()-0.5)*0.08;
                      enemy.mesh.position.z = sz + (Math.random()-0.5)*0.08;
                    }
                    if (shakes >= 6) {
                      clearInterval(enemy._droneShakeTimer);
                      enemy._droneShakeTimer = null;
                      if (enemy.mesh) { enemy.mesh.position.x = sx; enemy.mesh.position.z = sz; }
                    }
                  }, 30);
                }
                // Large compact blood pool directly under enemy
                if (window.BloodSystem) {
                  window.BloodSystem.emitBurst(enemy.mesh.position, 25, { spreadXZ: 0.2, spreadY: 0.1, minLife: 15, maxLife: 25 });
                }
              } else if (droneLevel >= 3) {
                // L3: Slight knockback + penetration, rapid tiny exit spray
                const exitPos2 = new THREE.Vector3(
                  enemy.mesh.position.x + this.vx * 0.8,
                  enemy.mesh.position.y,
                  enemy.mesh.position.z + this.vz * 0.8
                );
                const bulletDir2 = new THREE.Vector3(this.vx, 0, this.vz).normalize();
                if (window.BloodSystem) {
                  window.BloodSystem.emitExitWound(exitPos2, bulletDir2, 15, { spread: 0.3, speed: 0.25 });
                }
              }
            } else if (weapons.doubleBarrel.active && this.isDoubleBarrel) {
              // Double barrel: heavy knockback with partial topple effect
              knockbackForce = 1.8 * (1 + (weapons.doubleBarrel.level - 1) * 0.2);
              // Topple: tilt enemy mesh briefly on impact
              const toppleAngle = (Math.random() - 0.5) * 0.6;
              enemy.mesh.rotation.x = toppleAngle;
              enemy.mesh.rotation.z = toppleAngle * 0.5;
              setTimeout(() => {
                if (enemy.mesh) { enemy.mesh.rotation.x = 0; enemy.mesh.rotation.z = 0; }
              }, 300);
            } else {
              // Standard gun: reduced base force, scales up with weapon level
              knockbackForce = 0.3 * (1 + (weapons.gun.level - 1) * 0.2);
            }
            enemy.mesh.position.x += this.vx * knockbackForce;
            enemy.mesh.position.z += this.vz * knockbackForce;
            
            // ── Weapon-specific hit effects ──────────────────────────────────────
            if (this.isDroneTurret) {
              // Drone: constant tiny impacts — mesh twitches and small drips fall below
              const droneLevel = weapons.droneTurret.level || 1;
              // Twitching wobble (brief offset that snaps back)
              const twitch = 0.04 + droneLevel * 0.02;
              enemy.mesh.position.x += (Math.random() - 0.5) * twitch;
              enemy.mesh.position.z += (Math.random() - 0.5) * twitch;
              
              if (droneLevel >= 2) {
                // Level 2+: enemy freezes in place, violent shaking; rapid blood stream down front
                // Freeze in place briefly (handled via near-zero knockback)
                // Add 10-20 tiny entry holes rapidly
                const nowDrone = Date.now();
                if (!enemy._lastDroneHoleTime || nowDrone - enemy._lastDroneHoleTime > 60) {
                  enemy._lastDroneHoleTime = nowDrone;
                  if (!enemy.bulletHoles) enemy.bulletHoles = [];
                  const holesToAdd = droneLevel >= 3 ? 2 : 1;
                  for (let dh = 0; dh < holesToAdd && enemy.bulletHoles.length < 20; dh++) {
                    const dHole = new THREE.Mesh(bulletHoleGeo, bulletHoleMat.clone());
                    const th = Math.random() * Math.PI * 2;
                    const ph = Math.random() * Math.PI;
                    dHole.position.set(Math.sin(ph)*Math.cos(th)*0.51, Math.sin(ph)*Math.sin(th)*0.51, Math.cos(ph)*0.51);
                    dHole.lookAt(dHole.position.clone().multiplyScalar(2));
                    enemy.mesh.add(dHole);
                    enemy.bulletHoles.push(dHole);
                  }
                }
                // Blood streaming continuously down front of enemy
                if (bloodDrips.length < MAX_BLOOD_DRIPS) {
                  const streamDrop = new THREE.Mesh(
                    new THREE.SphereGeometry(0.025 + Math.random()*0.025, 4, 4),
                    new THREE.MeshBasicMaterial({ color: 0xAA0000 })
                  );
                  streamDrop.position.set(
                    enemy.mesh.position.x + (Math.random()-0.5)*0.3,
                    enemy.mesh.position.y + 0.4,
                    enemy.mesh.position.z + 0.45 // front face
                  );
                  scene.add(streamDrop);
                  bloodDrips.push({ mesh: streamDrop, velX: 0, velZ: 0, velY: -0.05, life: 35 + Math.floor(Math.random()*15) });
                }
                // Rapidly expanding blood pool
                spawnBloodDecal(enemy.mesh.position);
              } else {
                // Level 1: small continuous drips fall directly below enemy, slowly pooling
                if (bloodDrips.length < MAX_BLOOD_DRIPS) {
                  const drip1 = new THREE.Mesh(
                    new THREE.SphereGeometry(0.02 + Math.random()*0.02, 4, 4),
                    new THREE.MeshBasicMaterial({ color: 0x8B0000 })
                  );
                  drip1.position.set(enemy.mesh.position.x + (Math.random()-0.5)*0.2, enemy.mesh.position.y, enemy.mesh.position.z + (Math.random()-0.5)*0.2);
                  scene.add(drip1);
                  bloodDrips.push({ mesh: drip1, velX: 0, velZ: 0, velY: -0.04, life: 30 + Math.floor(Math.random()*10) });
                }
              }
              
              if (droneLevel >= 3) {
                // Level 3: exit-wound penetration — fine blood mist out back, coats ground behind
                const exitMistX = enemy.mesh.position.x - this.vx * 1.0;
                const exitMistZ = enemy.mesh.position.z - this.vz * 1.0;
                spawnParticles({ x: exitMistX, y: enemy.mesh.position.y, z: exitMistZ }, 0xCC0000, 3);
                spawnParticles({ x: exitMistX, y: enemy.mesh.position.y, z: exitMistZ }, 0x8B0000, 2);
                // Fine mist droplets coat the ground behind enemy
                for (let fm = 0; fm < 3 && bloodDrips.length < MAX_BLOOD_DRIPS; fm++) {
                  const mist = new THREE.Mesh(
                    new THREE.SphereGeometry(0.015 + Math.random()*0.015, 3, 3),
                    new THREE.MeshBasicMaterial({ color: 0xCC0000 })
                  );
                  mist.position.set(exitMistX + (Math.random()-0.5)*0.5, enemy.mesh.position.y + 0.3, exitMistZ + (Math.random()-0.5)*0.5);
                  scene.add(mist);
                  // High-velocity along bullet direction
                  bloodDrips.push({
                    mesh: mist,
                    velX: -this.vx * 0.25 + (Math.random()-0.5)*0.04,
                    velZ: -this.vz * 0.25 + (Math.random()-0.5)*0.04,
                    velY: 0.05 + Math.random()*0.08,
                    life: 30 + Math.floor(Math.random()*20)
                  });
                }
                spawnBloodDecal({ x: exitMistX + (Math.random()-0.5)*0.6, y: 0, z: exitMistZ + (Math.random()-0.5)*0.6 });
              }
            } else if (this.isDoubleBarrel) {
              // Double barrel / heavy explosive: large gore blobs + heavy directional blood
              // Blow-away chunk effect: 2-3 large chunks of dark red "gore" scatter from enemy
              for (let gc = 0; gc < 3 && bloodDrips.length < MAX_BLOOD_DRIPS; gc++) {
                const goreSize = 0.07 + Math.random() * 0.1;
                const gore = new THREE.Mesh(
                  new THREE.DodecahedronGeometry(goreSize, 0),
                  new THREE.MeshStandardMaterial({ color: gc % 2 === 0 ? 0x6B0000 : 0x4B0082, roughness: 0.9 })
                );
                gore.position.copy(enemy.mesh.position);
                gore.position.y += (Math.random() - 0.5) * 0.6;
                scene.add(gore);
                bloodDrips.push({
                  mesh: gore,
                  velX: (Math.random() - 0.5) * 0.5 + this.vx * 0.6,
                  velZ: (Math.random() - 0.5) * 0.5 + this.vz * 0.6,
                  velY: 0.25 + Math.random() * 0.35,
                  life: 55 + Math.floor(Math.random() * 25)
                });
              }
              // Heavy blood spray in all directions, stronger along blast trajectory
              spawnParticles(enemy.mesh.position, 0x8B0000, 5);
              spawnParticles(enemy.mesh.position, 0xCC0000, 4);
              spawnParticles(enemy.mesh.position, 0x660000, 3);
              // Directional spray along bullet path
              const blastExitX = enemy.mesh.position.x + this.vx * 1.5;
              const blastExitZ = enemy.mesh.position.z + this.vz * 1.5;
              for (let bs = 0; bs < 5 && bloodDrips.length < MAX_BLOOD_DRIPS; bs++) {
                const sp = new THREE.Mesh(
                  new THREE.SphereGeometry(0.04 + Math.random()*0.06, 4, 4),
                  new THREE.MeshBasicMaterial({ color: [0xAA0000, 0x880000, 0xCC0000][bs % 3] })
                );
                sp.position.copy(enemy.mesh.position);
                scene.add(sp);
                bloodDrips.push({
                  mesh: sp,
                  velX: this.vx * (0.3 + Math.random()*0.4) + (Math.random()-0.5)*0.15,
                  velZ: this.vz * (0.3 + Math.random()*0.4) + (Math.random()-0.5)*0.15,
                  velY: 0.1 + Math.random() * 0.3,
                  life: 40 + Math.floor(Math.random() * 20)
                });
              }
              // Large gore drops directly beneath enemy
              for (let gd = 0; gd < 3; gd++) {
                spawnBloodDecal({ x: enemy.mesh.position.x + (Math.random()-0.5)*0.6, y: 0, z: enemy.mesh.position.z + (Math.random()-0.5)*0.6 });
              }
            } else {
              // Standard gun hit — entry wound at front face
              // Entry: small dark hole at impact face + tiny blood drops toward player (entry splatter)
              const entryX = enemy.mesh.position.x - this.vx * 0.5;
              const entryZ = enemy.mesh.position.z - this.vz * 0.5;
              // Small entry blood spray toward bullet direction (back-spatter at entry)
              for (let es = 0; es < 3 && bloodDrips.length < MAX_BLOOD_DRIPS; es++) {
                const ep = new THREE.Mesh(
                  new THREE.SphereGeometry(0.02 + Math.random()*0.025, 4, 4),
                  new THREE.MeshBasicMaterial({ color: 0xAA0000 })
                );
                ep.position.set(entryX + (Math.random()-0.5)*0.25, enemy.mesh.position.y + 0.1 + (Math.random()-0.5)*0.3, entryZ + (Math.random()-0.5)*0.25);
                scene.add(ep);
                bloodDrips.push({
                  mesh: ep,
                  velX: -this.vx * (0.1 + Math.random()*0.12),
                  velZ: -this.vz * (0.1 + Math.random()*0.12),
                  velY: 0.06 + Math.random()*0.1,
                  life: 20 + Math.floor(Math.random()*12)
                });
              }
              // Exit wound for gun level 3+ — large hole on back, massive high-velocity exit spray
              if (weapons.gun.level >= 3) {
                const exitX = enemy.mesh.position.x + this.vx * 1.2;
                const exitZ = enemy.mesh.position.z + this.vz * 1.2;
                const exitPos = { x: exitX, y: enemy.mesh.position.y, z: exitZ };
                // Large exit blood burst
                spawnParticles(exitPos, 0x8B0000, 5);
                spawnParticles(exitPos, 0xCC0000, 4);
                spawnBloodDecal(exitPos);
                // 2-4 meter trail of high-velocity droplets behind enemy
                const trailLen = 2 + Math.floor(Math.random() * 3); // 2-4 meters (segments)
                for (let tl = 0; tl < trailLen && bloodDrips.length < MAX_BLOOD_DRIPS; tl++) {
                  const trailFrac = (tl + 1) / trailLen;
                  const tvx = this.vx * (0.35 + trailFrac * 0.35);
                  const tvz = this.vz * (0.35 + trailFrac * 0.35);
                  const tp = new THREE.Mesh(
                    new THREE.SphereGeometry(0.03 + Math.random()*0.035, 4, 4),
                    new THREE.MeshBasicMaterial({ color: tl % 2 === 0 ? 0xAA0000 : 0x880000 })
                  );
                  tp.position.set(exitX + (Math.random()-0.5)*0.3, enemy.mesh.position.y + 0.15, exitZ + (Math.random()-0.5)*0.3);
                  scene.add(tp);
                  bloodDrips.push({
                    mesh: tp,
                    velX: tvx + (Math.random()-0.5)*0.08,
                    velZ: tvz + (Math.random()-0.5)*0.08,
                    velY: 0.12 + Math.random() * 0.2,
                    life: 35 + Math.floor(Math.random()*20)
                  });
                  // Medium blood pools along the trail
                  if (tl % 2 === 0) spawnBloodDecal({ x: exitX + this.vx*(tl*0.7), y: 0, z: exitZ + this.vz*(tl*0.7) });
                }
                // Larger exit hole decal on back face
                if (!enemy.bulletHoles) enemy.bulletHoles = [];
                if (enemy.bulletHoles.length < 12) {
                  const exitHole = new THREE.Mesh(
                    new THREE.CircleGeometry(0.12 + Math.random()*0.08, 8),
                    new THREE.MeshStandardMaterial({ color: 0x1A0000, roughness: 0.3, metalness: 0.2, transparent: true, opacity: 0.9, side: THREE.DoubleSide, depthWrite: false })
                  );
                  // Place on the exit (back) face
                  const bMag = Math.sqrt(this.vx*this.vx + this.vz*this.vz);
                  const backNx = this.vx / bMag;
                  const backNz = this.vz / bMag;
                  exitHole.position.set(backNx*0.52, (Math.random()-0.5)*0.3, backNz*0.52);
                  exitHole.lookAt(new THREE.Vector3(backNx*2, exitHole.position.y*2, backNz*2));
                  enemy.mesh.add(exitHole);
                  enemy.bulletHoles.push(exitHole);
                }
              }
            }
            // ── End weapon-specific hit effects ──────────────────────────────────
            
            // Water splash effect on hit
            spawnParticles(enemy.mesh.position, COLORS.player, 5);
            spawnParticles(enemy.mesh.position, 0xFFFFFF, 3);
            
            // Mark this enemy as hit
            this.hitEnemies.add(enemy);
            
            // Check if bullet should be destroyed or continue piercing
            if (this.hitEnemies.size >= this.maxHits) {
              // Hit maximum number of enemies, destroy bullet
              this.destroy();
              playSound('hit');
              break;
            } else {
              // Continue piercing (haven't reached max hits yet)
              // Exit blood spray — blood flies out from the exit side
              const exitX = enemy.mesh.position.x + this.vx * 0.8;
              const exitZ = enemy.mesh.position.z + this.vz * 0.8;
              const exitPos = { x: exitX, y: enemy.mesh.position.y, z: exitZ };
              spawnParticles(exitPos, 0x8B0000, 6);
              spawnParticles(exitPos, 0xCC0000, 4);
              spawnBloodDecal(exitPos);
              // Level 3+ gun: massive exit wound with spray and stacking pools
              const gunLevel = weapons.gun ? (weapons.gun.level || 1) : 1;
              if (gunLevel >= 3 && window.BloodSystem) {
                const exitVec = new THREE.Vector3(exitPos.x, exitPos.y, exitPos.z);
                const bulletDir = new THREE.Vector3(this.vx, 0, this.vz).normalize();
                // Blood rapidly sprays out the back (exit hole) in drops, 2-4m trails
                const exitCount = 40 + (gunLevel - 3) * 20; // Scales with level: 40/60/80
                window.BloodSystem.emitExitWound(exitVec, bulletDir, exitCount, { spread: 0.6, speed: 0.4 });
                // Track hit count on enemy for stacking (each hit adds more spray, capped at 3)
                enemy._exitWoundCount = Math.min((enemy._exitWoundCount || 0) + 1, 3);
                if (enemy._exitWoundCount > 1 && window.BloodSystem) {
                  // Stacking: additional burst per wound, using fixed multiplier (no unbounded growth)
                  window.BloodSystem.emitExitWound(exitVec, bulletDir, exitCount, { spread: 0.5, speed: 0.35 });
                }
                // Extra blood decals for 2-4m trail scatter
                for (let tl = 0; tl < 6; tl++) {
                  const trailDist = 0.5 + Math.random() * 3.5; // 0.5-4m range
                  spawnBloodDecal({ x: exitX + this.vx * trailDist + (Math.random()-0.5)*0.4, y: 0, z: exitZ + this.vz * trailDist + (Math.random()-0.5)*0.4 });
                }
              } else {
                // Airborne exit blood (standard gun <3)
                for (let eb = 0; eb < 3 && bloodDrips.length < MAX_BLOOD_DRIPS; eb++) {
                  const bp = new THREE.Mesh(
                    new THREE.SphereGeometry(0.03 + Math.random() * 0.03, 4, 4),
                    new THREE.MeshBasicMaterial({ color: 0xAA0000 })
                  );
                  bp.position.set(exitX + (Math.random() - 0.5) * 0.3, enemy.mesh.position.y + 0.1, exitZ + (Math.random() - 0.5) * 0.3);
                  scene.add(bp);
                  bloodDrips.push({ mesh: bp, velY: 0.12 + Math.random() * 0.15, life: 25 + Math.floor(Math.random() * 10) });
                }
              }
              playSound('hit');
              // Don't break - allow bullet to continue
            }
          }
        }
        
        // FRESH IMPLEMENTATION: Destructible Props Collision
        if (window.destructibleProps) {
          for (let prop of window.destructibleProps) {
            if (prop.destroyed) continue;
            const dx = this.mesh.position.x - prop.mesh.position.x;
            const dz = this.mesh.position.z - prop.mesh.position.z;
            if (dx*dx + dz*dz < 1.5) { // Hit radius for props
              // Calculate damage (use base weapon damage)
              let dmg = weapons.gun.damage * playerStats.damage * playerStats.strength * 0.5; // Half damage to props
              
              if (weapons.doubleBarrel.active && this.isDoubleBarrel) {
                dmg = weapons.doubleBarrel.damage * playerStats.damage * playerStats.strength * 0.5;
              }
              
              if (weapons.droneTurret.active && this.isDroneTurret) {
                dmg = weapons.droneTurret.damage * playerStats.damage * playerStats.strength * 0.5;
              }
              
              prop.hp -= dmg;
              
              // Visual damage stages (5 stages for better destruction feel)
              const hpPercent = prop.hp / prop.maxHp;
              
              if (hpPercent <= 0.8 && hpPercent > 0.6 && !prop.damageStage1) {
                // Stage 1 (80% HP): Slight crack — small lean and sway increase
                prop.damageStage1 = true;
                if (prop.type === 'tree') {
                  prop.mesh.userData.swayAmount = Math.min(0.2, (prop.mesh.userData.swayAmount || 0.05) + 0.08);
                  prop.mesh.rotation.z = 0.05;
                }
              } else if (hpPercent <= 0.6 && hpPercent > 0.4 && !prop.darkenedStage1) {
                // Stage 2 (60% HP): Visible damage — darken slightly
                prop.darkenedStage1 = true;
                if (prop.type === 'tree') {
                  prop.mesh.userData.trunk.material.color.copy(prop.originalColor.trunk).multiplyScalar(0.85);
                  prop.mesh.userData.leaves.material.color.copy(prop.originalColor.leaves).multiplyScalar(0.75);
                  prop.mesh.userData.swayAmount = Math.min(0.3, (prop.mesh.userData.swayAmount || 0.05) + 0.12);
                } else {
                  prop.mesh.material.color.copy(prop.originalColor).multiplyScalar(0.8);
                }
              } else if (hpPercent <= 0.4 && hpPercent > 0.2 && !prop.damageStage3) {
                // Stage 3 (40% HP): Heavy damage — major lean, lose leaves
                prop.damageStage3 = true;
                if (prop.type === 'tree') {
                  prop.mesh.userData.trunk.material.color.copy(prop.originalColor.trunk).multiplyScalar(0.65);
                  if (prop.mesh.userData.leaves) prop.mesh.userData.leaves.scale.set(0.6, 0.6, 0.6);
                  prop.mesh.rotation.z = 0.15 * (Math.random() < 0.5 ? 1 : -1);
                } else {
                  prop.mesh.material.color.copy(prop.originalColor).multiplyScalar(0.6);
                  prop.mesh.scale.copy(prop.originalScale).multiplyScalar(0.85);
                }
                spawnParticles(prop.mesh.position, 0x8B4513, 6);
              } else if (hpPercent <= 0.2 && hpPercent > 0 && !prop.darkenedStage2) {
                // Stage 4 (20% HP): Near destruction — major shrink, very dark
                prop.darkenedStage2 = true;
                if (prop.type === 'tree') {
                  prop.mesh.userData.trunk.material.color.copy(prop.originalColor.trunk).multiplyScalar(0.4);
                  if (prop.mesh.userData.leaves) prop.mesh.userData.leaves.visible = false;
                  prop.mesh.rotation.z = 0.3 * (prop.mesh.rotation.z >= 0 ? 1 : -1);
                } else {
                  prop.mesh.material.color.copy(prop.originalColor).multiplyScalar(0.4);
                }
                prop.mesh.scale.copy(prop.originalScale).multiplyScalar(0.8);
                spawnParticles(prop.mesh.position, 0x8B4513, 10);
              } else if (prop.hp <= 0) {
                // Stage 5 (0 HP): Destroy with debris
                prop.destroyed = true;
                
                // Explosion effect based on type
                if (prop.type === 'barrel') {
                  // Barrel explodes
                  spawnParticles(prop.mesh.position, 0xFF4500, 30); // Orange explosion
                  spawnParticles(prop.mesh.position, 0xFFFF00, 15); // Yellow fire
                  playSound('hit');
                  // Barrel removed from scene
                  scene.remove(prop.mesh);
                  prop.mesh.geometry.dispose();
                  prop.mesh.material.dispose();
                } else if (prop.type === 'tree') {
                  // Tree falls and remains as debris (does not disappear)
                  spawnParticles(prop.mesh.position, 0x8B4513, 20); // Brown wood
                  spawnParticles(prop.mesh.position, 0x228B22, 15); // Green leaves
                  // Animate tree falling — rotate to ground and stay as debris
                  const fallDir = Math.random() < 0.5 ? 1 : -1;
                  const fallAxis = Math.random() < 0.5 ? 'x' : 'z';
                  const fallDuration = 600;
                  const fallStart = Date.now();
                  // Hide leaves to simulate them scattering, trunk remains as log
                  if (prop.mesh.userData.leaves) {
                    prop.mesh.userData.leaves.visible = false;
                  }
                  const treeMesh = prop.mesh;
                  if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
                    let treeFallTimer = 0;
                    const treeFallFrames = Math.ceil(fallDuration / 16); // ~37 frames
                    managedAnimations.push({ update(_dt) {
                      treeFallTimer++;
                      const progress = Math.min(treeFallTimer / treeFallFrames, 1);
                      const angle = (Math.PI / 2) * progress * fallDir;
                      if (fallAxis === 'x') {
                        treeMesh.rotation.x = angle;
                      } else {
                        treeMesh.rotation.z = angle;
                      }
                      treeMesh.position.y = -progress * 1.5; // Sink slightly into ground
                      if (progress >= 1) {
                        // Tree stays as fallen log debris — never removed
                        return false;
                      }
                      return true;
                    }});
                  }
                } else if (prop.type === 'crate') {
                  // Crate breaks apart and is removed
                  spawnParticles(prop.mesh.position, 0xD2691E, 20); // Wood particles
                  scene.remove(prop.mesh);
                  prop.mesh.geometry.dispose();
                  prop.mesh.material.dispose();
                }
              } else {
                // Tree movement on hit (shake/sway from impact)
                if (prop.type === 'tree' && prop.mesh.userData.swayPhase !== undefined) {
                  // Add extra sway from bullet impact
                  prop.mesh.userData.swayAmount = Math.min(0.3, prop.mesh.userData.swayAmount + 0.1);
                  // Gradually reduce sway back to normal
                  setTimeout(() => {
                    if (!prop.destroyed && prop.mesh.userData.swayAmount) {
                      prop.mesh.userData.swayAmount = Math.max(0.05, prop.mesh.userData.swayAmount - 0.05);
                    }
                  }, 500);
                }
              }
              
              // Small particle effect on hit
              spawnParticles(prop.mesh.position, 0x888888, 3);
              
              this.destroy();
              break;
            }
          }
        }
        
        // FRESH: Fence collision - fences can be damaged and broken by bullets
        if (window.breakableFences) {
          for (let fence of window.breakableFences) {
            if (!fence.userData.isFence || fence.userData.hp <= 0) continue;
            const dx = this.mesh.position.x - fence.position.x;
            const dz = this.mesh.position.z - fence.position.z;
            if (dx*dx + dz*dz < 1.5) { // Hit radius
              // Damage fence
              const dmg = weapons.gun.damage * 0.3; // Fences take less damage
              fence.userData.hp -= dmg;
              
              // Shake effect on hit
              fence.rotation.x = (Math.random() - 0.5) * 0.3;
              fence.rotation.z = (Math.random() - 0.5) * 0.3;
              
              // Visual damage
              const hpPercent = fence.userData.hp / fence.userData.maxHp;
              if (hpPercent < 0.5) {
                fence.material.color.setHex(0x654321); // Darken when damaged
              }
              
              if (fence.userData.hp <= 0) {
                // Fence broken! Create debris
                spawnParticles(fence.position, 0x8B4513, 15); // Brown wood debris
                spawnParticles(fence.position, 0x654321, 10);
                
                // Animate fence falling
                const fallDirection = Math.random() < 0.5 ? 1 : -1;
                const startRotX = fence.rotation.x;
                const fallDuration = 500;
                const fallStart = Date.now();
                
                const fenceFallFrames = Math.ceil(fallDuration / 16); // ~31 frames
                const fenceRef = fence;
                if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
                  let fenceFallTimer = 0;
                  managedAnimations.push({ update(_dt) {
                    fenceFallTimer++;
                    const progress = Math.min(fenceFallTimer / fenceFallFrames, 1);
                    fenceRef.rotation.x = startRotX + (Math.PI / 2) * progress * fallDirection;
                    fenceRef.position.y = 1 - progress * 0.8; // Sink down
                    
                    if (progress >= 1) {
                      scene.remove(fenceRef);
                      fenceRef.geometry.dispose();
                      fenceRef.material.dispose();
                      return false;
                    }
                    return true;
                  }});
                } else {
                  scene.remove(fenceRef);
                  fenceRef.geometry.dispose();
                  fenceRef.material.dispose();
                }
              }
              
              // Bullet destroyed on fence hit
              this.destroy();
              playSound('hit');
              break;
            }
          }
        }
        return this.active;
      }

      destroy() {
        this.active = false;
        scene.remove(this.mesh);
        // Dispose cloned materials (not geometry, which is shared)
        if (this.mesh.material) {
          this.mesh.material.dispose();
        }
        
        // Remove glow if it exists
        if (this.glow) {
          scene.remove(this.glow);
          // Dispose cloned glow material
          if (this.glow.material) {
            this.glow.material.dispose();
          }
        }
      }
    }

    class SwordSlash {
      constructor(x, z, angle) {
        // Thinner arc geometry for flowing blade effect
        const geometry = new THREE.RingGeometry(1.8, 2.2, 12, 1, -Math.PI/4, Math.PI/2);
        const material = new THREE.MeshBasicMaterial({ color: 0xCCDDFF, side: THREE.DoubleSide, transparent: true, opacity: 0.9 });
        this.mesh = new THREE.Mesh(geometry, material);
        this.mesh.rotation.x = -Math.PI / 2;
        this.mesh.rotation.z = angle - Math.PI/4;
        this.mesh.position.set(x, 0.6, z);
        scene.add(this.mesh);
        
        this.life = 12; // frames — slightly longer for smoother fade
        this.maxLife = 12;
        
        // Deal damage immediately
        const dmg = weapons.sword.damage * playerStats.strength * playerStats.damage;
        
        enemies.forEach(e => {
          const dx = e.mesh.position.x - x;
          const dz = e.mesh.position.z - z;
          const dist = Math.sqrt(dx*dx + dz*dz);
          
          if (dist < 3.5) {
            // Check angle
            const eAngle = Math.atan2(dz, dx); // -PI to PI
            // Normalize angles
            let diff = eAngle - angle;
            while (diff < -Math.PI) diff += Math.PI*2;
            while (diff > Math.PI) diff -= Math.PI*2;
            
            if (Math.abs(diff) < Math.PI/3) {
              e.takeDamage(dmg);
            }
          }
        });
      }
      
      update() {
        this.life--;
        const progress = 1 - (this.life / this.maxLife);
        // Smooth ease-out fade with slight scale expansion for flowing feel
        this.mesh.material.opacity = 0.9 * Math.pow(this.life / this.maxLife, 1.5);
        this.mesh.scale.set(1 + progress * 0.15, 1 + progress * 0.15, 1);
        if (this.life <= 0) {
          scene.remove(this.mesh);
          this.mesh.geometry.dispose();
          this.mesh.material.dispose();
          return false;
        }
        return true;
      }
    }

    class IceSpear {
      constructor(x, z, target) {
        // Ice shard — elongated octahedron for a crystalline look (4-sided cone approximation)
        const geometry = new THREE.ConeGeometry(0.12, 0.7, 4);
        // Bright ice-blue with high emissive so it stands out visually
        const material = new THREE.MeshStandardMaterial({
          color: 0xAEEEFF,
          emissive: 0x005577,
          emissiveIntensity: 0.8,
          transparent: true,
          opacity: 0.95,
          metalness: 0.3,
          roughness: 0.1
        });
        this.mesh = new THREE.Mesh(geometry, material);
        this.mesh.scale.set(1, 3, 1); // Elongated ice shard
        this.mesh.position.set(x, 0.5, z);
        scene.add(this.mesh);

        // Small glow light that travels with the shard
        this.light = new THREE.PointLight(0x88DDFF, 2.5, 5);
        this.light.position.copy(this.mesh.position);
        scene.add(this.light);

        this.speed = 0.42; // Slightly faster — ice shards fly fast
        this.active = true;
        this.life = 70; // Frames - longer range than normal projectile

        // Calculate direction
        const dx = target.x - x;
        const dz = target.z - z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        this.vx = (dx / dist) * this.speed;
        this.vz = (dz / dist) * this.speed;
        
        // Rotate shard to face direction of travel
        this.mesh.rotation.z = -Math.atan2(dz, dx) + Math.PI/2;
        this.mesh.rotation.x = Math.PI/2;
        
        // Trailing particles
        this.particleTimer = 0;

        // Spawn initial burst of ice chips from the "firing" point
        spawnParticles(this.mesh.position, 0xCCEEFF, 4);
        spawnParticles(this.mesh.position, 0xFFFFFF, 2);
      }

      update() {
        if (!this.active) return false;
        
        this.mesh.position.x += this.vx;
        this.mesh.position.z += this.vz;
        // Keep light in sync with shard
        this.light.position.copy(this.mesh.position);
        this.life--;
        
        // Denser ice trail — small ice chips flying off
        this.particleTimer++;
        if (this.particleTimer % 2 === 0) {
          spawnParticles(this.mesh.position, 0xAEEEFF, 1);
        }
        if (this.particleTimer % 5 === 0) {
          spawnParticles(this.mesh.position, 0xFFFFFF, 1); // White frost fleck
        }

        if (this.life <= 0) {
          this.destroy();
          return false;
        }

        // Collision Check
        for (let enemy of enemies) {
          if (enemy.isDead) continue;
          const dx = this.mesh.position.x - enemy.mesh.position.x;
          const dz = this.mesh.position.z - enemy.mesh.position.z;
          if (dx*dx + dz*dz < 0.6) {
            let dmg = weapons.iceSpear.damage * playerStats.damage * playerStats.strength;
            // Apply ice damage bonus from skills
            if (playerStats.iceDamage > 0 || playerStats.elementalDamage > 0) {
              dmg *= (1 + (playerStats.iceDamage || 0) + (playerStats.elementalDamage || 0));
            }
            const isCrit = Math.random() < playerStats.critChance;
            if (isCrit) dmg *= playerStats.critDmg;
            
            // Ice Spear: if enemy is already frozen, deal +100% bonus damage and shatter ice
            const wasAlreadyFrozen = enemy.isFrozen;
            if (wasAlreadyFrozen) {
              dmg *= 2; // +100% damage on frozen enemy
              // Shatter: large ice chunks fly outward and water pools form on ground
              spawnParticles(enemy.mesh.position, 0xAEEEFF, 6);
              spawnParticles(enemy.mesh.position, 0xCCEEFF, 5);
              spawnParticles(enemy.mesh.position, 0xFFFFFF, 4);
              // Large ice chunk blobs flying outward
              for (let ic = 0; ic < 5 && bloodDrips.length < MAX_BLOOD_DRIPS; ic++) {
                const chunkSize = 0.07 + Math.random() * 0.09;
                const chunk = new THREE.Mesh(
                  new THREE.DodecahedronGeometry(chunkSize, 0),
                  new THREE.MeshStandardMaterial({ color: 0xAEEEFF, transparent: true, opacity: 0.85, roughness: 0.3, metalness: 0.2 })
                );
                chunk.position.copy(enemy.mesh.position);
                scene.add(chunk);
                bloodDrips.push({
                  mesh: chunk,
                  velX: (Math.random() - 0.5) * 0.3,
                  velZ: (Math.random() - 0.5) * 0.3,
                  velY: 0.18 + Math.random() * 0.25,
                  life: 40 + Math.floor(Math.random() * 20),
                  isIce: true
                });
              }
              // Water pool from melting ice at enemy feet
              spawnBloodDecal({ x: enemy.mesh.position.x + (Math.random()-0.5)*0.5, y: 0, z: enemy.mesh.position.z + (Math.random()-0.5)*0.5 });
              spawnBloodDecal({ x: enemy.mesh.position.x + (Math.random()-0.5)*0.8, y: 0, z: enemy.mesh.position.z + (Math.random()-0.5)*0.8 });
            }
            
            enemy.takeDamage(Math.floor(dmg), isCrit, 'ice');
            
            // Freeze duration scales with ice spear level (base 2.5s, +0.5s per extra level)
            const freezeDur = 2500 + (weapons.iceSpear.level - 1) * 500;
            if (!enemy.isFrozen) {
              // Store original speed and color before first freeze
              if (!enemy._originalColor && enemy.mesh && enemy.mesh.material) {
                enemy._originalColor = enemy.mesh.material.color.clone();
              }
              if (!enemy.originalSpeed) enemy.originalSpeed = enemy.speed;
            }
            enemy.isFrozen = true;
            enemy.frozenUntil = Date.now() + freezeDur;
            enemy._freezeDuration = freezeDur; // Store for gradual visual transition
            // Freeze stops movement entirely — originalSpeed preserved for thaw
            enemy.speed = 0;
            // Visual: turn enemy icy blue with bright emissive; track freeze progress (0–1)
            if (enemy.mesh && enemy.mesh.material) {
              if (!enemy._freezeProgress) enemy._freezeProgress = 0;
              enemy._freezeProgress = Math.min(1, enemy._freezeProgress + 0.35);
              // Lerp from original color toward icy blue based on freeze progress
              const baseColor = enemy._originalColor || new THREE.Color(0xFFFFFF);
              const iceColor = new THREE.Color(0xB0E8FF);
              enemy.mesh.material.color.copy(baseColor).lerp(iceColor, enemy._freezeProgress);
              if (enemy.mesh.material.emissive !== undefined) {
                enemy.mesh.material.emissive = new THREE.Color(0x4488AA);
                enemy.mesh.material.emissiveIntensity = 0.3 + enemy._freezeProgress * 0.4;
              }
              // Ice crack overlay on body (small white/blue angular shapes)
              if (!enemy._iceCracks) enemy._iceCracks = [];
              if (enemy._iceCracks.length < 6) {
                const crackGeo = new THREE.PlaneGeometry(0.08 + Math.random()*0.12, 0.02 + Math.random()*0.04);
                const crackMat = new THREE.MeshBasicMaterial({ color: 0xFFFFFF, transparent: true, opacity: 0.55 + enemy._freezeProgress * 0.3, side: THREE.DoubleSide });
                const crack = new THREE.Mesh(crackGeo, crackMat);
                const theta = Math.random() * Math.PI * 2;
                const phi = Math.random() * Math.PI;
                crack.position.set(Math.sin(phi)*Math.cos(theta)*0.51, Math.sin(phi)*Math.sin(theta)*0.51, Math.cos(phi)*0.51);
                crack.lookAt(crack.position.clone().multiplyScalar(2));
                crack.rotation.z = Math.random() * Math.PI;
                enemy.mesh.add(crack);
                enemy._iceCracks.push(crack);
              }
              enemy.mesh.material.needsUpdate = true;
            }
            // Clear separate slow effect — freeze supersedes it
            enemy.slowedUntil = null;
            
            // Ice impact: shattered ice particles (not blood) on impact
            spawnParticles(enemy.mesh.position, 0xAEEEFF, 6);
            spawnParticles(enemy.mesh.position, 0xCCEEFF, 4);
            spawnParticles(enemy.mesh.position, 0xFFFFFF, 3);
            // Tiny ice shard fragments fly outward
            for (let is = 0; is < 3 && bloodDrips.length < MAX_BLOOD_DRIPS; is++) {
              const shardSize = 0.03 + Math.random() * 0.04;
              const shard = new THREE.Mesh(
                new THREE.TetrahedronGeometry(shardSize, 0),
                new THREE.MeshStandardMaterial({ color: 0xCCEEFF, transparent: true, opacity: 0.75, roughness: 0.2, metalness: 0.3 })
              );
              shard.position.copy(enemy.mesh.position);
              scene.add(shard);
              bloodDrips.push({
                mesh: shard,
                velX: (Math.random() - 0.5) * 0.18,
                velZ: (Math.random() - 0.5) * 0.18,
                velY: 0.1 + Math.random() * 0.15,
                life: 25 + Math.floor(Math.random() * 15),
                isIce: true
              });
            }
            
            // Minimal knockback (freeze compensates — less push than gun)
            const kbForce = 0.15;
            enemy.mesh.position.x += this.vx * kbForce;
            enemy.mesh.position.z += this.vz * kbForce;
            
            this.destroy();
            playSound('hit');
            break;
          }
        }
        return true;
      }

      destroy() {
        this.active = false;
        scene.remove(this.mesh);
        this.mesh.geometry.dispose();
        this.mesh.material.dispose();
        // Remove the glow light that travels with the shard
        if (this.light) {
          scene.remove(this.light);
          this.light = null;
        }
      }
    }

    class Meteor {
      constructor(targetX, targetZ) {
        this.target = new THREE.Vector3(targetX, 0, targetZ);
        
        // Falling sphere
        const geo = new THREE.DodecahedronGeometry(1.5);
        const mat = new THREE.MeshToonMaterial({ color: 0xFF4500, emissive: 0x8B0000 });
        this.mesh = new THREE.Mesh(geo, mat);
        this.mesh.position.set(targetX, 20, targetZ);
        scene.add(this.mesh);
        
        // Shadow indicator
        const shadowGeo = new THREE.CircleGeometry(2.5, 16);
        const shadowMat = new THREE.MeshBasicMaterial({ color: 0x000000, opacity: 0.3, transparent: true });
        this.shadow = new THREE.Mesh(shadowGeo, shadowMat);
        this.shadow.rotation.x = -Math.PI/2;
        this.shadow.position.set(targetX, 0.1, targetZ);
        scene.add(this.shadow);
        
        this.speed = 0.5;
        this.active = true;
      }
      
      update() {
        if (!this.active) return false;
        
        this.mesh.position.y -= this.speed;
        this.speed += 0.05; // Gravity
        
        if (this.mesh.position.y <= 0) {
          this.explode();
          return false;
        }
        return true;
      }
      
      explode() {
        this.active = false;
        scene.remove(this.mesh);
        scene.remove(this.shadow);
        this.mesh.geometry.dispose();
        this.mesh.material.dispose();
        this.shadow.geometry.dispose();
        this.shadow.material.dispose();
        
        // AOE Damage with knockback
        const range = weapons.meteor.area;
        const dmg = weapons.meteor.damage * playerStats.strength;
        
        enemies.forEach(e => {
          const d = e.mesh.position.distanceTo(this.target);
          if (d < range) {
            e.takeDamage(dmg);
            
            // Apply knockback to enemies
            const knockbackDir = new THREE.Vector3(
              e.mesh.position.x - this.target.x,
              0,
              e.mesh.position.z - this.target.z
            ).normalize();
            
            // Knockback strength inversely proportional to distance
            const knockbackStrength = (1 - d / range) * GAME_CONFIG.meteorKnockbackMultiplier;
            e.mesh.position.x += knockbackDir.x * knockbackStrength;
            e.mesh.position.z += knockbackDir.z * knockbackStrength;
            
            // Add visual bounce effect
            const originalY = e.mesh.position.y;
            e.mesh.position.y = originalY + 0.5 * (1 - d / range);
            setTimeout(() => {
              e.mesh.position.y = originalY;
            }, 200);
          }
        });
        
        // Enhanced visuals — visible explosion ring + debris
        spawnParticles(this.target, 0xFF4500, 8);
        spawnParticles(this.target, 0xFFFF00, 4);
        spawnParticles(this.target, 0xFF8C00, 6);
        spawnMuzzleSmoke(this.target, 10);

        // Explosion shockwave ring — expands outward and fades
        const ringGeo = new THREE.RingGeometry(0.2, 0.6, 24);
        const ringMat = new THREE.MeshBasicMaterial({ color: 0xFF6600, transparent: true, opacity: 0.9, side: THREE.DoubleSide, depthWrite: false });
        const ring = new THREE.Mesh(ringGeo, ringMat);
        ring.rotation.x = -Math.PI / 2;
        ring.position.set(this.target.x, 0.08, this.target.z);
        scene.add(ring);
        let ringLife = 25;
        if (managedAnimations.length < MAX_MANAGED_ANIMATIONS) {
          managedAnimations.push({ update(_dt) {
            ringLife--;
            const scale = 1 + (1 - ringLife / 25) * (weapons.meteor.area / 1.5);
            ring.scale.set(scale, scale, scale);
            ring.material.opacity = (ringLife / 25) * 0.9;
            if (ringLife <= 0) { scene.remove(ring); ring.geometry.dispose(); ring.material.dispose(); return false; }
            return true;
          }});
        } else {
          scene.remove(ring); ring.geometry.dispose(); ring.material.dispose();
        }
        
        // Camera shake for explosion
        const shakeIntensity = GAME_CONFIG.explosionShakeIntensity;
        const originalCameraPos = camera.position.clone();
        let shakeTime = 0;
        const shakeDuration = 0.3;
        
        const shakeAnim = () => {
          shakeTime += 0.016;
          if (shakeTime < shakeDuration) {
            const intensity = (1 - shakeTime / shakeDuration) * shakeIntensity;
            camera.position.x = originalCameraPos.x + (Math.random() - 0.5) * intensity;
            camera.position.y = originalCameraPos.y + (Math.random() - 0.5) * intensity;
            camera.position.z = originalCameraPos.z + (Math.random() - 0.5) * intensity;
            requestAnimationFrame(shakeAnim);
          } else {
            camera.position.copy(originalCameraPos);
          }
        };
        shakeAnim();
        
        playSound('meteor'); // Explosive boom sound
      }
    }

    // Phase 5: Object Pooling System for Particles (Performance Critical)
    class ObjectPool {
      constructor(createFn, resetFn, initialSize = 100) {
        this.createFn = createFn;
        this.resetFn = resetFn;
        this.pool = [];
        this.activeSet = new Set(); // Use Set for O(1) lookups instead of array
        
        // Pre-allocate initial pool
        for (let i = 0; i < initialSize; i++) {
          this.pool.push(this.createFn());
        }
      }
      
      get() {
        let obj;
        if (this.pool.length > 0) {
          obj = this.pool.pop();
        } else {
          obj = this.createFn();
        }
        this.activeSet.add(obj);
        return obj;
      }
      
      release(obj) {
        if (this.activeSet.has(obj)) {
          this.activeSet.delete(obj);
          this.resetFn(obj);
          this.pool.push(obj);
        }
      }
      
      clear() {
        // Clean up all objects
        for (const obj of this.activeSet) {
          if (obj.mesh && obj.mesh.parent) {
            scene.remove(obj.mesh);
          }
        }
        this.activeSet.clear();
      }
    }

    class Particle {
      static MAX_LIFETIME = 28; // Lifetime in frames before removal
      static INITIAL_OPACITY = 0.92; // Maximum opacity for particles
      static VEL_XZ_RANGE = 0.35; // Horizontal velocity spread
      static VEL_Y_MIN = 0.08;    // Minimum upward velocity
      static VEL_Y_RANGE = 0.5;   // Additional random upward velocity
      
      constructor(pos, color) {
        const geo = new THREE.BoxGeometry(0.06, 0.06, 0.06);
        const mat = new THREE.MeshStandardMaterial({ 
          color: color,
          transparent: true,
          opacity: Particle.INITIAL_OPACITY,
          emissive: color,
          emissiveIntensity: 0.5,
          roughness: 0.5,
          metalness: 0.15
        });
        this.mesh = new THREE.Mesh(geo, mat);
        this.mesh.position.copy(pos);
        
        this.vel = new THREE.Vector3(
          (Math.random() - 0.5) * Particle.VEL_XZ_RANGE,
          Particle.VEL_Y_MIN + Math.random() * Particle.VEL_Y_RANGE,
          (Math.random() - 0.5) * Particle.VEL_XZ_RANGE
        );
        
        scene.add(this.mesh);
        this.life = Particle.MAX_LIFETIME;
      }
      
      reset(pos, color) {
        // Reuse existing particle
        this.mesh.position.copy(pos);
        this.mesh.material.color.setHex(color);
        this.mesh.material.emissive.setHex(color);
        // Blood particles (dark red) get smaller, faster, more splatter-like behavior
        const isBlood = (color === 0x8B0000 || color === 0x6B0000);
        const velScale = isBlood ? 1.5 : 1.0;
        this.vel.set(
          (Math.random() - 0.5) * Particle.VEL_XZ_RANGE * velScale,
          (isBlood ? 0.05 : Particle.VEL_Y_MIN) + Math.random() * Particle.VEL_Y_RANGE * (isBlood ? 0.5 : 1.0),
          (Math.random() - 0.5) * Particle.VEL_XZ_RANGE * velScale
        );
        // Blood particles should be smaller scale
        const sizeScale = isBlood ? 0.4 + Math.random() * 0.4 : 1.0;
        this.mesh.scale.setScalar(sizeScale);
        this.mesh.rotation.set(0, 0, 0);
        this.mesh.visible = true;
        scene.add(this.mesh);
        this.life = isBlood ? Math.floor(Particle.MAX_LIFETIME * 0.6) : Particle.MAX_LIFETIME;
      }
      
      update() {
        this.life--;
        this.mesh.position.add(this.vel);
        this.vel.y -= 0.02; // Gravity
        this.mesh.rotation.x += 0.1;
        this.mesh.rotation.y += 0.1;
        
        // Fade out based on life remaining (more realistic smoke/fog effect)
        this.mesh.material.opacity = (this.life / Particle.MAX_LIFETIME) * Particle.INITIAL_OPACITY;
        
        if (this.mesh.position.y < 0) {
          this.mesh.position.y = 0;
          this.vel.y = 0;
          this.vel.x *= 0.8;
          this.vel.z *= 0.8;
        }
        
        if (this.life <= 0) {
          scene.remove(this.mesh);
          this.mesh.visible = false;
          this.mesh.scale.setScalar(1); // Reset scale for pool reuse
          return false;
        }
        return true;
      }
      
      dispose() {
        // Only called on final cleanup
        if (this.mesh) {
          scene.remove(this.mesh);
          this.mesh.geometry.dispose();
          this.mesh.material.dispose();
        }
      }
    }

    // Shared star geometry for all ExpGem instances (created once, reused for performance)
    let _expGemStarGeometry = null;
    let _expGemStarMaterial = null;
    let _expGemOutlineGeometry = null; // Shared outline geometry (created once, reused for performance)

    class ExpGem {
      constructor(x, z) {
        // Use shared star geometry (created once)
        if (!_expGemStarGeometry) {
          const starPoints = 5;
          const outerR = 0.28;
          const innerR = 0.12;
          const starShape = new THREE.Shape();
          for (let i = 0; i < starPoints * 2; i++) {
            const angle = (i / (starPoints * 2)) * Math.PI * 2 - Math.PI / 2;
            const r = i % 2 === 0 ? outerR : innerR;
            if (i === 0) starShape.moveTo(Math.cos(angle) * r, Math.sin(angle) * r);
            else starShape.lineTo(Math.cos(angle) * r, Math.sin(angle) * r);
          }
          starShape.closePath();
          const extrudeSettings = { depth: 0.10, bevelEnabled: true, bevelSize: 0.03, bevelThickness: 0.03, bevelSegments: 2 };
          _expGemStarGeometry = new THREE.ExtrudeGeometry(starShape, extrudeSettings);
          _expGemStarGeometry.center();
          _expGemStarMaterial = new THREE.MeshPhysicalMaterial({
            color: 0x5DADE2,      // Match XP bar color exactly (#5DADE2)
            emissive: 0x2E86C1,   // Blue emissive glow matching XP bar
            emissiveIntensity: 0.4,
            metalness: 0.3,
            roughness: 0.05,
            clearcoat: 1.0,        // Glass-like shine layer
            clearcoatRoughness: 0.05,
            reflectivity: 0.8
          });
        }

        // Each gem gets its own material clone for per-instance emissive animation
        const starMaterial = _expGemStarMaterial.clone();

        this.mesh = new THREE.Mesh(_expGemStarGeometry, starMaterial);
        this.mesh.position.set(x, 0.5, z);

        // SM64-style: add black outline ring and yellow-edge highlight using a slightly larger dark mesh
        // Outline geometry is shared across all ExpGem instances (created once)
        if (!_expGemOutlineGeometry) {
          const s = new THREE.Shape();
          const pts = 5, outerO = 0.33, innerO = 0.14;
          for (let i = 0; i < pts * 2; i++) {
            const ang = (i / (pts * 2)) * Math.PI * 2 - Math.PI / 2;
            const r = i % 2 === 0 ? outerO : innerO;
            if (i === 0) s.moveTo(Math.cos(ang) * r, Math.sin(ang) * r);
            else s.lineTo(Math.cos(ang) * r, Math.sin(ang) * r);
          }
          s.closePath();
          _expGemOutlineGeometry = new THREE.ExtrudeGeometry(s, { depth: 0.08, bevelEnabled: false });
          _expGemOutlineGeometry.center();
        }
        const outlineMat = new THREE.MeshBasicMaterial({ color: 0x000000 });
        const outlineMesh = new THREE.Mesh(_expGemOutlineGeometry, outlineMat);
        outlineMesh.position.z = -0.01;
        this._outlineMat = outlineMat; // Store per-instance material for disposal
        this.mesh.add(outlineMesh);
        
        // Black edge glow ring — thin, slightly larger than the star outline, glows subtly
        const glowRingMat = new THREE.MeshBasicMaterial({ color: 0x111111, transparent: true, opacity: 0.65 });
        const glowRingMesh = new THREE.Mesh(_expGemOutlineGeometry, glowRingMat);
        glowRingMesh.scale.set(1.08, 1.08, 0.5);
        glowRingMesh.position.z = -0.02;
        this._glowRingMat = glowRingMat;
        this.mesh.add(glowRingMesh);

        scene.add(this.mesh);

        this.active = true;
        // Spin fast on Y axis (star spinning over its axis as required)
        this.rotSpeedY = (Math.random() * 0.15 + 0.10) * (Math.random() < 0.5 ? 1 : -1);
        this.bobPhase = Math.random() * Math.PI * 2;
        this.sparklePhase = Math.random() * Math.PI * 2;
        this.value = GAME_CONFIG.expValue;
      }

      update(playerPos) {
        if (!this.active) return;

        // Spin star over its Y axis (fast)
        this.mesh.rotation.y += this.rotSpeedY;

        // Bob up and down
        this.bobPhase += 0.05;
        this.mesh.position.y = 0.5 + Math.sin(this.bobPhase) * 0.1;
        
        // Pulsing black edge glow — sync with star's emissive intensity
        this.sparklePhase += 0.1;
        const pulse = 0.35 + Math.sin(this.sparklePhase) * 0.25;
        this.mesh.material.emissiveIntensity = pulse;
        // Also pulse the black glow ring opacity
        if (this._glowRingMat) {
          this._glowRingMat.opacity = 0.45 + Math.sin(this.sparklePhase + 0.5) * 0.2;
        }

        // Magnet
        const dx = playerPos.x - this.mesh.position.x;
        const dz = playerPos.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        
        if (dist < magnetRange) { // Use magnetRange variable
          this.mesh.position.x += (dx / dist) * 0.3;
          this.mesh.position.z += (dz / dist) * 0.3;
          
          // Visual Trail when pulled - lighter blue particles (PR #117)
          if (Math.random() < 0.3) {
             spawnParticles(this.mesh.position, 0x4FC3F7, 1);
          }
        }

        if (dist < 0.8) { // Collect
          this.collect();
        }
      }

      collect() {
        this.active = false;
        
        // SPLASH EFFECT: use pooled particles to avoid per-gem geometry/material allocation
        // and eliminate 20 separate requestAnimationFrame callbacks per gem (PR #117)
        spawnParticles(this.mesh.position, 0x4FC3F7, 8);
        
        // Screen flash effect - lighter blue tint (PR #117)
        const flash = document.createElement('div');
        flash.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(79,195,247,0.18);pointer-events:none;z-index:500';
        document.body.appendChild(flash);
        setTimeout(() => flash.remove(), 100);
        
        scene.remove(this.mesh);
        // Geometry is shared across all ExpGem instances - do not dispose it
        this.mesh.material.dispose(); // Only dispose the per-instance cloned material
        if (this._outlineMat) this._outlineMat.dispose(); // Dispose per-instance outline material
        if (this._glowRingMat) this._glowRingMat.dispose(); // Dispose per-instance glow ring material
        
        addExp(this.value);
        playSound('collect');
      }
    }
    // Different gold drop types based on amount
    class GoldCoin {
      constructor(x, z, amount) {
        this.amount = amount;
        this.active = true;
        this.magnetRange = 4;
        this.collectRange = 0.8;
        this.vx = 0;
        this.vz = 0;
        this.wobblePhase = Math.random() * Math.PI * 2;
        this.bounceTime = 0;
        
        // Create appropriate visual based on amount
        if (amount >= 50) {
          // 50+ gold: Gold chest glowing from inside
          this.createGoldChest(x, z);
        } else if (amount >= 25) {
          // 25+ gold: Leather bag with knot
          this.createLeatherBag(x, z);
        } else if (amount >= 10) {
          // 10 coins: 3 spinning coins around center
          this.createMultipleCoins(x, z, 3);
        } else {
          // 5 coins: 1 spinning gold coin
          this.createSingleCoin(x, z);
        }
        
        // Play gold drop sound
        playSound('coinDrop');
        
        // Spawn sparkles on creation
        spawnParticles(this.mesh ? this.mesh.position : new THREE.Vector3(x, 0.3, z), 0xFFD700, 8);
        spawnParticles(this.mesh ? this.mesh.position : new THREE.Vector3(x, 0.3, z), 0xFFFFFF, 2);
      }
      
      createSingleCoin(x, z) {
        // Single large spinning coin
        const geometry = new THREE.CylinderGeometry(0.3, 0.3, 0.12, 16);
        const material = new THREE.MeshPhysicalMaterial({ 
          color: 0xFFD700,
          transparent: true,
          opacity: 0.95,
          metalness: 0.9,
          roughness: 0.1,
          emissive: 0xFFAA00,
          emissiveIntensity: 0.3
        });
        this.mesh = new THREE.Mesh(geometry, material);
        this.mesh.position.set(x, 0.4, z);
        this.mesh.rotation.x = Math.PI / 2;
        scene.add(this.mesh);
        this.type = 'single';
      }
      
      createMultipleCoins(x, z, count) {
        // Multiple coins orbiting around center
        this.coins = [];
        this.centerPos = new THREE.Vector3(x, 0.4, z);
        const radius = 0.4;
        
        for (let i = 0; i < count; i++) {
          const angle = (i / count) * Math.PI * 2;
          const geometry = new THREE.CylinderGeometry(0.25, 0.25, 0.1, 12);
          const material = new THREE.MeshPhysicalMaterial({ 
            color: 0xFFD700,
            transparent: true,
            opacity: 0.95,
            metalness: 0.9,
            roughness: 0.1,
            emissive: 0xFFAA00,
            emissiveIntensity: 0.3
          });
          const coin = new THREE.Mesh(geometry, material);
          coin.position.set(
            x + Math.cos(angle) * radius,
            0.4,
            z + Math.sin(angle) * radius
          );
          coin.rotation.x = Math.PI / 2;
          scene.add(coin);
          this.coins.push({ mesh: coin, angle: angle });
        }
        this.mesh = this.coins[0].mesh; // Reference for position
        this.type = 'multiple';
        this.orbitSpeed = 0.05;
      }
      
      createLeatherBag(x, z) {
        // Leather bag with knot - using sphere for bag, smaller sphere for knot
        const group = new THREE.Group();
        
        // Bag body
        const bagGeo = new THREE.SphereGeometry(0.35, 16, 16);
        bagGeo.scale(1, 1.2, 1); // Slightly taller
        const bagMat = new THREE.MeshPhysicalMaterial({ 
          color: 0x8B4513, // Brown leather
          transparent: true,
          opacity: 0.95,
          metalness: 0.1,
          roughness: 0.9
        });
        const bag = new THREE.Mesh(bagGeo, bagMat);
        bag.position.y = 0;
        group.add(bag);
        
        // Knot at top
        const knotGeo = new THREE.SphereGeometry(0.15, 8, 8);
        const knotMat = new THREE.MeshBasicMaterial({ color: 0x654321 }); // Darker brown
        const knot = new THREE.Mesh(knotGeo, knotMat);
        knot.position.y = 0.35;
        group.add(knot);
        
        // Gold coins texture (simple circles on the bag)
        const coinGeo = new THREE.CircleGeometry(0.08, 8);
        const coinMat = new THREE.MeshBasicMaterial({ 
          color: 0xFFD700,
          side: THREE.DoubleSide
        });
        for (let i = 0; i < 3; i++) {
          const coin = new THREE.Mesh(coinGeo, coinMat);
          const angle = (i / 3) * Math.PI * 2;
          coin.position.set(
            Math.cos(angle) * 0.25,
            -0.1 + Math.random() * 0.2,
            Math.sin(angle) * 0.25
          );
          coin.lookAt(group.position);
          group.add(coin);
        }
        
        group.position.set(x, 0.4, z);
        scene.add(group);
        this.mesh = group;
        this.type = 'bag';
      }
      
      createGoldChest(x, z) {
        // Gold chest glowing from inside
        const group = new THREE.Group();
        
        // Chest body
        const chestGeo = new THREE.BoxGeometry(0.5, 0.4, 0.4);
        const chestMat = new THREE.MeshPhysicalMaterial({ 
          color: 0xFFD700,
          transparent: true,
          opacity: 0.95,
          metalness: 0.9,
          roughness: 0.2,
          emissive: 0xFFD700,
          emissiveIntensity: 0.5
        });
        const chest = new THREE.Mesh(chestGeo, chestMat);
        chest.position.y = 0;
        group.add(chest);
        
        // Chest lid (slightly open)
        const lidGeo = new THREE.BoxGeometry(0.52, 0.1, 0.42);
        const lidMat = new THREE.MeshPhysicalMaterial({ 
          color: 0xDAA520, // Goldenrod
          metalness: 0.8,
          roughness: 0.3,
          emissive: 0xFFD700,
          emissiveIntensity: 0.3
        });
        const lid = new THREE.Mesh(lidGeo, lidMat);
        lid.position.set(0, 0.25, -0.1);
        lid.rotation.x = -0.3; // Slightly open
        group.add(lid);
        
        // Inner glow light
        const glowLight = new THREE.PointLight(0xFFD700, 2, 3);
        glowLight.position.set(0, 0.1, 0);
        group.add(glowLight);
        this.glowLight = glowLight;
        
        group.position.set(x, 0.4, z);
        scene.add(group);
        this.mesh = group;
        this.type = 'chest';
      }
      
      update(playerPos) {
        if (!this.active) return;
        
        // Type-specific animations
        if (this.type === 'single') {
          // Single coin spinning
          this.mesh.rotation.y += 0.15;
        } else if (this.type === 'multiple') {
          // Multiple coins orbiting and spinning
          this.coins.forEach((coinData, i) => {
            coinData.angle += this.orbitSpeed;
            const radius = 0.4;
            coinData.mesh.position.x = this.centerPos.x + Math.cos(coinData.angle) * radius;
            coinData.mesh.position.z = this.centerPos.z + Math.sin(coinData.angle) * radius;
            coinData.mesh.rotation.y += 0.15;
            
            // Update Y position for bouncing
            if (this.bounceTime < 1) {
              coinData.mesh.position.y = 0.4 + Math.abs(Math.sin(this.bounceTime * Math.PI * 3)) * 0.5 * (1 - this.bounceTime);
            } else {
              const baseY = 0.3;
              coinData.mesh.position.y = baseY + Math.sin(this.wobblePhase) * 0.1;
            }
          });
        } else if (this.type === 'bag') {
          // Bag swaying
          this.mesh.rotation.z = Math.sin(this.wobblePhase) * 0.1;
          this.wobblePhase += 0.05;
        } else if (this.type === 'chest') {
          // Chest glowing pulse
          if (this.glowLight) {
            this.glowLight.intensity = 2 + Math.sin(this.wobblePhase * 2) * 0.5;
          }
          this.wobblePhase += 0.05;
        }
        
        // Bounce physics on spawn (for single, bag, chest types)
        if (this.type !== 'multiple') {
          if (this.bounceTime < 1) {
            this.mesh.position.y = 0.4 + Math.abs(Math.sin(this.bounceTime * Math.PI * 3)) * 0.5 * (1 - this.bounceTime);
            this.bounceTime += 0.02;
          } else {
            // Wobble after bounce
            this.wobblePhase += 0.05;
            const baseY = this.type === 'chest' || this.type === 'bag' ? 0.4 : 0.3;
            this.mesh.position.y = baseY + Math.sin(this.wobblePhase) * 0.1;
          }
        } else {
          // Multiple coins handle bounce in their loop
          if (this.bounceTime < 1) {
            this.bounceTime += 0.02;
          } else {
            this.wobblePhase += 0.05;
          }
        }
        
        // NO MAGNET - player must walk over gold to collect it
        const dx = playerPos.x - this.mesh.position.x;
        const dz = playerPos.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        
        // Collect ONLY when player is very close
        if (dist < this.collectRange) {
          addGold(this.amount);
          playSound('coin');
          
          // Gold collect particles - 20 sparkles + flash
          spawnParticles(this.mesh.position, 0xFFD700, 8); // Reduced for performance
          spawnParticles(this.mesh.position, 0xFFFFFF, 3); // Reduced for performance
          
          // Flash effect - bright point light
          const flashLight = new THREE.PointLight(0xFFD700, 4, 8);
          flashLight.position.copy(this.mesh.position);
          flashLight.position.y += 1;
          scene.add(flashLight);
          flashLights.push(flashLight);
          const timeoutId = setTimeout(() => {
            scene.remove(flashLight);
            const idx = flashLights.indexOf(flashLight);
            if (idx > -1) flashLights.splice(idx, 1);
            const tidx = activeTimeouts.indexOf(timeoutId);
            if (tidx > -1) activeTimeouts.splice(tidx, 1);
          }, 100);
          activeTimeouts.push(timeoutId);
          
          this.destroy();
        }
      }
      
      destroy() {
        this.active = false;
        
        if (this.type === 'multiple' && this.coins) {
          // Clean up multiple coins
          this.coins.forEach(coinData => {
            scene.remove(coinData.mesh);
            coinData.mesh.geometry.dispose();
            coinData.mesh.material.dispose();
          });
        } else if (this.mesh) {
          // Clean up single mesh or group
          if (this.glowLight) {
            this.mesh.remove(this.glowLight);
          }
          scene.remove(this.mesh);
          
          // Dispose geometries and materials recursively
          this.mesh.traverse((child) => {
            if (child.geometry) child.geometry.dispose();
            if (child.material) {
              if (Array.isArray(child.material)) {
                child.material.forEach(mat => mat.dispose());
              } else {
                child.material.dispose();
              }
            }
          });
        }
      }
    }

    class Chest {
      constructor(x, z, tier = 'common') {
        this.tier = tier;
        
        // Define chest tier properties
        const tierProps = {
          common: {
            bodyColor: 0x8B7355,    // Brown
            lidColor: 0xC0C0C0,     // Silver
            emissive: 0xFFFFFF,     // White
            lightColor: 0xFFFFFF,   // White light
            particleColor: 0xFFFFFF, // White particles
            intensity: 1.0
          },
          uncommon: {
            bodyColor: 0x4A7C59,    // Dark Green
            lidColor: 0x6B8E23,     // Olive Green
            emissive: 0x00FF00,     // Green
            lightColor: 0x00FF00,   // Green light
            particleColor: 0x00FF00, // Green particles
            intensity: 1.3
          },
          rare: {
            bodyColor: 0x4169E1,    // Royal Blue
            lidColor: 0x1E90FF,     // Dodger Blue
            emissive: 0x0080FF,     // Blue
            lightColor: 0x0080FF,   // Blue light
            particleColor: 0x0080FF, // Blue particles
            intensity: 1.6
          },
          epic: {
            bodyColor: 0x8B00FF,    // Purple
            lidColor: 0xDA70D6,     // Orchid
            emissive: 0xA020F0,     // Purple
            lightColor: 0xA020F0,   // Purple light
            particleColor: 0xA020F0, // Purple particles
            intensity: 2.0
          },
          mythical: {
            bodyColor: 0xFF4500,    // Orange-Red
            lidColor: 0xFF6347,     // Tomato
            emissive: 0xFF0000,     // Red
            lightColor: 0xFF8C00,   // Dark Orange
            particleColor: 0xFF0000, // Red particles
            intensity: 2.5
          }
        };
        
        const props = tierProps[tier] || tierProps.common;
        
        // Create chest mesh - simple box with tier-specific color
        const geometry = new THREE.BoxGeometry(0.8, 0.6, 0.6);
        const material = new THREE.MeshPhysicalMaterial({ 
          color: props.bodyColor,
          metalness: 0.7,
          roughness: 0.3,
          emissive: props.emissive,
          emissiveIntensity: 0.2
        });
        this.mesh = new THREE.Mesh(geometry, material);
        this.mesh.position.set(x, 0.3, z);
        scene.add(this.mesh);
        
        // Add lid (different color)
        const lidGeo = new THREE.BoxGeometry(0.85, 0.1, 0.65);
        const lidMat = new THREE.MeshPhysicalMaterial({ 
          color: props.lidColor,
          metalness: 0.8,
          roughness: 0.2
        });
        this.lid = new THREE.Mesh(lidGeo, lidMat);
        this.lid.position.set(0, 0.35, 0);
        this.mesh.add(this.lid);
        
        this.active = true;
        this.opened = false;
        this.collectRange = 1.5;
        this.wobblePhase = Math.random() * Math.PI * 2;
        
        // Spawn sparkles around chest with tier-specific colors
        spawnParticles(this.mesh.position, props.particleColor, 8); // Reduced for performance
        spawnParticles(this.mesh.position, 0xFFFFFF, 4); // Reduced for performance
        
        // Add glowing light effect with tier-specific color
        const glowLight = new THREE.PointLight(props.lightColor, props.intensity, 6);
        glowLight.position.copy(this.mesh.position);
        glowLight.position.y += 0.5;
        scene.add(glowLight);
        this.glowLight = glowLight;
      }
      
      update(playerPos) {
        if (!this.active) return;
        
        // Bobbing animation
        this.wobblePhase += 0.05;
        this.mesh.position.y = 0.3 + Math.sin(this.wobblePhase) * 0.1;
        
        // Slow rotation
        this.mesh.rotation.y += 0.01;
        
        // Update glow light position
        if (this.glowLight) {
          this.glowLight.position.copy(this.mesh.position);
          this.glowLight.position.y += 0.5;
          // Pulsing glow
          this.glowLight.intensity = 1.5 + Math.sin(this.wobblePhase * 2) * 0.5;
        }
        
        // Check if player is close enough to open
        const dx = playerPos.x - this.mesh.position.x;
        const dz = playerPos.z - this.mesh.position.z;
        const dist = Math.sqrt(dx*dx + dz*dz);
        
        if (dist < this.collectRange && !this.opened) {
          this.open();
        }
      }
      
      open() {
        this.opened = true;
        
        // Animate lid opening
        let openProgress = 0;
        const animateLid = () => {
          openProgress += 0.05;
          if (openProgress < 1) {
            this.lid.rotation.x = -openProgress * Math.PI * 0.7; // Open 70%
            this.lid.position.z = -openProgress * 0.2; // Slide back slightly
            requestAnimationFrame(animateLid);
          }
        };
        animateLid();
        
        // Play sound and effects
        playSound('coin'); // Reuse coin sound
        
        // Explosion of particles
        spawnParticles(this.mesh.position, 0xFFD700, 15); // Reduced for performance
        spawnParticles(this.mesh.position, 0xFFFFFF, 8); // Reduced for performance
        spawnParticles(this.mesh.position, 0xFF69B4, 5); // Reduced for performance
        
        // Flash effect
        const flashLight = new THREE.PointLight(0xFFD700, 8, 15);
        flashLight.position.copy(this.mesh.position);
        flashLight.position.y += 2;
        scene.add(flashLight);
        flashLights.push(flashLight);
        const timeoutId = setTimeout(() => {
          scene.remove(flashLight);
          const idx = flashLights.indexOf(flashLight);
          if (idx > -1) flashLights.splice(idx, 1);
          const tidx = activeTimeouts.indexOf(timeoutId);
          if (tidx > -1) activeTimeouts.splice(tidx, 1);
        }, 200);
        activeTimeouts.push(timeoutId);
        
        // Give player reward
        this.giveReward();

        // Notify SSB of chest open with tier rarity
        if (window.pushSuperStatEvent) {
          const tr = this.tier === 'mythical' ? 'mythic' : (this.tier || 'common');
          window.pushSuperStatEvent(`🎁 ${(this.tier||'Common').toUpperCase()} Chest!`, tr, '🎁', 'success');
        }
        
        // Remove chest after short delay
        const destroyTimeoutId = setTimeout(() => {
          this.destroy();
        }, 2000);
        activeTimeouts.push(destroyTimeoutId);
      }
      
      giveReward() {
        // Determine reward type
        const rand = Math.random();
        
        if (rand < 0.35) {
          // Health restore (35% chance)
          const healAmount = 50;
          const prevHp = playerStats.hp;
          playerStats.hp = Math.min(playerStats.maxHp, playerStats.hp + healAmount);
          const actualHeal = playerStats.hp - prevHp;
          createFloatingText(`+${actualHeal} HP!`, this.mesh.position);
          showStatChange(`Chest: +${actualHeal} HP!`);
          spawnParticles(this.mesh.position, 0xFF69B4, 10); // Reduced for performance
        } else if (rand < 0.6) {
          // Gold (25% chance)
          const goldAmount = 12 + Math.floor(Math.random() * 19); // 12-30 gold (reduced from 20-50)
          addGold(goldAmount);
          createFloatingText(`+${goldAmount} Gold!`, this.mesh.position);
          showStatChange(`Chest: +${goldAmount} Gold!`);
        } else if (rand < 0.85) {
          // Random perk/stat boost (25% chance)
          this.applyRandomPerk();
        } else {
          // Weapon attachment or upgrade hint (15% chance)
          createFloatingText('Weapon Enhanced!', this.mesh.position);
          // Apply a small weapon boost - check if weapon exists
          if (weapons && weapons.gun && weapons.gun.active) {
            weapons.gun.damage += 5;
            showStatChange('Chest: Gun Damage +5');
          }
        }
      }
      
      applyRandomPerk() {
        const perks = [
          { name: 'Speed Boost', apply: () => { 
            // Cap max speed at 2x initial walkSpeed (50) to prevent breaking physics
            const maxWalkSpeed = 50; // 2x the initial 25
            if (playerStats.walkSpeed < maxWalkSpeed) {
              playerStats.walkSpeed *= 1.1;
              showStatChange('Chest: +10% Move Speed');
            } else {
              showStatChange('Chest: Max Speed Reached');
            }
          }},
          { name: 'Damage Boost', apply: () => { 
            playerStats.strength += 0.1;
            showStatChange('Chest: +10% Damage');
          }},
          { name: 'Health Boost', apply: () => { 
            playerStats.maxHp += 20;
            playerStats.hp += 20;
            showStatChange('Chest: +20 Max HP');
          }},
          { name: 'Armor Boost', apply: () => { 
            playerStats.armor = Math.min(80, playerStats.armor + 8);
            showStatChange('Chest: +8% Armor');
          }},
          { name: 'Attack Speed', apply: () => {
            // Cap minimum cooldown at 300ms to prevent performance issues
            if (weapons.gun.cooldown > 300) {
              weapons.gun.cooldown *= 0.9;
              showStatChange('Chest: +10% Attack Speed');
            } else {
              showStatChange('Chest: Max Attack Speed');
            }
          }}
        ];
        
        const perk = perks[Math.floor(Math.random() * perks.length)];
        perk.apply();
        createFloatingText(perk.name + '!', this.mesh.position);
      }
      
      destroy() {
        this.active = false;
        scene.remove(this.mesh);
        if (this.glowLight) {
          scene.remove(this.glowLight);
        }
        this.mesh.geometry.dispose();
        this.mesh.material.dispose();
        if (this.lid) {
          this.lid.geometry.dispose();
          this.lid.material.dispose();
        }
      }
    }

