    function getCost(upgradeKey) {
      const upgrade = PERMANENT_UPGRADES[upgradeKey];
      const currentLevel = saveData.upgrades[upgradeKey];
      return upgrade.baseCost + (currentLevel * upgrade.costIncrease);
    }
    
